    // In Java, we model this as a reference-counted object; actual native field is managed via JNI.
    private long baseRef; // placeholder for native cef_base_ref_counted_t pointer

    // Function pointers — represented as functional interfaces for callback registration

    /**
     * Returns true (1) if this object is read-only.
     */
    @FunctionalInterface
    public interface IsReadOnlyCallback {
        int invoke(long self);
    }
    private IsReadOnlyCallback isReadOnly;

    /**
     * Returns true (1) if the underlying POST data includes elements that are
     * not represented by this cef_post_data_t object (e.g., multi-part file upload data).
     * Modifying cef_post_data_t objects with excluded elements may result in the request failing.
     */
