    public interface HasExcludedElementsCallback {
        int invoke(long self);
    }
    private HasExcludedElementsCallback hasExcludedElements;

    /**
     * Returns the number of existing post data elements.
     */
    @FunctionalInterface
    public interface GetElementCountCallback {
        long invoke(long self); // size_t → long in Java (assumes 64-bit size_t on target platform)
    }
    private GetElementCountCallback getElementCount;

    /**
     * Retrieve the post data elements.
     * @param self native pointer to _cef_post_data_t
     * @param elementsCount output parameter: receives element count (pointer to size_t)
     * @param elements output parameter: receives array of _cef_post_data_element_t* (pointer to pointer)
     */
    @FunctionalInterface
    public interface GetElementsCallback {
        void invoke(long self, long elementsCountPtr, long elementsPtr);
    }
    private GetElementsCallback getElements;

    /**
     * Remove the specified post data element. Returns true (1) if the removal succeeds.
     */
    @FunctionalInterface
    public interface RemoveElementCallback {
        int invoke(long self, long element);
    }
    private RemoveElementCallback removeElement;

    /**
     * Add the specified post data element. Returns true (1) if the add succeeds.
     */
    @FunctionalInterface
    public interface AddElementCallback {
        int invoke(long self, long element);
    }
    private AddElementCallback addElement;

    /**
     * Remove all existing post data elements.
     */
    @FunctionalInterface
    public interface RemoveElementsCallback {
        void invoke(long self);
    }
    private RemoveElementsCallback removeElements;

    // Default constructor
    public CefPostDataT() {
        // In real JNI usage, this would allocate native cef_post_data_t via CEF API
        // e.g., cef_post_data_create(), and store the returned pointer in baseRef.
        this.baseRef = 0L;
    }

