    public void setIsReadOnly(IsReadOnlyCallback callback) { this.isReadOnly = callback; }
    public void setHasExcludedElements(HasExcludedElementsCallback callback) { this.hasExcludedElements = callback; }
    public void setGetElementCount(GetElementCountCallback callback) { this.getElementCount = callback; }
    public void setGetElements(GetElementsCallback callback) { this.getElements = callback; }
    public void setRemoveElement(RemoveElementCallback callback) { this.removeElement = callback; }
    public void setAddElement(AddElementCallback callback) { this.addElement = callback; }
    public void setRemoveElements(RemoveElementsCallback callback) { this.removeElements = callback; }

    // Native pointer accessor (for use in JNI implementations)
    public long getNativePtr() {
        return baseRef;
    }

    // Optional: setter for native pointer (if constructed from existing native object)
    public void setNativePtr(long ptr) {
        this.baseRef = ptr;
    }
