public interface LoggableActor extends Actor {
    ActorLogger getActorLogger();

    default void logMessageReceived(Message message) {
        ActorLogger logger = getActorLogger();
        String msgType = getMessageType(message);
        logger.logEvent(new ActorLogEvent.MessageReceived(getActorPath(), msgType));
    }

    default void logMessageProcessed(Message message, long processingTime) {
        ActorLogger logger = getActorLogger();
        String msgType = getMessageType(message);
        logger.logEvent(new ActorLogEvent.MessageProcessed(getActorPath(), msgType, processingTime));
    }

    default void logActorStarted() {
        ActorLogger logger = getActorLogger();
        logger.logEvent(new ActorLogEvent.ActorStarted(getActorPath()));
    }

    default void logActorStopped() {
        ActorLogger logger = getActorLogger();
        logger.logEvent(new ActorLogEvent.ActorStopped(getActorPath()));
    }

    default void logActorFailed(String error) {
        ActorLogger logger = getActorLogger();
        logger.logEvent(new ActorLogEvent.ActorFailed(getActorPath(), error));
    }

    default String getMessageType(Message message) {
        if (message instanceof StringMessage) {
            return "StringMessage";
        } else {
            return "UnknownMessage";
        }
    }

    default String getActorPath() {
        return "actor-path"; // 简化实现
    }
}

