public class MatrixUtils {
    public static <T extends CNumber<T>> Matrix<T> eye(long size) {
        Matrix<T> res = Matrix.zeros(size, size);
        for (long i = 0; i < size; i++) {
            res.set(i, i, T.fromInt(1));
        }
        return res;
    }
}

