public void sendWont(long option) {
    synchronized (lock) {
        OutputStream out = _output_.getOrThrow();
        out.write(COMMAND_WONT);
        out.write((int) option & 0xFF); // Convert UInt8(option) to byte
        try {
            out.flush();
        } catch (IOException e) {
            throw new RuntimeException(e);
        }
    }
}

