public class ShapeChecker {
    public static void checkShapes(AnimationData animationData,
                                   java.util.function.Consumer<java.util.ArrayList<ContentModel>> completeShapes,
                                   java.util.function.Consumer<ShapeData> convertPathsToAbsoluteValues) {
        int[] minimumVersion = {4, 4, 18};

        // Helper: complete closing flag for shapes recursively
        java.util.function.Consumer<java.util.ArrayList<ContentModel>> completeClosingShapes =
                (arr) -> {
                    long len = arr.size();
                    long jLen = 0;
                    ContentModel shape = new ContentModel();
                    // Iterate backwards: from len-1 down to 0 inclusive
                    for (long i = len - 1; i >= 0; i--) {
                        shape = arr.get((int) i);
                        if ("sh".equals(shape.ty)) {
                            ShapePath sh = ((ShapePath) shape).getOrThrow();
                            /*
                             * cj and arkts differ: arkts preserves JSON structure exactly.
                             * In cj:
                             * 1. If "shapes".{"ty": "sh"}.ks.k is an object → ShapePath.ks has one Keyframe<ShapeData>,
                             *    and parsed result resides in Keyframe.k.
                             * 2. If "shapes".{"ty": "sh"}.ks.k is an array → ShapePath.ks has multiple Keyframe<ShapeData>,
                             *    and parsed results reside in Keyframe.s / Keyframe.e.
                             * See test_shapes_07.cj.
                             */
                            if (sh.ks.size() == 1) { /* k is an object */
                                Keyframe<ShapeData> kf0 = sh.ks.get(0);
                                if (kf0.k != null) {
                                    kf0.k.c = sh.closed;
                                }
                            } else if (sh.ks.size() > 1) { /* k is an array */
                                jLen = sh.ks.size();
                                for (long j = 0; j < jLen; j++) {
                                    Keyframe<ShapeData> kf = sh.ks.get((int) j);
                                    if (kf.s != null) {
                                        kf.s.c = sh.closed;
                                    }
                                    if (kf.e != null) {
                                        kf.e.c = sh.closed;
                                    }
                                }
                            }
                        } else if ("gr".equals(shape.ty)) {
                            ShapeGroup group = ((ShapeGroup) shape).getOrThrow();
                            completeClosingShapes.accept(group.it);
                        }
                    }
                };

        // Helper: iterate layers and process masks + shape layers
        java.util.function.Consumer<Layer[]> iterateLayers = (layers) -> {
            long len = layers.length;
            long jLen = 0;
            long kLen = 0;
            for (int i = 0; i < len; i++) {
                Layer layerData = layers[i];
                if (layerData.hasMask) {
                    Mask[] maskProps = layerData.masksProperties;
                    jLen = maskProps.length;
                    for (int j = 0; j < jLen; j++) {
                        Mask mask = maskProps[j];
                        /*
                         * cj and arkts differ: arkts preserves JSON structure exactly.
                         * In cj:
                         * 1. If masksProperties.pt.k is an object → Mask.pt has one Keyframe<Array<Float64>>,
                         *    and parsed result resides in Keyframe.k.
                         * 2. If masksProperties.pt.k is an array → Mask.pt has multiple Keyframe<Array<Float64>>,
                         *    and parsed results reside in Keyframe.s / Keyframe.e.
                         * See test_layer_03.cj.
                         */
                        if (mask.pt.length == 1) { /* k is an object */
                            Keyframe<float[]> kf0 = mask.pt[0];
                            if (kf0.k != null) {
                                kf0.k.c = mask.cl;
                            }
                        } else if (mask.pt.length > 1) { /* k is an array */
                            kLen = mask.pt.length;
                            for (int k = 0; k < kLen; k++) {
                                Keyframe<float[]> kf = mask.pt[k];
                                if (kf.s != null) {
                                    kf.s.c = mask.cl;
                                }
                                if (kf.e != null) {
                                    kf.e.c = mask.cl;
                                }
                            }
                        }
                    }
                }
                if (layerData.ty == 4) {
                    completeClosingShapes.accept(layerData.shapes);
                }
            }
        };

        // Main logic
        if (checkVersion(minimumVersion, animationData.v)) {
            iterateLayers.accept(animationData.layers);
            if (animationData.assets != null && animationData.assets.length > 0) {
                for (Asset asset : animationData.assets) {
                    if (asset.layers != null && asset.layers.length > 0) {
                        iterateLayers.accept(asset.layers);
                    }
                }
            }
        }
    }

    // Assuming this helper exists elsewhere; stubbed for completeness
    private static boolean checkVersion(int[] minVer, String versionStr) {
        // Parse versionStr like "4.4.18" or "4.4.18.1234"
        String[] parts = versionStr.split("\\.");
        try {
            for (int i = 0; i < Math.min(minVer.length, parts.length); i++) {
                int v = Integer.parseInt(parts[i]);
                if (v > minVer[i]) return true;
                if (v < minVer[i]) return false;
            }
            return true; // equal up to minVer length → acceptable
        } catch (NumberFormatException e) {
            return false;
        }
    }
}

