        StringBuilder b = new StringBuilder("[");
        boolean first = true;
        for (T d : data) {
            if (!first) {
                b.append(',');
            }
            b.append(d.toData().toString());
            first = false;
        }
        b.append(']');
        return b.toString();
    }

    // Static utility methods — note: Java has no top-level static methods in generic classes like this,
    // so we keep them as static methods in the same class.
    public static <C extends DataFields<T> & Collection<T>, T extends DataFields<T>>
