/**
 * Extracts attributes from the global ATTRS list that fall within the given position range.
 * Each attribute is a pair of (ArrayList<MetaItem>, Tokens).
 * After extraction, the ATTRS list is updated to contain only the remaining attributes.
 *
 * @param firstPos the starting position (inclusive)
 * @param lastPos  the ending position (inclusive)
 * @return an array of attributes within the specified position range
 */
public static ArrayList<Object[]> takeAttrs(Position firstPos, Position lastPos) {
    int idx = 0;
    while (idx < ATTRS.size()) {
        Position pos = ATTRS.get(idx).get(1).get(0).pos;
        if (pos.compareTo(firstPos) >= 0 && pos.compareTo(lastPos) <= 0) {
            break;
        } else {
            idx++;
        }
    }
    if (idx > 0) {
        int offset = idx;
        ArrayList<Object[]> attr = new ArrayList<>();
        for (int i = 0; i < ATTRS.size() - offset; i++) {
            attr.add(ATTRS.get(offset + i));
        }
        ATTRS.clear();
        ATTRS.addAll(attr);
        return attr;
    } else {
        return new ArrayList<>(ATTRS);
    }
}

output:
func takeAttrs(firstPos: Position, lastPos: Position): Array<(ArrayList<MetaItem>, Tokens)> {
    var idx = 0
    while (idx < ATTRS.size) {
        let pos = ATTRS[idx][1][0].pos
        if (pos >= firstPos && pos <= lastPos) {
            break
        } else {
            idx++
        }
    }
    if (idx > 0) {
        let offset = idx
        let attr = Array<(ArrayList<MetaItem>, Tokens)>(ATTRS.size - idx) {i => ATTRS[offset + i]}
        ATTRS.clear()
        ATTRS.add(all: attr)
        return attr
    } else {
        return ATTRS.toArray()
    }
}

