public Buffer skip(long skipSize) {
    if (skipBytes < 0) {
        throw new IllegalArgumentException("Negative skipSize: " + skipBytes);
    }

    if (positionVal < skipSize) {
        throw new IllegalArgumentException("The skipSize: " + skipSize + " should less than position: " + positionVal);
    }

    // position, limit, capacity均要调整
    this.positionVal = positionVal - skipSize;
    this.limitVal = limitVal - skipSize;
    this.capacityVal = capacityVal - skipSize;
    // 增加skipBytes
    this.skipBytes = skipBytes + skipSize;
    return this;
}

