            throw IllegalArgumentException("no such vertex in graph: " + vertex.toString())
        }
    }

    public override func degreeOf(vertex: V): Int64 {
        if (unionType.isMixed()) {
            var d: Int64 = 0
            if (g1.containsVertex(vertex)) {
                d += g1.degreeOf(vertex)
            }
            if (g2.containsVertex(vertex)) {
                d += g2.degreeOf(vertex)
            }
            return d
        } else if (unionType.isUndirected()) {
            var degree: Int64 = 0
            let it: Iterator<E> = edgesOf(vertex).iterator()
            while (true) {
                let next = it.next()
                if (next == None) {
                    break
                }
                let e: E = next.getOrThrow()
                if (getEdgeSource(e) == getEdgeTarget(e)) {
                    degree++
                }
                degree++
            }
            return degree
        } else {
            return incomingEdgesOf(vertex).size + outgoingEdgesOf(vertex).size
        }
    }

    public override func inDegreeOf(vertex: V): Int64 {
        if (unionType.isMixed()) {
            var d: Int64 = 0
            if (g1.containsVertex(vertex)) {
                d += g1.inDegreeOf(vertex)
            }
            if (g2.containsVertex(vertex)) {
                d += g2.inDegreeOf(vertex)
            }
            return d
        } else if (unionType.isUndirected()) {
            return degreeOf(vertex)
        } else {
            return incomingEdgesOf(vertex).size
        }
    }

    public override func outDegreeOf(vertex: V): Int64 {
        if (unionType.isMixed()) {
            var d: Int64 = 0
            if (g1.containsVertex(vertex)) {
                d += g1.outDegreeOf(vertex)
            }
            if (g2.containsVertex(vertex)) {
                d += g2.outDegreeOf(vertex)
            }
            return d
        } else if (unionType.isUndirected()) {
            return degreeOf(vertex)
        } else {
            return outgoingEdgesOf(vertex).size
        }
    }

    public override func removeEdge(_: V, _: V): ?E {
        throw UnsupportedException(READ_ONLY)
    }

    public override func removeEdge(_: E): Bool {
        throw UnsupportedException(READ_ONLY)
    }

    public override func removeVertex(_: V): Bool {
        throw UnsupportedException(READ_ONLY)
    }

    public override func vertexSet(): Set<V> {
        return UnmodifiableUnionSet<V>.from(g1.vertexSet(), g2.vertexSet())
    }

    public override func getEdgeSource(e: E): V {
        if (g1.containsEdge(e)) {
            return g1.getEdgeSource(e)
        }
        if (g2.containsEdge(e)) {
            return g2.getEdgeSource(e)
        }
        throw IllegalArgumentException("no such edge in the union")
    }

    public override func getEdgeTarget(e: E): V {
        if (g1.containsEdge(e)) {
            return g1.getEdgeTarget(e)
        }
        if (g2.containsEdge(e)) {
            return g2.getEdgeTarget(e)
        }
        throw IllegalArgumentException("no such edge in the union")
    }

    public override func getEdgeWeight(e: E): Float64 {
        if (g1.containsEdge(e) && g2.containsEdge(e)) {
            return combiner.combine(g1.getEdgeWeight(e), g2.getEdgeWeight(e))
        }
        if (g1.containsEdge(e)) {
            return g1.getEdgeWeight(e)
        }
        if (g2.containsEdge(e)) {
            return g2.getEdgeWeight(e)
        }
        throw IllegalArgumentException("no such edge in the union")
    }

    public override func getType(): GraphType {
        return unionType
    }

    public override func setEdgeWeight(_: E, _: Float64): Unit {
        throw UnsupportedException(READ_ONLY)
    }
