private LogLevel parseLogLevel(String levelStr) {
    String lowerLevel = levelStr.toLowerCase();
    switch (lowerLevel) {
        case "off":
            return LogLevel.OFF;
        case "fatal":
            return LogLevel.FATAL;
        case "error":
            return LogLevel.ERROR;
        case "warn":
            return LogLevel.WARN;
        case "info":
            return LogLevel.INFO;
        case "debug":
            return LogLevel.DEBUG;
        case "trace":
            return LogLevel.TRACE;
        case "all":
            return LogLevel.ALL;
        default:
            JoyLog.warn("Unknown log level '" + levelStr + "', defaulting to INFO");
            return LogLevel.INFO;
    }
}

