import java.time.Duration;
import java.time.Instant;
import java.util.concurrent.*;
import java.util.concurrent.atomic.AtomicBoolean;

/**
 * A distributed future that blocks until a result is ready, supports timeouts,
 * and integrates with actor systems.
 *
 * @param <DataModel> the type of the serialized data model
 */
public class DistributedFuture<DataModel extends Serializable> {
    private volatile FutureResult<DataModel> result = new FutureResult<>();
    private final AtomicBoolean isReady = new AtomicBoolean(false);
    private final ReentrantLock mtx = new ReentrantLock();
    private final Condition cond;

    public DistributedFuture() {
        this.mtx.lock();
        try {
            this.cond = this.mtx.newCondition();
        } finally {
            this.mtx.unlock();
        }
    }

    /**
     * Blocks the current thread until the result is ready and returns the result
     *
     * @return the result
     * @throws RemoteException         if the remote connection fails
     * @throws RemoteReceiverException if the result is an exception or error thrown from the remote receiver execution
     * @throws ActorSystemException    for any system-specific errors
     */
    public DataModel get() throws RemoteException, RemoteReceiverException, ActorSystemException {
        if (isReady.get()) {
            return result.getOrThrow();
        }
        mtx.lock();
        try {
            while (!isReady.get()) {
                cond.await();
            }
            return result.getOrThrow();
        } catch (InterruptedException e) {
            Thread.currentThread().interrupt();
            throw new ActorSystemException("Interrupted while waiting for result", e);
        } finally {
            mtx.unlock();
        }
    }

    /**
     * Blocks the current thread until the result is ready with a timeout and returns the result
     *
     * @param timeout the timeout duration
     * @return the result if it is ready within the timeout, empty Optional otherwise
     * @throws RemoteException         if the remote connection fails
     * @throws RemoteReceiverException if the result is an exception or error thrown from the remote receiver execution
     * @throws ActorSystemException    for any system-specific errors
     */
    public java.util.Optional<DataModel> get(Duration timeout)
            throws RemoteException, RemoteReceiverException, ActorSystemException {
        if (timeout == null || timeout.isNegative() || timeout.isZero()) {
            return java.util.Optional.of(get());
        }
        if (isReady.get()) {
            return java.util.Optional.of(result.getOrThrow());
        }
        Instant start = Instant.now();
        mtx.lock();
        try {
            while (true) {
                if (isReady.get()) {
                    break;
                }
                Duration elapsed = Duration.between(start, Instant.now());
                if (elapsed.compareTo(timeout) >= 0) {
