import java.util.*;
import java.util.stream.Collectors;

public class GenCodeHelper {
    /* Get type name based on nesting level */
    private final List<String> nested = new ArrayList<>();

    public String getNestedTypeName(String name) {
        if (nested.isEmpty()) {
            return name;
        }
        StringBuilder sb = new StringBuilder();
        for (String n : nested) {
            sb.append(n).append('_');
        }
        sb.append(name);
        return sb.toString();
    }

    private final String pkgPrefix;

    public GenCodeHelper(String package_, boolean proto2) {
        this.pkgPrefix = package_.isEmpty() ? "." : "." + package_ + ".";
    }

    private final List<String> packages = new ArrayList<>();

    /* Get all dependent packages */
    public Set<String> getDependencyPackages(FileDescriptorProto desc) {
        Set<String> pkgs = new HashSet<>();
        for (String dep : desc.getDependencyList()) {
            int lastSlashIndex = dep.lastIndexOf('/');
            if (lastSlashIndex == -1) {
                continue;
            }
            String pkg = dep.substring(0, lastSlashIndex).replace('/', '.');
            if ("protobuf".equals(desc.getPackage()) && !"protobuf".equals(pkg)) {
                /* Dependency on external packages is not allowed in protobuf packages, and circular dependency on packages is not allowed in Cangjie */
                throw new RuntimeException(); // todo
            }
            if (!pkg.equals(desc.getPackage()) && !"protobuf".equals(pkg)) {
                /* Save packages other than `desc` itself and protobuf */
                pkgs.add(pkg);
            }
        }
        packages.add(pkgPrefix);
        for (String p : pkgs) {
            packages.add("." + p + ".");
        }
        packages.sort(GenCodeHelper::pkgCmp);
        return pkgs;
    }

    public String getTypeName(String typeName) {
        for (String p : packages) {
            if (typeName.startsWith(p)) {
                if (p.equals(pkgPrefix)) {
                    String suffix = typeName.substring(p.length());
                    String[] parts = suffix.split("\\.");
                    return String.join("_", parts);
                }
                String pkgPart = p.substring(1);
                String suffix = typeName.substring(p.length());
                String[] parts = suffix.split("\\.");
                return pkgPart + String.join("_", parts);
            }
        }
        throw new RuntimeException(); // todo
    }

    // For type_ Message. If it is a map, special processing is required
    public String getMessageTypeName(FieldDescriptorProto f, List<DescriptorProto> ns) {
        if (f.getLabel() == FieldDescriptorProto.Label.LABEL_REPEATED) {
            String[] sp = f.getTypeName().split("\\.");
            String entry = sp[sp.length - 1];
            if (entry.endsWith("Entry")) {
                // Looking for entry in nestedtype
                for (DescriptorProto n : ns) {
                    if (n.getFieldCount() != 2 || !n.getName().equals(entry)) {
                        continue;
                    }
                    try {
                        if (!n.getOptions().getMapEntry()) {
                            continue;
                        }
                    } catch (Exception ignored) {
                        continue;
                    }
                    // Find entry
                    return getPropType(n.getField(0)) + ", " +
                           getPropType(n.getField(1)) + ", " +
                           getAccesor(n.getField(0)) + ", " +
                           getAccesor(n.getField(1));
                }
            }
        }
        return getTypeName(f.getTypeName());
    }

    // pkg Dictionary order reverse
    private static int pkgCmp(String a, String b) {
        if (a.equals(b)) {
            return 0;
        } else if (a.compareTo(b) < 0) {
            return 1; // GT
        } else {
            return -1; // LT
        }
    }

    private final StringBuilder outbuf = new StringBuilder();
    private int oneofNum = 0;

