public class BLAS {
    private static final String zeroIncX = "INCX must not be zero";
    private static final String zeroIncY = "INCY must not be zero";
    private static final String nLT0 = "N must be non-negative";
    private static final String shortX = "Array X is too short for the given INCX and N";
    private static final String shortY = "Array Y is too short for the given INCY and N";

    public static void dswap(long n, double[] x, long incX, double[] y, long incY) {
        if (incX == 0) {
            throw new IllegalArgumentException(zeroIncX);
        }
        if (incY == 0) {
            throw new IllegalArgumentException(zeroIncY);
        }
        if (n < 1) {
            if (n == 0) {
                return;
            }
            throw new IllegalArgumentException(nLT0);
        }

        // Check bounds for x: required length is at least |(n-1)*incX| + 1
        long xRequiredSize;
        if (incX > 0) {
            xRequiredSize = (n - 1) * incX + 1;
        } else {
            xRequiredSize = (1 - n) * incX + 1; // incX < 0 → (-n+1)*incX = (1-n)*incX
        }
        if (x.length < xRequiredSize) {
            throw new IllegalArgumentException(shortX);
        }

        // Check bounds for y
        long yRequiredSize;
        if (incY > 0) {
            yRequiredSize = (n - 1) * incY + 1;
        } else {
            yRequiredSize = (1 - n) * incY + 1;
        }
        if (y.length < yRequiredSize) {
            throw new IllegalArgumentException(shortY);
        }

        if (incX == 1 && incY == 1) {
            // Optimized contiguous case
            for (long i = 0; i < n; i++) {
                double tmp = x[(int) i];
                x[(int) i] = y[(int) i];
                y[(int) i] = tmp;
            }
            return;
        }

        long ix = 0;
        long iy = 0;
        if (incX < 0) {
            ix = (-n + 1) * incX;
        }
        if (incY < 0) {
            iy = (-n + 1) * incY;
        }

        for (long k = 0; k < n; k++) {
            double tmp = x[(int) ix];
            x[(int) ix] = y[(int) iy];
            y[(int) iy] = tmp;
            ix += incX;
            iy += incY;
        }
    }
}

