public void subscribe(String[] topicFilters, long[] qos, IMqttMessageListener[] messageListeners) {
    IMqttToken tok = aClient.subscribe(topicFilters, qos, null, null, messageListeners);
    tok.waitForCompletion(getTimeToWait());
    long[] grantedQos = tok.getGrantedQos();
    // Copy granted QoS values back into the input qos array, up to grantedQos.length
    int copyLength = Math.min(grantedQos.length, qos.length);
    System.arraycopy(grantedQos, 0, qos, 0, copyLength);
    if (grantedQos.length == 1 && grantedQos[0] == 0x80L) {
        throw new MqttException(MqttException.REASON_CODE_SUBSCRIBE_FAILED);
    }
}

