private void unifyFraction() {
    // 使用正则表达式匹配时间小数秒部分 - 冒号后跟1-2个数字，然后是小数点和任意数字
    Pattern regex = Pattern.compile(":(\\d{1,2})\\.(\\d+)", Pattern.CASE_INSENSITIVE);

    Matcher matcher = regex.matcher(_dateStr);
    if (matcher.find()) {
        // 找到匹配项
        // 获取小数点位置
        int dotIndex = matcher.start() + matcher.group(1).length() + 1; // +1是冒号到小数点的偏移

        // 获取小数部分
        String fractionPart = matcher.group(2);
        int length = fractionPart.length();

        // 根据小数位长度确定需要补充的零数量
        int targetLength = length;
        if (length >= 1 && length <= 2) {
            targetLength = 3;  // 补足到3位(毫秒)
        } else if (length >= 4 && length <= 5) {
            targetLength = 6;  // 补足到6位(微秒)
        } else if (length >= 7 && length <= 8) {
            targetLength = 9;  // 补足到9位(纳秒)
        }

        // 如果需要补零
        if (targetLength > length) {
            // 计算需要补充的零数量
            int diff = targetLength - length;

            // 构建补充后的字符串
            String beforeDot = _dateStr.substring(0, dotIndex + 1); // 包括小数点
            String afterFraction = _dateStr.substring(dotIndex + 1 + length);

            // 生成需要的零
            StringBuilder zeros = new StringBuilder();
            for (int i = 0; i < diff; i++) {
                zeros.append('0');
            }

            // 更新字符串
            _dateStr = beforeDot + fractionPart + zeros.toString() + afterFraction;
        }
    }
    // 没有找到匹配项，不需要处理
}

