public class MathUtils {
    public static double[] polarOffset(double[] p, double angle, double length) {
        if (p.length < 2) {
            throw new IndexOutOfBoundsException("[polarOffset]: p.size = " + p.length);
        }
        return new double[]{
            p[0] + Math.cos(angle) * length,
            p[1] - Math.sin(angle) * length
        };
    }
}

