        try {
            if (recursive) {
                if (!this.existFolder(path)) {
                    let lastInterval: Int64 = path.lastIndexOf(FileUtils.SEPARATOR) ?? -1
                    if (lastInterval <= 0) {
                        return
                    }
                    let newPath: String = path[0..lastInterval]
                    this.createFolder(newPath, recursive: true)
                    if (!this.existFolder(path)) {
                        FileFs.mkdir(path)
                    }
                }
            } else {
                if (!this.existFolder(path)) {
