public class Money {
    public final long amount;
    public final String currency;

    public Money(long amount, String currency) {
        this.amount = amount;
        this.currency = currency;
    }
}

public class MoneyUtils {
    public static Money round(Money m, long e) {
        if (e <= 0) {
            throw new IllegalArgumentException("精度 e 为正整数。");
        }

        long absam = Math.abs(m.amount);
        long exp = (long) Math.pow(10.0, e);
        long dec = absam % exp;

        if (dec >= exp / 2) {
            absam += exp;
        }

        absam = (absam / exp) * exp;

        if (m.amount < 0) {
            return new Money(-absam, m.currency);
        }

        return new Money(absam, m.currency);
    }
}

