        if (this == COMP_FIELDS_BEFORE) {
            this.rawFields.add(raw);
        } else {
            throw new RuntimeException("fields computed");
        }
    }

    public CompFields computeBitfieldUnits(CjbindContext ctx, boolean packed) {
        List<RawField> raws;
        if (this == COMP_FIELDS_BEFORE) {
            raws = this.rawFields;
        } else {
            throw new RuntimeException("fields computed");
        }

        Result<Pair<RawField[], Boolean>, String> result = rawFieldsToFieldsAndBitfieldUnits(ctx, raws, packed);

        if (result.isOk()) {
            Pair<RawField[], Boolean> okValue = result.getOk();
            RawField[] fields = okValue.getFirst();
            boolean hasBitfieldUnits = okValue.getSecond();
            return compFieldsAfter(new CompFieldsAfterValue(fields, hasBitfieldUnits));
        } else {
            return COMP_FIELDS_ERROR;
        }
    }

    public void deanonymizeFields(CjbindContext context) {
        RawField[] fields;
        if (this == COMP_FIELDS_AFTER) {
            fields = this.compFieldsAfterValue.fields;
        } else if (this == COMP_FIELDS_ERROR) {
            return;
        } else if (this == COMP_FIELDS_BEFORE) {
            throw new RuntimeException("fields not computed");
        } else {
            throw new IllegalStateException("Unknown CompFields variant");
        }

        int anonFieldCounter = 0;
        for (RawField field : fields) {
            if (field instanceof Field.DataMember) {
                Field.DataMember data = (Field.DataMember) field;
                if (data.name != null && data.name.isPresent()) {
