public class HtmlTreeBuilder {

    // Helper methods assumed to be present in the surrounding class:
    // - settings(): ParseSettings
    // - stack(): List<Element>
    // - tokeniser(): Tokeniser
    // - doc(): Document
    // - currentElement(): Element
    // - formElement(): Optional<FormElement>
    // - isFosterInserts(): boolean
    // - isContentForTagData(String tagName): boolean
    // - onNodeInserted(Node node, Token token): void
    // - setFormElement(FormElement el): void
    // - onStack(String tagName): boolean
    // - insertInFosterParent(Node node): void
    // - tagFor(String name, ParseSettings settings): Tag
    // - emptyEnd(): EndTagToken
    // - error(String msg): void

    public Element insert(StartTagToken startTag) {
        // cleanup duplicate attributes:
        if (startTag.hasAttributes() && !startTag.attributes().isEmpty()) {
            long dupes = startTag.attributes().deduplicate(settings());
            if (dupes > 0) {
                error("Dropped duplicate attribute(s) in tag [" + startTag.normalName() + "]");
            }
        }

        // handle empty unknown tags
        // when the spec expects an empty tag, will directly hit insertEmpty, so won't generate this fake end tag.
        if (startTag.isSelfClosing()) {
            Element el = insertEmpty(startTag);
            if (stack() != null) {
                stack().add(el);
            }
            if (tokeniser() != null) {
                tokeniser().transition(TokeniserState.Data); // handles <script />, otherwise needs breakout steps from script data
                tokeniser().emit(emptyEnd().reset().name(el.tagName())); // ensure we get out of whatever state we are in. emitted for yielded processing
            }
            return el;
        }

        Tag tag = tagFor(startTag.name(), settings());
        Attributes normalizedAttrs = settings().normalizeAttributes(startTag.attributes());
        Element el = new Element(tag, null, normalizedAttrs);
        insert(el, startTag);
        return el;
    }

    public Element insertStartTag(String startTagName) {
        Tag tag = tagFor(startTagName, settings());
        Element el = new Element(tag, null);
        insert(el);
        return el;
    }

    public void insert(Element el) {
        insertNode(el, null);
        if (stack() != null) {
            stack().add(el);
        }
    }

    private void insert(Element el, Token token) {
        insertNode(el, token);
        if (stack() != null) {
            stack().add(el);
        }
    }

    public Element insertEmpty(StartTagToken startTag) {
        Tag tag = tagFor(startTag.name(), settings());
        Attributes normalizedAttrs = settings().normalizeAttributes(startTag.attributes());
        Element el = new Element(tag, null, normalizedAttrs);
        insertNode(el, startTag);
        if (startTag.isSelfClosing()) {
            if (tag.isKnownTag()) {
                if (!tag.isEmpty()) {
                    tokeniser().error("Tag [" + tag.normalName() + "] cannot be self closing; not a void tag");
                }
            } else {
                // unknown tag, remember this is self closing for output
                tag.setSelfClosing();
            }
        }
        return el;
    }

    public FormElement insertForm(StartTagToken startTag, boolean onStackBool, boolean checkTemplateStack) {
        Tag tag = tagFor(startTag.name(), settings());
        Attributes normalizedAttrs = settings().normalizeAttributes(startTag.attributes());
        FormElement el = new FormElement(tag, null, normalizedAttrs);
        if (checkTemplateStack) {
            if (!onStack("template")) {
                setFormElement(el);
            }
        } else {
            setFormElement(el);
        }

        insertNode(el, startTag);
        if (onStackBool && stack() != null) {
            stack().add(el);
        }
        return el;
    }

    public void insert(CommentToken commentToken) {
        Comment comment = new Comment(commentToken.getData());
        insertNode(comment, commentToken);
    }

    public void insert(CharacterToken characterToken) {
        Node node;
        Element el = currentElement(); // will be doc if no current element; allows for whitespace to be inserted into the doc root object (not on the stack)
        String tagName = el.normalName();
        String data = characterToken.getData();

        if (characterToken.isCData()) {
            node = new CDataNode(data);
        } else if (isContentForTagData(tagName)) {
            node = new DataNode(data);
        } else {
            node = new TextNode(data);
        }
        el.appendChild(node); // doesn't use insertNode, because we don't foster these; and will always have a stack.
        onNodeInserted(node, characterToken);
    }

    private void insertNode(Node node, Token token) {
        // if the stack hasn't been set up yet, elements (doctype, comments) go into the doc
        if (stack() == null || stack().isEmpty()) {
            doc().appendChild(node);
        } else if (isFosterInserts() && StringUtil.inSorted(currentElement().normalName(), InTableFoster)) {
            insertInFosterParent(node);
        } else {
            currentElement().appendChild(node);
        }

        // connect form controls to their form element
        if (node instanceof Element) {
