import java.nio.charset.Charset;
import java.nio.charset.StandardCharsets;
import java.util.ArrayList;
import java.util.Arrays;
import java.util.List;
import java.util.Objects;
import java.util.Optional;
import java.util.stream.Collectors;

// Note: This Java translation assumes availability of helper utilities for UTF-8 byte handling,
// rune iteration, and safe substring/replace logic. Since Java lacks built-in `unsafeBytes()`,
// `runes()`, or `indexOf` on byte arrays with ranges, we emulate behavior using standard APIs.
// OS-specific line endings are approximated via `System.lineSeparator()` and explicit "\n".
// `Charsets.UTF8` is used as default; `Charsets.ISO_8859_1` etc. would require extension.

public class StringGenerator implements ToString {
    private final ArrayList<Byte> utf8;

    public StringGenerator() {
        this.utf8 = new ArrayList<>();
    }

    public StringGenerator(String s) {
        this();
        append(s);
    }

    public long size() {
        return utf8.size();
    }

    public StringGenerator reset() {
        utf8.clear();
        return this;
    }

    private void checkIndex(long fromIndex, long toIndex) {
        long size = size();
        if (fromIndex < 0 || fromIndex > size || toIndex < fromIndex || toIndex > size) {
            throw new IndexOutOfBoundsException(
                String.format("current size is %d, but fromIndex: %d, toIndex: %d", size, fromIndex, toIndex)
            );
        }
    }

    public StringGenerator append(StringGenerator gen) {
        byte[] bytes = gen.unsafeBytes();
        for (byte b : bytes) {
            utf8.add(b);
        }
        return this;
    }

    public <T extends ToString> StringGenerator append(T content) {
        String str = content.toString();
        byte[] bytes = str.getBytes(StandardCharsets.UTF_8);
        for (byte b : bytes) {
            utf8.add(b);
        }
        return this;
    }

    public StringGenerator appendln(StringGenerator gen, String nextLine) {
        append(gen);
        append(nextLine);
        return this;
    }

    public StringGenerator appendUnixNewLine(StringGenerator gen) {
        append(gen);
        appendUnixNewLine();
        return this;
    }

    public <T extends ToString> StringGenerator appendln(T content, String nextLine) {
        append(content);
        append(nextLine);
        return this;
    }

    public <T extends ToString> StringGenerator appendUnixNewLine(T content) {
        append(content);
        appendUnixNewLine();
        return this;
    }

    public StringGenerator append(String nextLine) {
        return append(nextLine, StandardCharsets.UTF_8);
    }

    public StringGenerator appendUnixNewLine() {
        return append("\n");
    }

    public StringGenerator appendFromUtf8(byte[] utf8Bytes) {
        String s = new String(utf8Bytes, StandardCharsets.UTF_8);
        return append(s);
    }

    public StringGenerator appendFromBytes(byte[] bytes, Charset charset) {
        String s = new String(bytes, charset);
        return append(s);
    }

    // Helper: convert ArrayList<Byte> to byte[]
    private byte[] toByteArray() {
        byte[] arr = new byte[utf8.size()];
        for (int i = 0; i < utf8.size(); i++) {
            arr[i] = utf8.get(i);
        }
        return arr;
    }

    // indexOf for byte[] search in internal byte array
    private Optional<Long> indexOf(byte[] search, long fromIndex) {
        byte[] data = toByteArray();
        int start = Math.toIntExact(fromIndex);
        if (start < 0 || start > data.length) return Optional.empty();
        for (int i = start; i <= data.length - search.length; i++) {
            boolean match = true;
            for (int j = 0; j < search.length; j++) {
                if (data[i + j] != search[j]) {
                    match = false;
                    break;
                }
            }
            if (match) {
                return Optional.of((long) i);
            }
        }
        return Optional.empty();
    }

    public <T extends ToString> Optional<Long> indexOf(T content, long fromIndex) {
        String str = content.toString();
        byte[] search = str.getBytes(StandardCharsets.UTF_8);
        return indexOf(search, fromIndex);
    }

    private Optional<Long> lastIndexOf(byte[] search, long fromIndex) {
        byte[] data = toByteArray();
        int end = (fromIndex == 0) ? data.length : Math.min(Math.toIntExact(fromIndex), data.length);
        if (search.length == 0) return Optional.of((long) end);
        for (int i = end - search.length; i >= 0; i--) {
            boolean match = true;
            for (int j = 0; j < search.length; j++) {
                if (data[i + j] != search[j]) {
                    match = false;
                    break;
                }
            }
            if (match) {
                return Optional.of((long) i);
            }
        }
        return Optional.empty();
    }

    public <T extends ToString> Optional<Long> lastIndexOf(T content, long fromIndex) {
        String str = content.toString();
        byte[] search = str.getBytes(StandardCharsets.UTF_8);
        return lastIndexOf(search, fromIndex);
    }

    public <T extends ToString> boolean contains(T content) {
        return indexOf(content, 0L).isPresent();
    }

    public boolean startsWith(String content) {
        byte[] contentBytes = content.getBytes(StandardCharsets.UTF_8);
        byte[] data = toByteArray();
        if (contentBytes.length > data.length) return false;
        for (int i = 0; i < contentBytes.length; i++) {
            if (data[i] != contentBytes[i]) {
                return false;
            }
        }
        return true;
    }

    public boolean endsWith(String content) {
        byte[] contentBytes = content.getBytes(StandardCharsets.UTF_8);
        byte[] data = toByteArray();
        if (contentBytes.length > data.length) return false;
        int offset = data.length - contentBytes.length;
        for (int i = 0; i < contentBytes.length; i++) {
            if (data[offset + i] != contentBytes[i]) {
                return false;
            }
        }
        return true;
    }

    public String substring(long start, long end) {
        checkIndex(start, end);
        byte[] data = toByteArray();
        int s = Math.toIntExact(start);
        int e = Math.toIntExact(end);
        byte[] sub = Arrays.copyOfRange(data, s, e);
        return new String(sub, StandardCharsets.UTF_8);
    }

    public void clear() {
        utf8.clear();
    }

    public <T extends ToString> StringGenerator removeFirst(T content, long fromIndex) {
        String str = content.toString();
        byte[] search = str.getBytes(StandardCharsets.UTF_8);
        Optional<Long> idxOpt = indexOf(search, fromIndex);
        if (idxOpt.isPresent()) {
            long idx = idxOpt.get();
            int i = Math.toIntExact(idx);
            int len = search.length;
            utf8.subList(i, i + len).clear();
        }
        return this;
    }

    public <T extends ToString> StringGenerator removeLast(T content, long fromIndex) {
        String str = content.toString();
        byte[] search = str.getBytes(StandardCharsets.UTF_8);
        Optional<Long> idxOpt = lastIndexOf(search, fromIndex);
        if (idxOpt.isPresent()) {
            long idx = idxOpt.get();
            int i = Math.toIntExact(idx);
            int len = search.length;
            utf8.subList(i, i + len).clear();
        }
        return this;
    }

    public <T extends ToString> StringGenerator remove(T content, long fromIndex, long toIndex) {
        checkIndex(fromIndex, toIndex);
        String str = content.toString();
        byte[] search = str.getBytes(StandardCharsets.UTF_8);
        List<Integer> toRemove = new ArrayList<>();
        long fromIdx = fromIndex;
        while (true) {
            Optional<Long> idxOpt = indexOf(search, fromIdx);
            if (!idxOpt.isPresent()) break;
            long idx = idxOpt.get();
            if (idx >= toIndex) break;
            toRemove.add(Math.toIntExact(idx));
            fromIdx = idx + search.length;
