/**
 * Parses the increment and chomping indicators for a block scalar.
 * Returns a token and a boolean indicating success.
 */
public static class ParserScanBlockScalarResolveAddOrSubResult {
    public final TokenT token;
    public final boolean success;

    public ParserScanBlockScalarResolveAddOrSubResult(TokenT token, boolean success) {
        this.token = token;
        this.success = success;
    }
}

public static ParserScanBlockScalarResolveAddOrSubResult parserScanBlockScalarResolveAddOrSub(
        ParserT parser,
        MarkT startMark,
        Box<Long> incrementBox,
        Box<Long> chompingBox) {
    // Set chomping indicator: + => 1, - => -1
    if (parser.buffer[parser.bufferPos] == 0x2B) {
        chompingBox.value = 1L;
    } else {
        chompingBox.value = -1L;
    }
    skip(parser);

    // Ensure at least one byte is available in buffer
    if (parser.unread < 1) {
        if (!parserUpdateBuffer(parser, 1)) {
            return new ParserScanBlockScalarResolveAddOrSubResult(new TokenT(), false);
        }
    }

    // Parse increment indicator if next char is a digit
    if (isDigit(parser.buffer, parser.bufferPos)) {
        if (parser.buffer[parser.bufferPos] == 0x30) {
            parserSetScannerError(
                    parser,
                    "while scanning a block scalar",
                    startMark,
                    "found an indentation indicator equal to 0"
            );
            return new ParserScanBlockScalarResolveAddOrSubResult(new TokenT(), false);
        }

        incrementBox.value = (long) asDigit(parser.buffer, parser.bufferPos);
        skip(parser);
    }

    // Return (None, false) — i.e., no token produced, parsing incomplete
    return new ParserScanBlockScalarResolveAddOrSubResult(new TokenT(), false);
}

