public class StreamingPowersetIterator<T> implements Iterator<List<T>> {
    private final List<T> elements;
    private long currentSize;        // 当前子集大小
    private final List<Long> indices; // 当前组合的索引
    private boolean initialized;
    private boolean done;

    public StreamingPowersetIterator(Iterator<T> base) {
        this.elements = new ArrayList<>();
        // 收集所有元素
        while (base.hasNext()) {
            this.elements.add(base.next());
        }
        this.currentSize = 0;
        this.indices = new ArrayList<>();
        this.initialized = false;
        this.done = false;
    }

    // 初始化当前大小的组合
    private boolean initializeSize() {
        this.indices.clear();
        if (this.currentSize > this.elements.size()) {
            return false;
        }
        for (long i = 0; i < this.currentSize; i++) {
            this.indices.add(i);
        }
        return true;
    }

    // 推进到下一个组合（同一大小内）
    private boolean advanceCombination() {
        if (this.currentSize == 0) {
            return false;
        }

        int n = this.elements.size();
        int i = (int) (this.currentSize - 1);

        while (i >= 0) {
            if (this.indices.get(i) < n - this.currentSize + i) {
                long nextIdx = this.indices.get(i) + 1;
                this.indices.set(i, nextIdx);
                for (int j = i + 1; j < this.currentSize; j++) {
                    long prev = this.indices.get(j - 1);
                    this.indices.set(j, prev + 1);
                }
                return true;
            }
            i--;
        }

        return false;
    }

    // 构建当前子集
    private List<T> buildSubset() {
        List<T> result = new ArrayList<>();
        for (long idx : this.indices) {
            result.add(this.elements.get((int) idx));
        }
        return result;
    }

    @Override
    public boolean hasNext() {
        if (this.done) {
            return false;
        }
        if (!this.initialized) {
            return true; // will return empty set
        }
        if (this.currentSize > 0 && this.advanceCombination()) {
            return true;
        }
        // would advance to next size or terminate
        return this.currentSize + 1 <= this.elements.size();
    }

    @Override
    public List<T> next() {
        if (this.done) {
            throw new NoSuchElementException();
        }

        if (!this.initialized) {
            this.initialized = true;
            return new ArrayList<>(); // empty set
        }

        // 尝试在当前大小内推进
        if (this.currentSize > 0 && this.advanceCombination()) {
            return this.buildSubset();
        }

        // 移动到下一个大小
        this.currentSize++;
        if (this.initializeSize()) {
            return this.buildSubset();
        }

        this.done = true;
        throw new NoSuchElementException();
    }
}

