import java.net.*;
import java.nio.*;
import java.nio.channels.*;
import java.util.*;
import java.util.concurrent.*;
import java.util.concurrent.atomic.*;

public class Server {
    private final BlockingQueue<Map.Entry<SocketAddress, byte[]>> queue = new LinkedBlockingQueue<>();
    private final ConcurrentHashMap<String, SocketAddress> registered = new ConcurrentHashMap<>();

    // Constants for protocol commands and responses
    private static final byte REGISTER_REQ = 1;
    private static final byte USERS_REQ = 2;
    private static final byte QUIT_REQ = 3;

    private static final String REGISTERED_RESP = "REGISTERED";
    private static final String OCCUPIED_RESP = "OCCUPIED";
    private static final String USERS_RESP = "USERS";
    private static final String NO_USER_RESP = "NO_USERS";
    private static final String UNREGISTERED_RESP = "UNREGISTERED";
    private static final String UNREGISTER_RESP = "USER_QUIT";

    public void startup() {
        try (DatagramChannel server = DatagramChannel.open()) {
            server.bind(new InetSocketAddress(8888));
            System.out.println("server started");

            // Consumer thread for sending responses
            new Thread(() -> {
                while (true) {
                    try {
                        Map.Entry<SocketAddress, byte[]> resp = queue.take();
                        if (server.isOpen()) {
                            server.send(ByteBuffer.wrap(resp.getValue()), resp.getKey());
                        }
                    } catch (InterruptedException | IOException e) {
                        Thread.currentThread().interrupt();
                        return;
                    }
                }
            }).start();

            // Buffer for incoming datagrams
            ByteBuffer buf = ByteBuffer.allocate(1024);

            while (true) {
                buf.clear();
                SocketAddress clientAddress;
                try {
                    clientAddress = server.receive(buf);
                    if (clientAddress == null) continue;
                } catch (IOException e) {
                    continue;
                }

                final SocketAddress finalClientAddress = clientAddress;
                final byte[] receivedBytes = new byte[buf.position()];
                buf.flip();
                buf.get(receivedBytes);

                // Process message asynchronously
                new Thread(() -> {
                    BulkArrayParser pd = new BulkArrayParser();
                    pd.fromBytes(receivedBytes);

                    if (pd.progress == BulkArrayParser.Progress.COMPLETED) {
                        try {
                            byte[] message = pd.data.orElseThrow().data.orElseThrow();
                            if (message.length == 0) {
                                queue.add(new AbstractMap.SimpleEntry<>(finalClientAddress,
                                        "ILLEGAL MESSAGE SENT!!!".getBytes()));
                                return;
                            }

                            byte cmd = message[0];
                            if (cmd == REGISTER_REQ) {
                                if (message.length < 2) {
                                    queue.add(new AbstractMap.SimpleEntry<>(finalClientAddress,
                                            "ILLEGAL MESSAGE SENT!!!".getBytes()));
                                    return;
                                }
                                String username = new String(Arrays.copyOfRange(message, 1, message.length));
                                SocketAddress existing = registered.putIfAbsent(username, finalClientAddress);
                                String resp = (existing != null) ? OCCUPIED_RESP : REGISTERED_RESP;
                                queue.add(new AbstractMap.SimpleEntry<>(finalClientAddress,
                                        resp.getBytes()));
                            } else if (cmd == USERS_REQ) {
                                Collection<String> users = registered.keySet();
                                if (users.isEmpty()) {
                                    queue.add(new AbstractMap.SimpleEntry<>(finalClientAddress,
                                            NO_USER_RESP.getBytes()));
                                } else {
                                    List<String> userList = new ArrayList<>();
                                    userList.add(USERS_RESP);
                                    for (Map.Entry<String, SocketAddress> entry : registered.entrySet()) {
                                        if (!entry.getValue().equals(finalClientAddress)) {
                                            userList.add(entry.getKey() + ":" + entry.getValue());
                                        }
                                    }
                                    if (userList.size() == 1) {
                                        queue.add(new AbstractMap.SimpleEntry<>(finalClientAddress,
                                                NO_USER_RESP.getBytes()));
                                    } else {
                                        byte[] bytes = new BulkArray(userList).toBytes();
                                        queue.add(new AbstractMap.SimpleEntry<>(finalClientAddress, bytes));
                                    }
                                }
                            } else if (cmd == QUIT_REQ) {
                                if (message.length < 2) {
                                    queue.add(new AbstractMap.SimpleEntry<>(finalClientAddress,
                                            "ILLEGAL MESSAGE SENT!!!".getBytes()));
                                    return;
                                }
                                String username = new String(Arrays.copyOfRange(message, 1, message.length));
                                registered.remove(username);
                                queue.add(new AbstractMap.SimpleEntry<>(finalClientAddress,
                                        UNREGISTERED_RESP.getBytes()));

                                for (Map.Entry<String, SocketAddress> entry : registered.entrySet()) {
                                    byte[] quitMsg = new BulkArray(Arrays.asList(UNREGISTER_RESP, username)).toBytes();
                                    queue.add(new AbstractMap.SimpleEntry<>(entry.getValue(), quitMsg));
                                }
                                System.out.println("quit: " + username);
                            } else {
                                queue.add(new AbstractMap.SimpleEntry<>(finalClientAddress,
                                        "ILLEGAL MESSAGE SENT!!!".getBytes()));
                            }
                        } catch (Exception e) {
                            queue.add(new AbstractMap.SimpleEntry<>(finalClientAddress,
                                    "ILLEGAL MESSAGE SENT!!!".getBytes()));
                        }
                    } else {
                        queue.add(new AbstractMap.SimpleEntry<>(finalClientAddress,
                                "ILLEGAL MESSAGE SENT!!!".getBytes()));
                    }
                }).start();
            }
        } catch (IOException e) {
            e.printStackTrace();
        }
    }

    // Minimal stubs to make code compile — real implementation depends on actual protocol library
    static class BulkArrayParser {
        enum Progress { COMPLETED, INCOMPLETE, ERROR }
        Progress progress = Progress.INCOMPLETE;
        Optional<BulkArrayParserResult> data = Optional.empty();

        BulkArrayParser fromBytes(byte[] bytes) {
            // Placeholder: real parser would populate this
            this.progress = Progress.COMPLETED;
            this.data = Optional.of(new BulkArrayParserResult(bytes));
            return this;
        }
    }

    static class BulkArrayParserResult {
        Optional<byte[]> data;

        BulkArrayParserResult(byte[] bytes) {
            this.data = Optional.of(bytes);
        }
    }

    static class BulkArray {
        private final List<String> elements;

        BulkArray(List<String> elements) {
            this.elements = elements;
        }

        BulkArray(String[] elements) {
            this.elements = Arrays.asList(elements);
        }

        byte[] toBytes() {
            // Simplified serialization — real impl would follow RESP or similar
            StringBuilder sb = new StringBuilder();
            sb.append("*").append(elements.size()).append("\r\n");
            for (String s : elements) {
                sb.append("$").append(s.length()).append("\r\n").append(s).append("\r\n");
            }
            return sb.toString().getBytes();
        }
    }

    // SimpleString stub
    static class SimpleString {
        private final String value;

        SimpleString(String value) {
            this.value = value;
        }

        byte[] toBytes() {
            return (value + "\r\n").getBytes();
        }
    }

    public static void main(String[] args) {
        new Server().startup();
    }
}

