public class Server {
    private let queue = BlockingQueue<(SocketAddress, Array<Byte>)>() //为了避免产生多线程中竞争，客户端也是
    private let registered = ConcurrentHashMap<String, SocketAddress>()
    public func startup() {
        try (server = UdpSocket(bindAt: 8888)) {
            server.bind()
            println('server started')
            spawn {
                while (let resp <- queue.dequeue()) {
                    if (!server.isClosed()) {
                        server.sendTo(resp[0], resp[1])
                    }
                }
            }
            while (true) {
                let buf = Array<Byte>(1024, repeat: 0)
                let (clientAddress, length) = server.receiveFrom(buf)
                spawn {
                    let pd = BulkArrayParser().fromBytes(buf[0..length])
                    if (pd.progress == Completed) {
                        let message = pd.data.getOrThrow().data.getOrThrow()
                        let cmd = message[0]
                        if (cmd == REGISTER_REQ) {
                            let resp = if (let Some(_) <- registered.putIfAbsent(message[1], clientAddress)) {
                                OCCUPIED_RESP
                            } else {
                                REGISTERED_RESP
                            }
                            // println('register: ${message[1]} ${clientAddress} ${resp}')
                            queue.enqueue((clientAddress, SimpleString(resp).toBytes()))
                        } else if (cmd == USERS_REQ) {
                            let users = Array<String>(registered.size, repeat: '')
                            users[0] = USERS_RESP
                            var i = 1
                            for ((k, v) in registered where v != clientAddress) {
                                users[i] = '${k}:${v}'
                                i++
                            }
                            let bytes = if(users.size == 1){
                                SimpleString(NO_USER_RESP).toBytes()
                            }else{
                                BulkArray(users).toBytes()
                            }
                            queue.enqueue((clientAddress, bytes))
                        } else if (cmd == QUIT_REQ) {
                            let user = message[1]
                            registered.remove(user)
                            queue.enqueue((clientAddress, SimpleString(UNREGISTERED_RESP).toBytes()))
                            for ((_, addr) in registered) {
                                queue.enqueue((addr, BulkArray([UNREGISTER_RESP, user]).toBytes()))
                            }
                            println('quit: ${user}')
                        } else {
                            queue.enqueue((clientAddress, SimpleString("ILLEGAL MESSAGE SENT!!!").toBytes()))
                        }
                    } else {
                        queue.enqueue((clientAddress, SimpleString("ILLEGAL MESSAGE SENT!!!").toBytes()))
                    }
                }
            }
        }
    }
}

