public static void generateCompare(ClassDecl d, HashSet<String> exclusion) {
    if (d.superTypes.isEmpty()) {
        d.upperBound = upperbound[0];
    }
    String typeName = d.identifier + (d.genericParamTokens != null ? d.genericParamTokens : "");
    d.superTypes.add(new RefType("Comparable<" + typeName + ">"));
    StringBuilder cmp = new StringBuilder();
    for (Decl decl : d.body.decls) {
        if (decl instanceof VarDecl varDecl &&
            !isStatic(varDecl) &&
            !exclusion.contains(varDecl.identifier.value) &&
            !exclusion.contains(varDecl.identifier.value + "_")) {
            cmp.append(String.format("result = f_data_cmp(this.%s, other.%s);\n",
                varDecl.identifier.value, varDecl.identifier.value));
            cmp.append("if (result != Ordering.EQ) {\n");
            cmp.append("    return result;\n");
            cmp.append("}\n");
        }
    }
    String funcCode = String.format(
        "public %s compare(%s other) {\n" +
        "    Ordering result = Ordering.EQ;\n" +
        "    %s" +
        "    return result;\n" +
        "}",
        openTokens(d), typeName, cmp.toString().replace("\n", "\n    ")
    );
    d.body.decls.add(new FuncDecl(funcCode));
}

