import java.util.*;

public class CommandCompletion {
    private List<CompletionSuggestion> commands;
    private List<String> completionHistory;
    private int maxHistorySize;
    private List<CompletionMatch> currentSuggestions;
    private int selectedIndex;
    private boolean isActive;

    public CommandCompletion() {
        this.commands = new ArrayList<>();
        this.completionHistory = new ArrayList<>();
        this.maxHistorySize = 50;
        this.currentSuggestions = new ArrayList<>();
        this.selectedIndex = -1;
        this.isActive = false;

        // 初始化内置命令
        initializeBuiltinCommands();
    }

    /**
     * 初始化内置命令数据库
     */
    private void initializeBuiltinCommands() {
        // 系统命令
        addCommand("help", "显示帮助信息", "system",
                Arrays.asList("h", "?"), Arrays.asList("[command]"), Arrays.asList("help", "help config"), 100);
        addCommand("exit", "退出程序", "system",
                Arrays.asList("quit", "q"), Collections.emptyList(), Arrays.asList("exit"), 95);
        addCommand("clear", "清屏", "system",
                Arrays.asList("cls"), Collections.emptyList(), Arrays.asList("clear"), 90);
        addCommand("config", "配置管理", "system",
                Arrays.asList("cfg"), Arrays.asList("[key] [value]"), Arrays.asList("config", "config theme dark"), 85);
        addCommand("status", "显示系统状态", "system",
                Arrays.asList("stat"), Collections.emptyList(), Arrays.asList("status"), 80);
        addCommand("history", "显示历史记录", "system",
                Arrays.asList("hist"), Arrays.asList("[count]"), Arrays.asList("history", "history 10"), 75);

        // 模式切换命令
        addCommand("mode", "切换输入模式", "mode",
                Arrays.asList("m"), Arrays.asList("prompt|bash|koding"), Arrays.asList("mode bash", "mode koding"), 70);
        addCommand("prompt", "切换到对话模式", "mode",
                Arrays.asList("p"), Collections.emptyList(), Arrays.asList("prompt"), 65);
        addCommand("bash", "切换到命令模式", "mode",
                Arrays.asList("b"), Collections.emptyList(), Arrays.asList("bash"), 65);
        addCommand("koding", "切换到编程模式", "mode",
                Arrays.asList("k", "code"), Collections.emptyList(), Arrays.asList("koding"), 65);

        // 文件操作命令
        addCommand("read", "读取文件", "file",
                Arrays.asList("r"), Arrays.asList("<filename>"), Arrays.asList("read config.json"), 60);
        addCommand("write", "写入文件", "file",
                Arrays.asList("w"), Arrays.asList("<filename> <content>"), Arrays.asList("write test.txt hello"), 60);
        addCommand("list", "列出文件", "file",
                Arrays.asList("ls", "dir"), Arrays.asList("[path]"), Arrays.asList("list", "list src/"), 55);

        // AI相关命令
        addCommand("ask", "询问AI助手", "ai",
                Arrays.asList("query"), Arrays.asList("<question>"), Arrays.asList("ask 如何使用仓颉"), 50);
        addCommand("generate", "生成代码", "ai",
                Arrays.asList("gen"), Arrays.asList("<description>"), Arrays.asList("generate 排序函数"), 50);
        addCommand("analyze", "分析代码", "ai",
                Arrays.asList("check"), Arrays.asList("<code>"), Arrays.asList("analyze main.cj"), 45);

        // 工具命令
        addCommand("test", "运行测试", "tool",
                Arrays.asList("t"), Arrays.asList("[pattern]"), Arrays.asList("test", "test *_test.cj"), 40);
        addCommand("build", "构建项目", "tool",
                Arrays.asList("compile"), Collections.emptyList(), Arrays.asList("build"), 40);
        addCommand("run", "运行程序", "tool",
                Arrays.asList("exec"), Arrays.asList("[args...]"), Arrays.asList("run", "run --debug"), 35);
    }

    /**
     * 添加命令到数据库
     */
    private void addCommand(String command, String description, String category,
                            List<String> aliases, List<String> parameters,
                            List<String> examples, int priority) {
        CompletionSuggestion suggestion = new CompletionSuggestion(
                command, description, category, new ArrayList<>(aliases),
                new ArrayList<>(parameters), new ArrayList<>(examples), priority);
        commands.add(suggestion);
    }

    /**
     * 解析斜杠命令输入
     */
    public Pair<String, String> parseSlashCommand(String input) {
        String trimmed = input.trim();

        if (!trimmed.startsWith("/")) {
            return new Pair<>("", "");
        }

        String withoutSlash = trimmed.substring(1);
        int spaceIndex = withoutSlash.indexOf(' ');

        if (spaceIndex == -1) {
            return new Pair<>(withoutSlash, "");
        } else {
            String command = withoutSlash.substring(0, spaceIndex);
            String args = withoutSlash.substring(spaceIndex + 1).trim();
            return new Pair<>(command, args);
        }
    }

    /**
     * 更新补全建议
     */
    public void updateSuggestions(String input) {
        currentSuggestions.clear();
        selectedIndex = -1;

        if (!input.startsWith("/")) {
            isActive = false;
            return;
        }

        isActive = true;
        Pair<String, String> parsed = parseSlashCommand(input);
        String command = parsed.first;
        String args = parsed.second;

        if (command.isEmpty()) {
            // 显示所有命令
            for (CompletionSuggestion cmd : commands) {
                CompletionMatch completionMatch = new CompletionMatch(cmd, 1.0, "all");
                currentSuggestions.add(completionMatch);
            }
        } else {
            // 查找匹配的命令
            findMatchingCommands(command);
        }

        // 按优先级和匹配分数排序
        sortSuggestions();

        if (!currentSuggestions.isEmpty()) {
            selectedIndex = 0;
        }
    }

    /**
     * 查找匹配的命令
     */
    private void findMatchingCommands(String query) {
        String lowerQuery = query.toLowerCase(Locale.US);

        for (CompletionSuggestion cmd : commands) {
            CompletionMatch matchResult = calculateMatch(cmd, lowerQuery);
            if (matchResult.getMatchScore() > 0.0) {
                currentSuggestions.add(matchResult);
            }
        }
    }

    /**
     * 计算匹配分数
     */
    private CompletionMatch calculateMatch(CompletionSuggestion cmd, String query) {
        String cmdLower = cmd.getCommand().toLowerCase(Locale.US);

        // 精确匹配
        if (cmdLower.equals(query)) {
            return new CompletionMatch(cmd, 1.0, "exact");
        }

        // 前缀匹配
        if (cmdLower.startsWith(query)) {
            double score = (double) query.length() / cmdLower.length();
            return new CompletionMatch(cmd, score * 0.9, "prefix");
        }

        // 别名匹配
        for (String alias : cmd.getAliases()) {
            String aliasLower = alias.toLowerCase(Locale.US);
            if (aliasLower.equals(query)) {
                return new CompletionMatch(cmd, 0.95, "alias");
            }
            if (aliasLower.startsWith(query)) {
                double score = (double) query.length() / aliasLower.length();
                return new CompletionMatch(cmd, score * 0.8, "alias");
            }
        }

        // 模糊匹配
        double fuzzyScore = calculateFuzzyMatch(cmdLower, query);
        if (fuzzyScore > 0.3) {
            return new CompletionMatch(cmd, fuzzyScore * 0.7, "fuzzy");
        }

        return new CompletionMatch(cmd, 0.0, "none");
    }

    /**
     * 计算模糊匹配分数
     */
    private double calculateFuzzyMatch(String text, String query) {
        if (query.isEmpty()) {
            return 0.0;
        }

        int matches = 0;
        int textIndex = 0;

        for (int i = 0; i < query.length(); i++) {
            char queryChar = query.charAt(i);
            boolean found = false;

            for (int j = textIndex; j < text.length(); j++) {
                if (text.charAt(j) == queryChar) {
                    matches++;
                    textIndex = j + 1;
                    found = true;
                    break;
                }
            }

            if (!found) {
                break;
            }
        }

        return (double) matches / query.length();
    }

    /**
     * 排序建议列表
     */
    private void sortSuggestions() {
        // 简单的冒泡排序，按匹配分数和优先级排序
        int n = currentSuggestions.size();
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < n - i - 1; j++) {
                CompletionMatch current = currentSuggestions.get(j);
                CompletionMatch next = currentSuggestions.get(j + 1);

                double currentWeight = current.getMatchScore() + (double) current.getSuggestion().getPriority() / 1000.0;
                double nextWeight = next.getMatchScore() + (double) next.getSuggestion().getPriority() / 1000.0;

                if (currentWeight < nextWeight) {
                    // 交换位置
                    currentSuggestions.set(j, next);
                    currentSuggestions.set(j + 1, current);
                }
            }
        }
    }

    /**
     * 获取当前建议列表
     */
    public List<CompletionMatch> getCurrentSuggestions() {
        return currentSuggestions;
    }

    /**
     * 获取选中的建议索引
     */
    public int getSelectedIndex() {
        return selectedIndex;
    }

    /**
     * 设置选中的建议索引
     */
    public void setSelectedIndex(int index) {
        if (index >= 0 && index < currentSuggestions.size()) {
            selectedIndex = index;
        }
    }

    /**
     * 移动到下一个建议
     */
    public void selectNext() {
        if (!currentSuggestions.isEmpty()) {
            selectedIndex = (selectedIndex + 1) % currentSuggestions.size();
        }
    }

    /**
     * 移动到上一个建议
     */
    public void selectPrevious() {
        if (!currentSuggestions.isEmpty()) {
            selectedIndex = (selectedIndex <= 0) ? currentSuggestions.size() - 1 : selectedIndex - 1;
        }
    }

    /**
     * 获取当前选中的建议
     */
    public Optional<CompletionMatch> getSelectedSuggestion() {
        if (selectedIndex >= 0 && selectedIndex < currentSuggestions.size()) {
            return Optional.of(currentSuggestions.get(selectedIndex));
        }
        return Optional.empty();
    }

    /**
     * 应用选中的建议
     */
    public Optional<String> applySelectedSuggestion() {
        Optional<CompletionMatch> selectedSuggestion = getSelectedSuggestion();
        if (selectedSuggestion.isPresent()) {
            CompletionMatch completionMatch = selectedSuggestion.get();
            String command = completionMatch.getSuggestion().getCommand();
            addToHistory(command);
            return Optional.of("/" + command + " ");
        } else {
            return Optional.empty();
        }
    }

    /**
     * 添加到历史记录
     */
    public void addToHistory(String command) {
        // 移除重复项
        completionHistory.removeIf(c -> c.equals(command));

        // 添加到开头
        completionHistory.add(0, command);

        // 限制历史记录大小
        while (completionHistory.size() > maxHistorySize) {
            completionHistory.remove(completionHistory.size() - 1);
        }
    }

    /**
     * 获取历史记录
     */
    public List<String> getHistory() {
        return completionHistory;
    }

    /**
     * 清空建议
     */
    public void clearSuggestions() {
        currentSuggestions.clear();
        selectedIndex = -1;
        isActive = false;
    }

    /**
     * 检查是否处于活动状态
     */
    public boolean isCompletionActive() {
        return isActive && !currentSuggestions.isEmpty();
    }

    /**
     * 获取命令的参数提示
     */
    public Optional<List<String>> getParameterHints(String command) {
        for (CompletionSuggestion cmd : commands) {
            if (cmd.getCommand().equals(command)) {
                return Optional.of(cmd.getParameters());
            }

            for (String alias : cmd.getAliases()) {
                if (alias.equals(command)) {
                    return Optional.of(cmd.getParameters());
                }
            }
        }
        return Optional.empty();
    }

    /**
     * 获取命令的使用示例
     */
    public Optional<List<String>> getCommandExamples(String command) {
        for (CompletionSuggestion cmd : commands) {
            if (cmd.getCommand().equals(command)) {
                return Optional.of(cmd.getExamples());
            }

            for (String alias : cmd.getAliases()) {
                if (alias.equals(command)) {
                    return Optional.of(cmd.getExamples());
                }
            }
        }
        return Optional.empty();
    }

    /**
     * 添加自定义命令
     */
    public void addCustomCommand(CompletionSuggestion suggestion) {
        commands.add(suggestion);
    }

    /**
     * 移除命令
     */
    public boolean removeCommand(String command) {
        for (int i = 0; i < commands.size(); i++) {
            if (commands.get(i).getCommand().equals(command)) {
                commands.remove(i);
                return true;
            }
        }
        return false;
    }

    /**
     * 获取所有命令分类
     */
    public List<String> getCategories() {
        List<String> categories = new ArrayList<>();
        for (CompletionSuggestion cmd : commands) {
            boolean found = false;
            for (String cat : categories) {
                if (cat.equals(cmd.getCategory())) {
                    found = true;
                    break;
                }
            }
            if (!found) {
                categories.add(cmd.getCategory());
            }
        }
        return categories;
    }

    /**
     * 按分类获取命令
     */
    public List<CompletionSuggestion> getCommandsByCategory(String category) {
        List<CompletionSuggestion> result = new ArrayList<>();
        for (CompletionSuggestion cmd : commands) {
            if (cmd.getCategory().equals(category)) {
                result.add(cmd);
            }
        }
        return result;
    }

    /**
     * 格式化建议显示文本
     */
    public String formatSuggestion(CompletionMatch completionMatch, int maxWidth) {
        CompletionSuggestion cmd = completionMatch.getSuggestion();
        String name = cmd.getCommand();
        String desc = cmd.getDescription();
        String category = cmd.getCategory();

        // 构建显示文本
        StringBuilder result = new StringBuilder("/");
        result.append(name);

        // 添加参数提示
        List<String> parameters = cmd.getParameters();
        if (!parameters.isEmpty()) {
            result.append(" ");
            for (int i = 0; i < parameters.size(); i++) {
                if (i > 0) {
                    result.append(" ");
                }
                result.append(parameters.get(i));
            }
        }

        // 添加描述
        int remainingWidth = maxWidth - result.length() - 3; // 3 for " - "
        if (remainingWidth > 10 && !desc.isEmpty()) {
            result.append(" - ");
            if (desc.length() <= remainingWidth) {
                result.append(desc);
            } else {
                String truncatedDesc = desc.substring(0, Math.min(remainingWidth - 3, desc.length()));
                result.append(truncatedDesc).append("...");
            }
        }

        return result.toString();
    }

    // Helper class to represent a pair of values
    public static class Pair<T, U> {
        public final T first;
        public final U second;

        public Pair(T first, U second) {
            this.first = first;
            this.second = second;
        }
    }
}

