class CommentStartDashState extends TokeniserState {
    @Override
    protected void read(Tokeniser tker, CharacterReader r) {
        char c = r.consume();
        switch (c) {
            case '-':
                tker.transition(CommentEnd.class);
                break;
            case '\u0000': // nullChar
                tker.error(this);
                tker.commentPending.append('\uFFFD'); // replacementChar
                tker.transition(CommentState.class);
                break;
            case '>':
                tker.error(this);
                tker.emitCommentPending();
                tker.transition(Data.class);
                break;
            case '\u0004': // eof (assuming EOF is represented as EOT character 0x04)
                tker.eofError(this);
                tker.emitCommentPending();
                tker.transition(Data.class);
                break;
            default:
                tker.commentPending.append(c);
                tker.transition(CommentState.class);
                break;
        }
    }
}

