public class Image extends BaseObject {
    private Texture _texture;
    private Resource _resource;
    private ImageFillMode _fillMode;
    private Color _tint;

    /**
     * 创建图片对象
     */
    public Image() {
        super();
        _texture = null;
        _resource = null;
        _fillMode = ImageFillMode.Contain;
        _tint = Colors.WHITE;
    }

    /**
     * 从文件创建图片对象
     */
    public Image(String path) {
        super();
        _texture = new Texture(path);
        _resource = null;
        _fillMode = ImageFillMode.Contain;
        _tint = Colors.WHITE;

        if (_texture != null) {
            _minSize = _texture.size();
        }
    }

    /**
     * 从资源创建图片对象
     */
    public Image(Resource resource) {
        super();
        _texture = null;
        _resource = resource;
        _fillMode = ImageFillMode.Contain;
        _tint = Colors.WHITE;
    }

    /**
     * 获取填充模式
     */
    public ImageFillMode fillMode() {
        return _fillMode;
    }

    /**
     * 设置填充模式
     */
    public void setFillMode(ImageFillMode mode) {
        _fillMode = mode;
        refresh();
    }

    /**
     * 获取色调
     */
    public Color tint() {
        return _tint;
    }

    /**
     * 设置色调
     */
    public void setTint(Color color) {
        _tint = color;
        refresh();
    }

    @Override
    public void render(Painter painter, Rect bounds) {
        if (!_visible) {
            return;
        }

        if (_texture != null) {
            // 根据填充模式计算实际绘制区域
            Rect drawRect;
            switch (_fillMode) {
                case Contain:
                    drawRect = calculateContainRect(_texture.size(), bounds);
                    break;
                case Cover:
                    drawRect = calculateCoverRect(_texture.size(), bounds);
                    break;
                case Stretch:
                    drawRect = bounds;
                    break;
                case Original:
                    drawRect = new Rect(bounds.x, bounds.y,
                            (float) _texture.width(), (float) _texture.height());
                    break;
                default:
                    drawRect = bounds;
            }

            painter.drawTextureTinted(_texture, drawRect, _tint);
        }
    }

    private Rect calculateContainRect(Size texSize, Rect bounds) {
        float scaleX = bounds.width / texSize.width;
        float scaleY = bounds.height / texSize.height;
        float scale = Math.min(scaleX, scaleY);

        float width = texSize.width * scale;
        float height = texSize.height * scale;
        float x = bounds.x + (bounds.width - width) / 2.0f;
        float y = bounds.y + (bounds.height - height) / 2.0f;

        return new Rect(x, y, width, height);
    }

    private Rect calculateCoverRect(Size texSize, Rect bounds) {
        float scaleX = bounds.width / texSize.width;
        float scaleY = bounds.height / texSize.height;
        float scale = Math.max(scaleX, scaleY);

        float width = texSize.width * scale;
        float height = texSize.height * scale;
        float x = bounds.x + (bounds.width - width) / 2.0f;
        float y = bounds.y + (bounds.height - height) / 2.0f;

        return new Rect(x, y, width, height);
    }
}

