        _texture = Some(Texture(path))
        _resource = None
        _fillMode = ImageFillMode.Contain
        _tint = Colors.white

        match (_texture) {
            case Some(tex) =>
                _minSize = tex.size()
            case None => ()
        }
    }

    /**
     * 从资源创建图片对象
     */
    public init(resource: Resource) {
        super()
        _texture = None
        _resource = Some(resource)
        _fillMode = ImageFillMode.Contain
        _tint = Colors.white
    }

    /**
     * 获取填充模式
     */
    public func fillMode(): ImageFillMode {
        return _fillMode
    }

    /**
     * 设置填充模式
     */
    public func setFillMode(mode: ImageFillMode): Unit {
        _fillMode = mode
        refresh()
    }

    /**
     * 获取色调
     */
    public func tint(): Color {
        return _tint
    }

    /**
     * 设置色调
     */
    public func setTint(color: Color): Unit {
        _tint = color
        refresh()
    }

    public override func render(painter: Painter, bounds: Rect): Unit {
        if (!_visible) {
            return
        }

        match (_texture) {
            case Some(tex) =>
                // 根据填充模式计算实际绘制区域
                let drawRect = match (_fillMode) {
                    case ImageFillMode.Contain =>
                        calculateContainRect(tex.size(), bounds)
                    case ImageFillMode.Cover =>
                        calculateCoverRect(tex.size(), bounds)
                    case ImageFillMode.Stretch =>
                        bounds
                    case ImageFillMode.Original =>
                        Rect(bounds.x, bounds.y, Float32(tex.width()), Float32(tex.height()))
                }

                painter.drawTextureTinted(tex, drawRect, _tint)
            case None => ()
        }
    }

    private func calculateContainRect(texSize: Size, bounds: Rect): Rect {
        let scaleX = bounds.width / texSize.width
        let scaleY = bounds.height / texSize.height
        let scale = if (scaleX < scaleY) { scaleX } else { scaleY }

        let width = texSize.width * scale
        let height = texSize.height * scale
        let x = bounds.x + (bounds.width - width) / 2.0
        let y = bounds.y + (bounds.height - height) / 2.0

        return Rect(x, y, width, height)
    }

    private func calculateCoverRect(texSize: Size, bounds: Rect): Rect {
        let scaleX = bounds.width / texSize.width
        let scaleY = bounds.height / texSize.height
        let scale = if (scaleX > scaleY) { scaleX } else { scaleY }

        let width = texSize.width * scale
        let height = texSize.height * scale
        let x = bounds.x + (bounds.width - width) / 2.0
        let y = bounds.y + (bounds.height - height) / 2.0

        return Rect(x, y, width, height)
    }
}

