import java.util.*;

public class KSmallest {
    public static <T> List<T> kSmallest(Iterator<T> xs, int k, Comparator<T> less) {
        if (k <= 0) {
            return new ArrayList<>();
        }

        // 使用 max-heap 维护 k 个最小元素
        // max-heap 的堆顶是当前 k 个元素中最大的
        PriorityQueue<T> heap = new PriorityQueue<>((a, b) -> less.compare(b, a));

        while (xs.hasNext()) {
            T x = xs.next();
            if (heap.size() < k) {
                heap.offer(x);
            } else {
                // 如果当前 element is smaller than the largest in heap, replace it
                T top = heap.peek();
                if (top != null && less.compare(x, top) < 0) {
                    heap.poll();
                    heap.offer(x);
                }
            }
        }

        // Extract elements and collect into list (in descending order from max-heap)
        List<T> result = new ArrayList<>();
        while (!heap.isEmpty()) {
            result.add(heap.poll());
        }
        // Reverse to get ascending order (since max-heap yields largest first)
        Collections.reverse(result);
        return result;
    }

    // Example usage (optional main for testing)
    public static void main(String[] args) {
        // Example: find 3 smallest integers
        List<Integer> input = Arrays.asList(7, 10, 4, 3, 20, 15);
        Iterator<Integer> iter = input.iterator();
        List<Integer> smallest3 = kSmallest(iter, 3, Integer::compareTo);
        System.out.println(smallest3); // e.g., [3, 4, 7]
    }
