import java.time.DateTimeException;
import java.time.Instant;
import java.time.ZoneId;
import java.time.format.DateTimeFormatter;
import java.time.format.DateTimeParseException;
import java.util.Arrays;
import java.util.Objects;
import java.util.Optional;

/**
 * Represents an FTP file entry parsed from an FTP server listing.
 * This class mimics Unix-style file permissions and metadata.
 */
public class FTPFile {

    /** Constant indicating the file is a regular file. */
    public static final long FILE_TYPE = 0L;

    /** Constant indicating the file is a directory. */
    public static final long DIRECTORY_TYPE = 1L;

    /** Constant indicating the file is a symbolic link. */
    public static final long SYMBOLIC_LINK_TYPE = 2L;

    /** Constant indicating the file type is unknown. */
    public static final long UNKNOWN_TYPE = 3L;

    /** Constant indicating user access permissions. */
    public static final long USER_ACCESS = 0L;

    /** Constant indicating group access permissions. */
    public static final long GROUP_ACCESS = 1L;

    /** Constant indicating world (other) access permissions. */
    public static final long WORLD_ACCESS = 2L;

    /** Constant indicating read permission. */
    public static final long READ_PERMISSION = 0L;

    /** Constant indicating write permission. */
    public static final long WRITE_PERMISSION = 1L;

    /** Constant indicating execute permission. */
    public static final long EXECUTE_PERMISSION = 2L;

    /** File type, defaulting to unknown. */
    private long _type = UNKNOWN_TYPE;

    /** Hard link count; 0 means invalid. */
    private long hardLinkCount = 0L;

    /** File size in bytes; -1 means unknown. */
    private long size = -1L;

    /** Raw FTP listing line used to construct this object. */
    private String rawListing = "";

    /** File owner username (may be numeric string). */
    private String user = "";

    /** Group name (may be numeric string). */
    private String group = "";

    /** Filename. */
    private String name = "";

    /** Target of symbolic link, if any. */
    private String link = "";

    /** File modification timestamp. */
    private Optional<Instant> calendar = Optional.empty();

    /**
     * Permissions matrix: [access][permission] → boolean.
     * Null if parsing failed.
     */
    private final boolean[][] permissions;

    /**
     * Constructs an empty FTPFile with all permissions unset.
     */
    public FTPFile() {
        this.rawListing = "";
        this.permissions = new boolean[3][3];
        for (int i = 0; i < 3; i++) {
            Arrays.fill(this.permissions[i], false);
        }
    }

    /**
     * Constructs an FTPFile for an unparsable listing line.
     *
     * @param rawListing the unparsable FTP server listing line
     */
    public FTPFile(String rawListing) {
        this.rawListing = Objects.requireNonNull(rawListing, "rawListing must not be null");
        this.permissions = null;
    }

    /**
     * Gets the format character representing the file type.
     *
     * @return '-' for file, 'd' for directory, 'l' for symlink, '?' for unknown
     */
    private char formatType() {
        return switch ((int) _type) {
            case 0 -> '-';
            case 1 -> 'd';
            case 2 -> 'l';
            default -> '?';
        };
    }

    /**
     * Gets the group name owning the file.
     *
     * @return group name (may be numeric string)
     */
    public String getGroup() {
        return group;
    }

    /**
     * Gets the number of hard links to the file.
     *
     * @return hard link count
     */
    public long getHardLinkCount() {
        return hardLinkCount;
    }

    /**
     * Gets the target of the symbolic link, or empty string if not a symlink.
     *
     * @return symlink target, or empty string
     */
    public String getLink() {
        return link;
    }

    /**
     * Gets the filename.
     *
     * @return filename
     */
    public String getName() {
        return name;
    }

    /**
     * Gets the original raw FTP listing line used to initialize this object.
     *
     * @return raw listing line
     */
    public String getRawListing() {
        return rawListing;
    }

    /**
     * Gets the file size in bytes.
     *
     * @return file size in bytes, or -1 if unknown
     */
    public long getSize() {
        return size;
    }

    /**
     * Gets the file timestamp (usually last modified time).
     *
     * @return optional Instant representing the timestamp
     */
    public Optional<Instant> getTimestamp() {
        return calendar;
    }

    /**
     * Gets the file type (one of the *_TYPE constants).
     *
     * @return file type constant
     */
    public long getType() {
        return _type;
    }

    /**
     * Gets the username owning the file.
     *
     * @return owner username (may be numeric string)
     */
    public String getUser() {
        return user;
    }

    /**
     * Checks whether the given access group has the given permission.
     *
     * @param access     access group (USER_ACCESS, GROUP_ACCESS, WORLD_ACCESS)
     * @param permission permission (READ_PERMISSION, WRITE_PERMISSION, EXECUTE_PERMISSION)
     * @return true if valid and permission is granted, false otherwise
     */
    public boolean hasPermission(long access, long permission) {
        if (permissions == null) {
            return false;
        }
        int a = (int) access;
        int p = (int) permission;
        return a >= 0 && a < 3 && p >= 0 && p < 3 && permissions[a][p];
    }

    /**
     * Checks whether the file is a directory.
     *
     * @return true if directory, false otherwise
     */
    public boolean isDirectory() {
        return _type == DIRECTORY_TYPE;
    }

    /**
     * Checks whether the file is a regular file.
     *
     * @return true if regular file, false otherwise
     */
    public boolean isFile() {
        return _type == FILE_TYPE;
    }

    /**
     * Checks whether the file is a symbolic link.
     *
     * @return true if symlink, false otherwise
     */
    public boolean isSymbolicLink() {
        return _type == SYMBOLIC_LINK_TYPE;
    }

    /**
     * Checks whether the file type is unknown.
     *
     * @return true if unknown, false otherwise
     */
    public boolean isUnknown() {
        return _type == UNKNOWN_TYPE;
    }

    /**
     * Checks whether the FTPFile entry is valid (i.e., successfully parsed).
     * If invalid, only {@link #getRawListing()} is reliable.
     *
     * @return true if valid, false otherwise
     */
    public boolean isValid() {
        return permissions != null;
    }

    /**
     * Converts permissions for a given access group to a 3-character string (e.g., "rwx", "r--").
     *
     * @param access access group (USER_ACCESS, GROUP_ACCESS, WORLD_ACCESS)
     * @return permission string like "rwx"
     */
    private String permissionToString(long access) {
        StringBuilder sb = new StringBuilder();
        int a = (int) access;
        if (hasPermission(access, READ_PERMISSION)) {
            sb.append('r');
        } else {
            sb.append('-');
        }
        if (hasPermission(access, WRITE_PERMISSION)) {
            sb.append('w');
        } else {
            sb.append('-');
        }
        if (hasPermission(access, EXECUTE_PERMISSION)) {
            sb.append('x');
        } else {
            sb.append('-');
        }
        return sb.toString();
    }

    /**
     * Sets the group name owning the file.
     *
     * @param group group name (may be numeric string)
     */
    public void setGroup(String group) {
        this.group = Objects.requireNonNull(group, "group must not be null");
    }

    /**
     * Sets the number of hard links.
     *
     * @param links hard link count
     */
    public void setHardLinkCount(long links) {
        this.hardLinkCount = links;
    }

    /**
     * Sets the target of the symbolic link.
     *
     * @param link symlink target
     */
    public void setLink(String link) {
        this.link = Objects.requireNonNull(link, "link must not be null");
    }

    /**
     * Sets the filename.
     *
     * @param name filename
     */
    public void setName(String name) {
        this.name = Objects.requireNonNull(name, "name must not be null");
    }

    /**
     * Sets whether a given access group has a given permission.
     *
     * @param access     access group (USER_ACCESS, GROUP_ACCESS, WORLD_ACCESS)
     * @param permission permission (READ_PERMISSION, WRITE_PERMISSION, EXECUTE_PERMISSION)
     * @param value      true to grant, false to revoke
     * @throws IllegalStateException if permissions matrix is null (invalid entry)
     */
    public void setPermission(long access, long permission, boolean value) {
        if (permissions == null) {
            throw new IllegalStateException("Cannot set permission on invalid FTPFile entry");
        }
        int a = (int) access;
        int p = (int) permission;
        if (a < 0 || a >= 3 || p < 0 || p >= 3) {
            throw new IllegalArgumentException("Invalid access or permission index");
        }
        permissions[a][p] = value;
    }

    /**
     * Sets the raw FTP listing line.
     *
     * @param rawListing raw listing line
     */
    public void setRawListing(String rawListing) {
        this.rawListing = Objects.requireNonNull(rawListing, "rawListing must not be null");
    }

    /**
     * Sets the file size in bytes.
     *
     * @param size file size in bytes
     */
    public void setSize(long size) {
        this.size = size;
    }

    /**
     * Sets the file timestamp (last modified time).
     *
     * @param date optional Instant representing the timestamp
     */
    public void setTimestamp(Optional<Instant> date) {
        this.calendar = Objects.requireNonNull(date, "date must not be null");
    }

    /**
     * Sets the file type.
     *
     * @param type file type constant (FILE_TYPE, DIRECTORY_TYPE, etc.)
     */
    public void setType(long type) {
        this._type = type;
    }

    /**
     * Sets the username owning the file.
     *
     * @param user owner username (may be numeric string)
     */
    public void setUser(String user) {
        this.user = Objects.requireNonNull(user, "user must not be null");
    }

    /**
     * Gets a formatted string representation mimicking Unix 'ls -l' output.
     * Uses system default timezone.
     *
     * @return formatted string, or error message if invalid
     */
    public String toFormattedString() {
        return toFormattedString(null);
    }

    /**
     * Gets a formatted string representation mimicking Unix 'ls -l' output,
     * optionally using a custom timezone ID.
     *
     * @param timezone optional timezone ID (e.g., "UTC", "America/New_York")
     * @return formatted string, or error message if invalid
     */
    public String toFormattedString(String timezone) {
        if (!isValid()) {
            return "[Invalid: could not parse file entry]";
        }

        StringBuilder sb = new StringBuilder();

        try {
            sb.append(formatType());
            sb.append(permissionToString(USER_ACCESS));
            sb.append(permissionToString(GROUP_ACCESS));
            sb.append(permissionToString(WORLD_ACCESS));
            sb.append(' ');

            // Pad hard link count to width 4
            String linkStr = String.valueOf(hardLinkCount);
            while (linkStr.length() < 4) {
                linkStr = " " + linkStr;
            }
            sb.append(linkStr);
            sb.append(' ');

            // Pad user and group to width 8
            String u = getUser();
            while (u.length() < 8) u += " ";
            if (u.length() > 8) u = u.substring(0, 8);
            sb.append(u);

            String g = getGroup();
            while (g.length() < 8) g += " ";
            if (g.length() > 8) g = g.substring(0, 8);
            sb.append(g);

            // Pad size to width 8
            String sizeStr = String.valueOf(size);
            while (sizeStr.length() < 8) sizeStr = " " + sizeStr;
            if (sizeStr.length() > 8) sizeStr = sizeStr.substring(sizeStr.length() - 8);
            sb.append(sizeStr);

            // Format timestamp
            Optional<Instant> ts = getTimestamp();
            if (ts.isPresent()) {
                Instant instant = ts.get();
                ZoneId zone = ZoneId.systemDefault();
                if (timezone != null && !timezone.isEmpty()) {
                    try {
                        ZoneId tz = ZoneId.of(timezone);
                        if (!tz.equals(zone)) {
                            // Convert instant to target timezone
                            instant = instant.atZone(zone).withZoneSameInstant(tz).toInstant();
                        }
                    } catch (DateTimeException e) {
                        // Fall back to system default
                    }
                }

                // Format as " YYYY-MM-dd HH:mm" then optionally ":ss" or ":ss.S"
                DateTimeFormatter baseFmt = DateTimeFormatter.ofPattern(" yyyy-MM-dd HH:mm");
                sb.append(instant.atZone(zone).format(baseFmt));

                DateTimeFormatter secFmt = DateTimeFormatter.ofPattern(":ss");
                DateTimeFormatter fracFmt = DateTimeFormatter.ofPattern(":ss.S");

                try {
                    String secPart = instant.atZone(zone).format(secFmt);
                    sb.append(secPart);

                    // Add fractional second only if nanos > 0
                    if (instant.getNano() > 0) {
                        String fracPart = instant.atZone(zone).format(fracFmt);
                        sb.append(fracPart.substring(fracPart.length() - 2)); // ".S"
                    }
                } catch (DateTimeException ignored) {
                    // Ignore formatting errors for seconds
                }

                // Append timezone abbreviation (e.g., " PST")
                String zoneAbbrev = instant.atZone(zone).getZone().getDisplayName(
                        java.time.format.TextStyle.SHORT, java.util.Locale.getDefault());
                sb.append(" ").append(zoneAbbrev);
            }

            sb.append(' ');
            sb.append(getName());

        } catch (Exception ignored) {
            // Swallow all exceptions during formatting
        }

        return sb.toString();
    }

    /**
     * Returns the raw listing string.
     *
     * @return raw listing line
     */
    @Override
    public String toString() {
        return getRawListing();
    }
}

