    /**常量，表示其他用户访问权限。 */
    public static let WORLD_ACCESS: Int64 = 2

    /**常量，表示文件/目录读取权限。 */
    public static let READ_PERMISSION: Int64 = 0

    /**常量，表示文件/目录写权限。 */
    public static let WRITE_PERMISSION: Int64 = 1

    /**常量，表示文件/目录执行权限。 */
    public static let EXECUTE_PERMISSION: Int64 = 2

    /**文件类型，默认为未知类型。*/
    private var _type: Int64 = UNKNOWN_TYPE

    /**硬链接数，0表示无效。*/
    private var hardLinkCount: Int64 = 0

    /**文件大小，-1表示大小未知。*/
    private var size: Int64 = -1

    /**原始列表信息。*/
    private var rawListing: String

    /**文件所有者。*/
    private var user: String = ""

    /**所属组。*/
    private var group: String = ""

    /**文件名。*/
    private var name: String = ""

    /**符号链接指向文件名。*/
    private var link: String = ""

    /**文件修改时间。*/
    private var calendar: ?DateTime = None

    // e.g. _permissions[USER_ACCESS][READ_PERMISSION]
    /**表示权限的二维数组。如果为 None ，表示文件解析失败。*/
    private let permissions: ?Array<Array<Bool>>

    /**构造函数，创建一个空的 FTPFile 对象，权限都设置为无。*/
    public init() {
        this.rawListing = ""
        this.permissions = Array<Array<Bool>>(3, {_ => Array<Bool>(3, repeat: false)})
    }

    /**
     * 用于在解析失败时创建一个 FTPFile 对象的实例。主要用于 {@link FTPListParseEngine} 。
     *
     * @param RawListing 无法解析的条目行
     */
    public init(RawListing: String) {
        this.rawListing = RawListing
        this.permissions = None
    }

    /**
     * 获取文件类型对应的格式字符。
     * @return 文件类型对应的格式字符
     */
    private func formatType(): Rune {
        return match (_type) {
            case 0 =>  r'-'
            case 1 =>  r'd'
            case 2 =>  r'l'
            case _ =>  r'?'
        }
    }

    /**
     * 获取拥有文件的组的名称。有时字符串表示的为组号。
     *
     * @return 拥有文件的组的名称
     */
    public func getGroup(): String {
        return group
    }

    /**
     * 获取该文件的硬链接数。
     *
     * @return 该文件的硬链接数
     */
    public func getHardLinkCount(): Int64 {
        return hardLinkCount
    }

    /**
     * 如果FTPFile是符号链接，此方法返回符号链接指向的文件的名称。否则，返回String.empty。
     *
     * @return 符号链接指向的文件（如果FTPFile不是符号链接，则为String.empty）。
     */
    public func getLink(): String {
        return link
    }

    /**
     * 获取文件的名称。
     *
     * @return 文件的名称
     */
    public func getName(): String {
        return name
    }

    /**
     * 获取用于初始化FTPFile的原始FTP服务器列表条目。
     *
     * @return 用于初始化FTPFile的原始FTP服务器列表条目
     */
    public func getRawListing(): String {
        return rawListing
    }

    /**
     * 获取文件的大小（以字节为单位）。
     *
     * @return 文件的大小（以字节为单位）
     */
    public func getSize(): Int64 {
        return size
    }

    /**
     * 获取文件的时间戳。这通常是最后修改时间。
     *
     * @return 表示文件时间戳的 DateTime 实例。
     */
    public func getTimestamp(): ?DateTime {
        return calendar
    }

    /**
     * 获取文件的类型（ _TYPE 常量之一），可以为目录、普通文件或符号链接。
     *
     * @return 文件的类型。
     */
    public func getType(): Int64 {
        return _type
    }

    /**
     * 获取拥有文件的用户名。有时表示的为用户编号。
     *
     * @return 拥有文件的用户名。
     */
    public func getUser(): String {
        return user
    }

    /**
     * 判断给定访问组（ _ACCESS 常量之一）是否具有给定访问权限（ _PERMISSION 常量之一）。
     *
     * @param access     访问组（ _ACCESS 常量之一）
     * @param permission 访问权限（ _PERMISSION 常量之一）
     * @return 如果 {@link #isValid()} 为 true 且关联权限已设置，则为 true ；否则为 false 。
     */
    public func hasPermission(access: Int64, permission: Int64): Bool {
        if (permissions == None) {
            return false
        }
        return permissions.getOrThrow()[access][permission]
    }

    /**
     * 判断文件是否为目录。
     *
     * @return 如果文件类型为 {@link DIRECTORY_TYPE} ，则为 true ；否则为 false 。
     */
    public func isDirectory(): Bool {
        return _type == DIRECTORY_TYPE
    }

    /**
     * 判断文件是否为普通文件。
     *
     * @return 如果文件类型为 {@link FILE_TYPE} ，则为 true ；否则为 false 。
     */
    public func isFile(): Bool {
        return _type == FILE_TYPE
    }

    /**
     * 判断文件是否为符号链接。
     *
     * @return 如果文件类型为 {@link SYMBOLIC_LINK_TYPE} ，则为 true ；否则为 false 。
     */
    public func isSymbolicLink(): Bool {
        return _type == SYMBOLIC_LINK_TYPE
    }

    /**
     * 判断文件类型是否为未知。
     *
     * @return 如果文件类型为 {@link UNKNOWN_TYPE} ，则为 true ；否则为 false 。
     */
    public func isUnknown(): Bool {
        return _type == UNKNOWN_TYPE
    }

    /**
     * 判断条目是否有效。如果条目无效，只有 {@link #getRawListing()} 方法有用，其他方法可能会失败。
     *
     * @return 如果条目有效，则为 true ；否则为 false
     *
     * @see FTPClientConfig#setUnparseableEntries()
     */
    public func isValid(): Bool {
        return permissions != None
    }

    /**
     * 将给定访问组的权限转换为字符串表示形式。
     *
     * @param access 访问组
     * @return 权限的字符串表示形式
     */
    private func permissionToString(access: Int64): String {
        let sb = StringBuilder()
        if (hasPermission(access, READ_PERMISSION)) {
            sb.append('r')
        } else {
            sb.append('-')
        }
        if (hasPermission(access, WRITE_PERMISSION)) {
            sb.append('w')
        } else {
            sb.append('-')
        }
        if (hasPermission(access, EXECUTE_PERMISSION)) {
            sb.append('x')
        } else {
            sb.append('-')
        }
        return sb.toString()
    }

    /**
     * 设置文件所属组的名称，也可能是一个表示组编号的字符串。
     *
     * @param group 文件所属组的名称
     */
    public func setGroup(group: String): Unit {
        this.group = group
    }

    /**
     * 设置此文件的硬链接数。
     *
     * @param links 此文件的硬链接数
     */
    public func setHardLinkCount(links: Int64): Unit {
        this.hardLinkCount = links
    }

    /**
     * 如果 FTPFile 是一个符号链接，使用此方法设置被符号链接指向的文件的名称。
     *
     * @param link 被符号链接指向的文件
     */
    public func setLink(link: String): Unit {
        this.link = link
    }

    /**
     * 设置文件的名称。
     *
     * @param name 文件的名称
     */
    public func setName(name: String): Unit {
        this.name = name
    }

    /**
     * 设置给定访问组（  _ACCESS 常量之一）是否具有对文件的给定访问权限（  _PERMISSION 常量之一）。
     *
     * @param access     访问组（ _ACCESS 常量之一）
     * @param permission 访问权限（ _PERMISSION 常量之一）
     * @param value      如果允许权限，则为 true ；如果不允许，则为 false
     *
     * @throws NoneValueException 文件解析失败
     */
    public func setPermission(access: Int64, permission: Int64, value: Bool): Unit {
        // TODO: only allow permission setting if file is valid
        permissions.getOrThrow()[access][permission] = value
    }

    /**
     * 设置FTPFile创建时的原始FTP服务器列表。
     *
     * @param rawListing 原始FTP服务器列表
     */
    public func setRawListing(rawListing: String): Unit {
        this.rawListing = rawListing
    }

    /**
     * 以字节为单位设置文件大小。
     *
     * @param size 文件大小（以字节为单位）
     */
    public func setSize(size: Int64): Unit {
        this.size = size
    }

    /**
     * 设置文件时间戳。这通常指最后修改时间。
     *
     * @param date 表示文件时间戳的 DateTime 实例。
     */
    public func setTimestamp(date: ?DateTime): Unit {
        this.calendar = date
    }

    /**
     * 设置文件的类型（ {@link DIRECTORY_TYPE} 、 {@link FILE_TYPE} 等）。
     *
     * @param type 表示文件类型的整数代码
     */
    public func setType(Type: Int64): Unit {
        this._type = Type
    }

    /**
     * 设置拥有文件的用户的名称。这可能是表示用户编号的字符串。
     *
     * @param user 拥有文件的用户的名称
     */
    public func setUser(user: String): Unit {
        this.user = user
    }

    /**
     * 获取FTPFile信息的字符串表示形式，模仿Unix列表格式。
     *
     * @return FTPFile信息的字符串表示形式
     *
     * @throws IllegalArgumentException timezone长度超过 4096，或不合法
     * @throws InvalidDataException 时区文件加载失败
     */
    public func toFormattedString(): String {
        return toFormattedString(None)
    }

    /**
     * 获取FTPFile信息的字符串表示形式，允许修改时区。目前模仿Unix列表格式。
     *
     * @param timezone 将要替换的时区id的字符串表示
     * @return FTPFile信息的字符串表示形式
     */
    public func toFormattedString(timezone: ?String): String {
        if (!isValid()) {
            return "[Invalid: could not parse file entry]"
        }
        let sb = StringBuilder()
        try {
            sb.append(formatType())
            sb.append(permissionToString(USER_ACCESS))
            sb.append(permissionToString(GROUP_ACCESS))
            sb.append(permissionToString(WORLD_ACCESS))
            sb.append(' ')
            sb.append(getHardLinkCount().format("4"))
            sb.append(' ')
            sb.append(getUser().padEnd(8))
            sb.append(' ')
            sb.append(getGroup().padEnd(8))
            sb.append(' ')
            sb.append(getSize().format("8"))

            var timestamp: ?DateTime = getTimestamp()
            if (timestamp != None) {
                if (timezone != None) {
                    if (timezone != timestamp.getOrThrow().zoneId) {
                        /*
                         * TimeZone.load : 从系统中加载指定的时区
                         * 如果是windows系统，需要用户自行下载 IANA 时区文件
                         * 如果是Linux系统，可以直接加载成功
                         */
                        let newStamp: ?DateTime = timestamp.getOrThrow().inTimeZone(
                            TimeZone.load(timezone.getOrThrow()))
                        timestamp = newStamp
                    }
                }
                let time = timestamp.getOrThrow()
                sb.append(time.toString(" YYYY-MM-dd HH:mm"))
                if (time.nanosecond > 0) {
                    sb.append(time.toString(":ss.S"))
                } else if (time.second >= 0) {
                    sb.append(time.toString(":ss"))
                }
                sb.append(time.toString(" z"))
            }

            sb.append(' ')
            sb.append(getName())
        } catch (e: Exception) {
            // None
        }

        return sb.toString()
    }

    /**
     * 获取 FTPFile 信息的字符串表示形式。
     *
     * @return FTPFile信息的字符串表示形式
     * @see #getRawListing()
     */
    public func toString(): String {
        return getRawListing()
    }
}

