/**
 * Calculates the UTF-8 byte width of a leading byte.
 * Returns:
 *   1 for ASCII (0x00–0x7F),
 *   2 for 2-byte sequences (0xC0–0xDF),
 *   3 for 3-byte sequences (0xE0–0xEF),
 *   4 for 4-byte sequences (0xF0–0xF7),
 *   0 for invalid leading bytes.
 */
public static long width(byte b) {
    int unsignedB = b & 0xFF; // Convert to unsigned int
    if ((unsignedB & 0x80) == 0x00) {
        return 1L;
    } else if ((unsignedB & 0xE0) == 0xC0) {
        return 2L;
    } else if ((unsignedB & 0xF0) == 0xE0) {
        return 3L;
    } else if ((unsignedB & 0xF8) == 0xF0) {
        return 4L;
    } else {
        return 0L;
    }
}

