                let value = ResponseBuilderFactory.listOfStringBuilder.build(arrayMessage)
                userInfo.add(key, value)
            } else if (let Some(stringMessage) <- (valueMessage as BulkStringRedisMessage)) {
                // Redis 7.0.0
                let value = ResponseBuilderFactory.stringBuilder.build(stringMessage)
                let array = value.split(" ")
                if (array.size > 0) {
                    userInfo.add(key, ArrayList<String>(array))
                } else {
                    userInfo.add(key, value)
                }
            } else {
                throw RedisException("Incompatible type, ${valueMessage.getType()} is not the expect type")
            }
            case "channels" => if (let Some(arrayMessage) <- (valueMessage as ArraysRedisMessage)) {
                let value = ResponseBuilderFactory.listOfStringBuilder.build(arrayMessage)
                userInfo.add(key, value)
            } else if (let Some(stringMessage) <- (valueMessage as BulkStringRedisMessage)) {
                // Redis 7.0.0
                let value = ResponseBuilderFactory.stringBuilder.build(stringMessage)
                let array = value.split(" ")
                if (array.size > 0) {
                    userInfo.add(key, ArrayList<String>(array))
                } else {
                    userInfo.add(key, value)
                }
            } else {
                throw RedisException("Incompatible type, ${valueMessage.getType()} is not the expect type")
            }
            case "selectors" => if (let Some(arrayMessage) <- (valueMessage as ArraysRedisMessage)) {
                // List of Map
                let selectors = ArrayList<HashMap<String, String>>()
                if (let Some(children) <- arrayMessage.getValue()) {
                    for (child in children) {
                        let selectorEntry = ResponseBuilderFactory.stringToStringMapBuilder.build(child)
                        selectors.add(selectorEntry)
                    }
                }

                userInfo.add(key, selectors)
            }
            case _ => { => } // 未来版本扩展的Key
        }
    }
