import java.util.*;

public class KeyAndFlagsResponseBuilder implements ResponseBuilder<List<Map.Entry<String, List<String>>>> {
    @Override
    public List<Map.Entry<String, List<String>>> build(RedisMessage redisMessage) {
        List<Map.Entry<String, List<String>>> keyAndFlags = new ArrayList<>();

        if (redisMessage instanceof ArraysRedisMessage arraysMessage) {
            Optional<List<RedisMessage>> childrenOpt = arraysMessage.getValue();
            if (childrenOpt.isPresent()) {
                for (RedisMessage child : childrenOpt.get()) {
                    List<Map.Entry<String, List<String>>> keyValues =
                        ResponseBuilderFactory.listOfKeyValueBuilder.build(child);
                    for (Map.Entry<String, List<String>> keyValue : keyValues) {
                        String key = ResponseBuilderFactory.stringBuilder.build(keyValue.getKey());
                        List<String> flags = ResponseBuilderFactory.listOfStringBuilder.build(keyValue.getValue());
                        keyAndFlags.add(new AbstractMap.SimpleEntry<>(key, flags));
                    }
                }
            }
        } else {
            throw new RedisException("Incompatible type, " + redisMessage.getType() + " is not the expected type");
        }

        return keyAndFlags;
    }
}

