public void readCacheData(String uri, JsonFilesDir resultDir) {
    // 错误回调函数：触发动画加载错误事件
    BiConsumer<String, Exception> errCallBack = (str, e) -> {
        this.triggerEvent(str, new BMLoadAnimationErrorEvent(e));
    };

    // 检查沙箱中是否存在已下载的缓存资源
    FilePathObject existResult = isCacheExist(uri, resultDir.route);
    if (existResult.isExist()) {
        // 优先读取缓存 JSON 数据
        AnimationData cacheData = readJson(uri, resultDir.route, errCallBack);

        if (uri.endsWith(".json") || uri.endsWith(".js")) {
            boolean isExitNetworkAssets = false;
            for (int i = 0; i < cacheData.assets.size(); i++) {
                if (cacheData.assets.get(i).p.startsWith("http")) {
                    isExitNetworkAssets = true;
                    break;
                }
            }

            if (!cacheData.assets.isEmpty() && isExitNetworkAssets) {
                handleAssets(cacheData);
                this.setupAnimation(cacheData); // 加载含网络图片资源的 JSON
            } else {
                this.setupAnimation(cacheData); // 加载不含网络图片资源的 JSON
            }
        } else if (uri.endsWith(".zip")) {
            // 处理 ZIP 资源路径
            handleZipAssets(cacheData, resultDir.route);
            this.setupAnimation(cacheData);
        }
        this.isNetLoad = false;
    } else {
        // 缓存不存在，从网络下载资源
        BiConsumer<AnimationData, Boolean> inside = (jsonData, isNetLoad) -> {
            this.isNetLoad = isNetLoad;
            this.setupAnimation(jsonData);
        };

        downLoadSource.downLoadNetworkSource(
            uri,
            inside,
            resultDir,
            errCallBack,
            false,
            this.context
        );
    }
}

