    validateIndex(index, 3);
    if (_isMotorolaByteOrder) {
        return (getByte(index) << 16 & 0xFF0000) |  // 第1字节 → 24~17位
               (getByte(index + 1) << 8 & 0xFF00) |   // 第2字节 → 16~9位
               (getByte(index + 2) & 0xFF);           // 第3字节 → 8~0位
    } else {
        return (getByte(index + 2) << 16 & 0xFF0000) |  // 第3字节 → 24~17位
               (getByte(index + 1) << 8 & 0xFF00) |   // 第2字节 → 16~9位
               (getByte(index) & 0xFF);                // 第1字节 → 8~0位
    }
}

