public class TraceIterator<T> <: Iterator<T> where T <: ToString {
    var base: Iterator<T>
    var name: String
    var config: TraceConfig
    var index: Int64

    /**
     * 创建跟踪迭代器。
     *
     * @param base 底层迭代器
     * @param name 跟踪器名称
     * @param config 跟踪配置
     */
    public init(base: Iterator<T>, name: String, config: TraceConfig) {
        this.base = base
        this.name = name
        this.config = config
        this.index = 0
    }

    public func next(): Option<T> {
        let result = this.base.next()

        if (this.config.enabled) {
            match (result) {
                case Some(value) =>
                    let msg = "${this.config.prefix} ${this.name}[${this.index}]: ${value}"
                    this.config.output(msg)
                    this.index += 1
                case None =>
                    let msg = "${this.config.prefix} ${this.name}: end of iterator (${this.index} elements)"
                    this.config.output(msg)
            }
        } else {
            match (result) {
                case Some(_) => this.index += 1
                case None => ()
            }
        }

        return result
    }
}

