public class MMapFile implements AutoCloseable {
    private static final File ZERO_FILE = null;
    private static final int ANONYMOUS_FD = -1;

    private final File file;
    private final MMapProt[] prots;
    private final MMapFlag flag;
    private final long offset;
    private final long mapLength;

    private final int fd;
    private final MemorySegment pointer;
    private final BytePointerStream ptrStream;

    private final AtomicBoolean closed = new AtomicBoolean(false);
    private long dirtyStart = 0L;
    private long dirtyBytes = 0L;

    private static final long MEM_PAGE_SIZE = 4096L;
    private static final long DEFAULT_MMAP_BYTES = 1024 * 1024; // 1 MiB

    // Native method stubs (would be linked via JNI or jdk.incubator.foreign)
    private static native long mmap(long addr, long len, int prot, int flags, int fd, long offset);
    private static native int munmap(long addr, long len);
    private static native int msync(long addr, long len, int flags);

    static {
        // Load native library if needed
        // System.loadLibrary("mmap");
    }

    public MMapFile(File file, MMapProt[] prots, MMapFlag flag, long offset, long mapLength) throws IOException {
        this.file = file;
        this.prots = prots;
        this.flag = flag != null ? flag : MMapFlag.Private;
        this.offset = offset;
        this.mapLength = mapLength != 0 ? mapLength : DEFAULT_MMAP_BYTES;

        int protBits = combineProtBits(prots);
        boolean readable = (protBits & 1) != 0; // assuming Read=1
        boolean writable = (protBits & 2) != 0; // assuming Write=2

        int flags;
        int fd;
        if (!isZeroFile(file)) {
            if (writable && offset + mapLength > file.length()) {
                file.setLength(offset + mapLength);
            } else {
                throw new MMapException(
                    String.format("file %s is not writable but the file length - offset(%d - %d) is less than mapLength %d",
                        file.info().path, file.length(), offset, mapLength));
            }
            fd = getFileDescriptor(file);
            flags = this.flag.value;
        } else {
            fd = ANONYMOUS_FD;
            flags = this.flag.value | MMapFlag.Anonymous.value;
        }

        long addr = mmap(0L, mapLength, protBits, flags, fd, fd == ANONYMOUS_FD ? 0L : offset);
        if (addr == -1L) {
            throw new MMapException("mmap failed");
        }

        this.fd = fd;
        this.pointer = MemorySegment.ofAddress(addr, mapLength, Arena.global());
        this.ptrStream = new BytePointerStream(new CPointer<>(this.pointer), mapLength, readable, writable);
    }

    public static MMapFile anonymous(MMapProt[] prots, MMapFlag flag, long mapLength) throws IOException {
        return new MMapFile(ZERO_FILE, prots, flag, 0L, mapLength);
    }

    private static int combineProtBits(MMapProt[] prots) {
        int bits = 0;
        for (MMapProt p : prots) {
            switch (p) {
                case Read -> bits |= 1;
                case Write -> bits |= 2;
                case Execute -> bits |= 4;
            }
        }
        return bits;
    }

    private static boolean isZeroFile(File file) {
        return file == ZERO_FILE;
    }

    private static int getFileDescriptor(File file) throws IOException {
        // Simulate getting fd from FileChannel via reflection or jdk.internal.misc.Unsafe if needed
        // This is a placeholder — real impl depends on platform/JDK version
        throw new UnsupportedOperationException("getFileDescriptor not implemented");
    }

    public FileInfo getInfo() {
        return file.info();
    }

    public boolean isReadable() {
        return ptrStream.readable();
    }

    public boolean isWritable() {
        return ptrStream.writable();
    }

    public boolean isSyncable() {
        return !(flag == MMapFlag.Private || isAnonymous());
    }

    public boolean isAnonymous() {
        return fd == ANONYMOUS_FD;
    }

    /**
     * 相对文件头的读偏移量
     */
    public long getReadOffset() {
        return offset + ptrStream.readOffset();
    }

    public void setReadOffset(long value) {
        ptrStream.readOffset(value - offset);
    }

    /**
     * 相对文件头的写偏移量
     */
    public long getWriteOffset() {
        return offset + ptrStream.writeOffset();
    }

    public void setWriteOffset(long value) {
        ptrStream.writeOffset(value - offset);
    }

    /**
     * 同步内存映射区域到磁盘，取消映射，不关闭文件
     */
    public void syncAndUnmap() throws IOException {
        sync();
        unmap();
    }

    private void unmap() {
        if (pointer != null && pointer != MemorySegment.NULL) {
            int result = munmap(pointer.address().toRawLongValue(), mapLength);
            if (result != 0) {
                throw new MMapException("munmap failed");
            }
        }
    }

    /**
     * 使用指定的flag将未同步数据同步到磁盘。
     */
    public void sync(MSyncFlag flag) throws IOException {
        if (!isSyncable()) {
            throw new MMapException("current mmap can not sync, due to it is Anonymous or Private.");
        }
        long syncStart = (dirtyStart / MEM_PAGE_SIZE) * MEM_PAGE_SIZE;
        long len = dirtyBytes + (dirtyStart % MEM_PAGE_SIZE);
        int result = msync(ptrStream.pointerOffset(syncStart).toLong(), len, flag.value);
        if (result != 0) {
            throw new MMapException("msync failed");
        }
    }

    private void sync() throws IOException {
        if (dirtyBytes > 0 && isSyncable()) {
            sync(MSyncFlag.Sync);
            dirtyStart += dirtyBytes;
            dirtyBytes = 0;
        }
    }

    private MMapException extract(Optional<MMapException> ex, Throwable caused) {
        if (ex.isPresent()) {
            ex.get().addSuppressed(caused);
            return ex.get();
        } else {
            return new MMapException(caused);
        }
    }

    /**
     * 使用指定参数重映射。offset是文件开头的偏移量。mapLength是映射的内存大小，默认是当前的mapLength
     */
    public MMapFile remap(long offset, long mapLength, MMapFlag flag) throws IOException {
        sync();
        unmap();
        if (isAnonymous()) {
            return new MMapFile(file, prots, flag, offset, mapLength);
        } else {
            return file.mmap(offset, mapLength, flag);
        }
    }

    public boolean isClosed() {
        return closed.get();
    }

    /**
     * 同步内存映射区域到磁盘，取消映射，关闭文件
     */
    @Override
