    checkClosed();
    this.session.checkMessageListener();
    if (timeout.equals(Duration.ZERO)) {
        return this.receive();
    }

    sendPullCommand(timeout);
    if (timeout.compareTo(Duration.ZERO) > 0) {
        MessageDispatch md;
        if (info.prefetchSize == 0) {
            // We let the broker let us know when we timeout.
            md = dequeue(Duration.ofMillis(-1));
        } else {
            md = dequeue(timeout);
        }

        if (md != null) {
            beforeMessageIsConsumed(md);
            afterMessageIsConsumed(md, false);
            CJMSMessage message = createActiveMQMessage(md);
            if (message != null) {
                return message;
            }
        }
    }
    return null;
}

