public class FoldingCube extends JPanel implements Runnable {
    private static final long serialVersionUID = 1L;

    // State fields
    private FoldingCubeModel model = new FoldingCubeModel();
    private double size = 50.0;

    // Rendering context settings — simulated (antialiasing handled via Graphics2D)
    private final RenderingHints antialiasHints = new RenderingHints(
            RenderingHints.KEY_ANTIALIASING, RenderingHints.VALUE_ANTIALIAS_ON);

    // Animation state variables
    private float angle11 = 0.0f;
    private double opacity11 = 0.0;
    private float angle12 = 0.0f;
    private double opacity12 = 0.0;

    private float angle21 = 0.0f;
    private double opacity21 = 0.0;
    private float angle22 = 0.0f;
    private double opacity22 = 0.0;

    private float angle31 = 0.0f;
    private double opacity31 = 0.0;
    private float angle32 = 0.0f;
    private double opacity32 = 0.0;

    private float angle41 = 0.0f;
    private double opacity41 = 0.0;

    // Animator support
