    private long startTime;
    private double animationProgress = 0.0;
    private boolean isAnimating = false;
    private final List<AnimationTask> pendingAnimations = new ArrayList<>();

    // For simplicity, we simulate CanvasRenderingContext2D as no-op — actual drawing uses Graphics2D
    // All "context.*" calls are omitted; drawing happens in paintComponent.

    public FoldingCube() {
        setPreferredSize(new Dimension((int) model.size, (int) model.size));
        setBackground(Color.WHITE);
    }

    @Override
    public void run() {
        // Simulate aboutToAppear lifecycle hook
        size = model.size;

        // First animator sequence (short, triggers main animation)
        AnimatorOptions option1 = new AnimatorOptions(100, "ease", 0, AnimatorFill.NONE,
                AnimatorDirection.NORMAL, 1, 0.0, 1.0);
        AnimatorResult animator = new AnimatorResult(option1);
        animator.play();

        animator.setOnFinish(() -> {
            animator11();
            animator21();
            animator31();
            animator41();

            animator12();
            animator22();
            animator32();

            // Second long-running animator
            AnimatorOptions option2 = new AnimatorOptions(
                    (long) (model.duration * 7 + model.duration / 5),
                    "ease", 0, AnimatorFill.NONE,
                    AnimatorDirection.NORMAL, 1, 0.0, 1.0);
            animator.reset(option2);
            animator.play();
        });
    }

    private void animator11() {
        angle31 = 0.0f;
        opacity31 = 0.0;
        angle41 = 0.0f;
        opacity41 = 0.0;

        AnimateParam param = new AnimateParam(
                model.duration, 0, Curve.EASE_IN, 1, PlayMode.NORMAL,
                () -> {
                    opacity11 = 0.0;
                    opacity12 = 1.0;
                    angle11 = 0.0f;
                });
