                () -> {
                    angle12 = 0.0f;
                    opacity12 = 0.0;
                    angle11 = 0.0f;
                    opacity11 = 0.0;
                });
        animateTo(param, () -> {
            angle12 = 180.0f;
            opacity12 = 0.0;
        });
    }

    private void animator21() {
        AnimateParam param = new AnimateParam(
                model.duration, (long) (model.duration * 1), Curve.EASE_IN, 1, PlayMode.NORMAL,
                () -> {
