            animatorTimer = new Timer(16, e -> {
                long now = System.currentTimeMillis();
                double elapsed = (now - startTime) / 1000.0;
                animationProgress = 0.0;

                Iterator<AnimationTask> it = pendingAnimations.iterator();
                while (it.hasNext()) {
                    AnimationTask task = it.next();
                    if (elapsed >= task.param.delay / 1000.0) {
                        double t = Math.min(1.0, (elapsed - task.param.delay / 1000.0) / (task.param.duration / 1000.0));
                        double eased = task.param.curve.apply(t);
                        // Linear interpolation not implemented here — for brevity, just call at end
