                            task.updateBlock.run();
                            if (task.param.onFinish != null) {
                                task.param.onFinish.run();
                            }
                            it.remove();
                        }
                    }
                }

                if (pendingAnimations.isEmpty()) {
                    isAnimating = false;
                    animatorTimer.stop();
                } else {
                    repaint();
                }
            });
        }
        animatorTimer.start();
    }

