    private void drawFace(Graphics2D g2d, double x1, double y1, double x2, double y2,
                          float angle, double opacity, String label) {
        AffineTransform orig = g2d.getTransform();
        Composite origComp = g2d.getComposite();

        // Rotate around center of face
        double cx = (x1 + x2) / 2.0;
        double cy = (y1 + y2) / 2.0;
        g2d.rotate(Math.toRadians(angle), cx, cy);

        // Apply opacity
        g2d.setComposite(AlphaComposite.getInstance(AlphaComposite.SRC_OVER, (float) opacity));

        // Draw rectangle
        g2d.setColor(model.color);
        g2d.fill(new Rectangle2D.Double(x1, y1, x2 - x1, y2 - y1));
        g2d.setStroke(new BasicStroke(5.0f));
        g2d.draw(new Rectangle2D.Double(x1, y1, x2 - x1, y2 - y1));

        g2d.setTransform(orig);
        g2d.setComposite(origComp);
    }

