            this.duration = duration;
            this.easing = easing;
            this.delay = delay;
            this.fill = fill;
            this.direction = direction;
            this.iterations = iterations;
            this.begin = begin;
            this.end = end;
        }
    }

    static class AnimatorResult {
        private AnimatorOptions options;
        private Runnable onFinish;

        AnimatorResult(AnimatorOptions options) {
            this.options = options;
        }

        void play() {
