    enum PlayMode { NORMAL }

    static class AnimateParam {
        long duration;
        long delay;
        Curve curve;
        int iterations;
        PlayMode playMode;
        Runnable onFinish;

        AnimateParam(long duration, long delay, Curve curve, int iterations,
