            this.curve = curve;
            this.iterations = iterations;
            this.playMode = playMode;
            this.onFinish = onFinish;
        }
    }

    enum Curve {
        EASE_IN {
            @Override
            double apply(double t) {
                return t * t;
            }
        };

        abstract double apply(double t);
    }

    static class AnimationTask {
        AnimateParam param;
        Runnable updateBlock;

        AnimationTask(AnimateParam param, Runnable updateBlock) {
            this.param = param;
