class InTableBody extends HtmlTreeBuilderState {
    @Override
    public String toString() {
        return "InTableBody";
    }

    @Override
    protected boolean process(Token tk, HtmlTreeBuilder builder) {
        switch (tk.typ) {
            case StartTagType:
                StartTag startTag = tk.asStartTag();
                String name = startTag.normalName();
                if ("tr".equals(name)) {
                    builder.clearStackToTableBodyContext();
                    builder.insert(startTag);
                    builder.transition(InRow);
                } else if (Constants.InCellNames.contains(name)) {
                    builder.error(this);
                    builder.processStartTag("tr");
                    return builder.process(startTag);
                } else if (Constants.InTableBodyExit.contains(name)) {
                    return exitTableBody(tk, builder);
                } else {
                    return anythingElse(tk, builder);
                }
                break;
            case EndTagType:
                EndTag endTag = tk.asEndTag();
                String endName = endTag.normalName();
                if (Constants.InTableEndIgnore.contains(endName)) {
                    if (!builder.inTableScope(endName)) {
                        builder.error(this);
                        return false;
                    } else {
                        builder.clearStackToTableBodyContext();
                        builder.pop();
                        builder.transition(InTable);
                    }
                } else if ("table".equals(endName)) {
                    return exitTableBody(tk, builder);
                } else if (Constants.InTableBodyEndIgnore.contains(endName)) {
                    builder.error(this);
                    return false;
                } else {
                    return anythingElse(tk, builder);
                }
                break;
            default:
                return anythingElse(tk, builder);
        }
        return true;
    }

    private boolean exitTableBody(Token tk, HtmlTreeBuilder builder) {
        if (!builder.inTableScope("tbody")) {
            if (!builder.inTableScope("thead")) {
                if (!builder.inScope("tfoot")) {
                    // frag case
                    builder.error(this);
                    return false;
                }
            }
        }
        builder.clearStackToTableBodyContext();
        // tbody, tfoot, thead
        builder.processEndTag(builder.currentElement().normalName());
        return builder.process(tk);
    }

    private boolean anythingElse(Token tk, HtmlTreeBuilder builder) {
        return builder.process(tk, InTable);
    }
}

