    @Override
    protected void read(Tokeniser tker, CharacterReader r) {
        char c = r.consume();
        switch (c) {
            case '\'':
                tker.transition(AfterDoctypeSystemIdentifier.INSTANCE);
                break;
            case '\u0000': // nullChar
                tker.error(this);
                tker.doctypePending.systemIdentifier.append('\uFFFD'); // replacementChar
                break;
            case '>':
                tker.error(this);
                tker.doctypePending.forceQuirks = true;
                tker.emitDoctypePending();
                tker.transition(Data.INSTANCE);
                break;
            case CharacterReader.EOF:
                tker.eofError(this);
                tker.doctypePending.forceQuirks = true;
                tker.emitDoctypePending();
                tker.transition(Data.INSTANCE);
                break;
            default:
                tker.doctypePending.systemIdentifier.append(c);
                break;
        }
    }
}

