import java.lang.Math;
import java.util.Arrays;

public class MathUtils {

    /**
     * Softmax函数
     */
    public static double[] softmax(double[] x) {
        int n = x.length;
        double[] result = new double[n];

        // 找最大值（数值稳定性）
        double maxVal = x[0];
        for (int i = 1; i < n; i++) {
            if (x[i] > maxVal) {
                maxVal = x[i];
            }
        }

        double sumExp = 0.0;
        for (int i = 0; i < n; i++) {
            result[i] = Math.exp(x[i] - maxVal);
            sumExp += result[i];
        }

        for (int i = 0; i < n; i++) {
            result[i] /= sumExp;
        }

        return result;
    }

    /**
     * Sigmoid函数
     */
    public static double sigmoid(double x) {
        if (x >= 0.0) {
            return 1.0 / (1.0 + Math.exp(-x));
        } else {
            double expX = Math.exp(x);
            return expX / (1.0 + expX);
        }
    }

    /**
     * Log-sum-exp（数值稳定）
     */
    public static double logSumExp(double[] x) {
        int n = x.length;
        double maxVal = x[0];
        for (int i = 1; i < n; i++) {
            if (x[i] > maxVal) {
                maxVal = x[i];
            }
        }
        double sumExp = 0.0;
        for (double xi : x) {
            sumExp += Math.exp(xi - maxVal);
        }
        return maxVal + Math.log(sumExp);
    }

    /**
     * 计算对数损失
     */
    public static double logLoss(double yTrue, double yPred) {
        final double eps = 1e-15;
        double p = Math.max(eps, Math.min(1.0 - eps, yPred));
        return -(yTrue * Math.log(p) + (1.0 - yTrue) * Math.log(1.0 - p));
    }

    /**
     * 数值求导（中心差分）
     */
    public static double numericalGradient(java.util.function.DoubleUnaryOperator f, double x, double h) {
        return (f.applyAsDouble(x + h) - f.applyAsDouble(x - h)) / (2.0 * h);
    }

    /**
     * 数值求导（中心差分），默认 h = 1e-5
     */
    public static double numericalGradient(java.util.function.DoubleUnaryOperator f, double x) {
        return numericalGradient(f, x, 1e-5);
    }

    /**
     * 裁剪值到指定范围
     */
    public static double clip(double x, double minVal, double maxVal) {
        return Math.max(minVal, Math.min(maxVal, x));
    }

    /**
     * 裁剪数组
     */
    public static double[] clipArray(double[] x, double minVal, double maxVal) {
        int n = x.length;
        double[] result = new double[n];
        for (int i = 0; i < n; i++) {
            result[i] = clip(x[i], minVal, maxVal);
        }
        return result;
    }

    /**
     * 计算百分位数
     */
    public static double percentile(double[] x, double p) {
        int n = x.length;
        if (n == 0) {
            throw new IllegalArgumentException("Array must not be empty");
        }

        // 排序（浅拷贝后排序）
        double[] sorted = Arrays.copyOf(x, n);
        Arrays.sort(sorted);

        double idx = (p / 100.0) * (n - 1);
        int lower = (int) Math.floor(idx);
        int upper = Math.min(lower + 1, n - 1);
        double frac = idx - lower;

        return sorted[lower] * (1.0 - frac) + sorted[upper] * frac;
    }

    /**
     * 计算四分位距（IQR）
     */
    public static double iqr(double[] x) {
        return percentile(x, 75.0) - percentile(x, 25.0);
    }

    /**
     * Z-score标准化
     */
    public static double[] zscore(double[] x) {
        int n = x.length;
        if (n == 0) {
            return new double[0];
        }

        double mean = 0.0;
        for (double xi : x) {
            mean += xi;
        }
        mean /= n;

        double variance = 0.0;
        for (double xi : x) {
            double diff = xi - mean;
            variance += diff * diff;
        }
        variance /= n;
        double std = Math.sqrt(variance);

        double[] result = new double[n];
        if (std > 0.0) {
            for (int i = 0; i < n; i++) {
                result[i] = (x[i] - mean) / std;
            }
        }

        return result;
    }
}

