public class MathUtils {
    /**
     * Softmax函数
     */
    public static func softmax(x: Array<Float64>): Array<Float64> {
        let n = x.size
        var result = Array<Float64>(n, repeat: 0.0)

        // 找最大值（数值稳定性）
        var maxVal = x[0]
        for (i in 1..n) {
            if (x[i] > maxVal) {
                maxVal = x[i]
            }
        }

        var sumExp = 0.0
        for (i in 0..n) {
            result[i] = exp(x[i] - maxVal)
            sumExp += result[i]
        }

        for (i in 0..n) {
            result[i] /= sumExp
        }

        return result
    }

    /**
     * Sigmoid函数
     */
    public static func sigmoid(x: Float64): Float64 {
        if (x >= 0.0) {
            return 1.0 / (1.0 + exp(-x))
        } else {
            let expX = exp(x)
            return expX / (1.0 + expX)
        }
    }

    /**
     * Log-sum-exp（数值稳定）
     */
    public static func logSumExp(x: Array<Float64>): Float64 {
        var maxVal = x[0]
        for (i in 1..x.size) {
            if (x[i] > maxVal) {
                maxVal = x[i]
            }
        }
        var sumExp = 0.0
        for (xi in x) {
            sumExp += exp(xi - maxVal)
        }
        return maxVal + log(sumExp)
    }

    /**
     * 计算对数损失
     */
    public static func logLoss(yTrue: Float64, yPred: Float64): Float64 {
        let eps = 1e-15
        let p = max(min(yPred, 1.0 - eps), eps)
        return -(yTrue * log(p) + (1.0 - yTrue) * log(1.0 - p))
    }

    /**
     * 数值求导（中心差分）
     */
    public static func numericalGradient(f: (Float64) -> Float64, x: Float64,
                                          h!: Float64 = 1e-5): Float64 {
        return (f(x + h) - f(x - h)) / (2.0 * h)
    }

    /**
     * 裁剪值到指定范围
     */
    public static func clip(x: Float64, minVal: Float64, maxVal: Float64): Float64 {
        return max(minVal, min(maxVal, x))
    }

    /**
     * 裁剪数组
     */
    public static func clipArray(x: Array<Float64>, minVal: Float64, maxVal: Float64): Array<Float64> {
        var result = Array<Float64>(x.size, repeat: 0.0)
        for (i in 0..x.size) {
            result[i] = clip(x[i], minVal, maxVal)
        }
        return result
    }

    /**
     * 计算百分位数
     */
    public static func percentile(x: Array<Float64>, p: Float64): Float64 {
        let n = x.size

        // 排序
        var sorted = Array<Float64>(n, repeat: 0.0)
        for (i in 0..n) {
            sorted[i] = x[i]
        }

        for (i in 0..n) {
            for (j in 0..(n - i - 1)) {
                if (sorted[j] > sorted[j + 1]) {
                    let temp = sorted[j]
                    sorted[j] = sorted[j + 1]
                    sorted[j + 1] = temp
                }
            }
        }

        let idx = (p / 100.0) * Float64(n - 1)
        let lower = Int64(idx)
        let upper = min(lower + 1, n - 1)
        let frac = idx - Float64(lower)

        return sorted[lower] * (1.0 - frac) + sorted[upper] * frac
    }

    /**
     * 计算四分位距（IQR）
     */
    public static func iqr(x: Array<Float64>): Float64 {
        return percentile(x, 75.0) - percentile(x, 25.0)
    }

    /**
     * Z-score标准化
     */
    public static func zscore(x: Array<Float64>): Array<Float64> {
        let n = x.size

        var mean = 0.0
        for (xi in x) {
            mean += xi
        }
        mean /= Float64(n)

        var variance = 0.0
        for (xi in x) {
            let diff = xi - mean
            variance += diff * diff
        }
        variance /= Float64(n)
        let std = sqrt(variance)

        var result = Array<Float64>(n, repeat: 0.0)
        if (std > 0.0) {
            for (i in 0..n) {
                result[i] = (x[i] - mean) / std
            }
        }

        return result
    }
}

