public class NillableIntegerResponseBuilder implements ResponseBuilder<Long> {
    @Override
    public Long build(RedisMessage message) {
        if (message instanceof NullRedisMessage) {
            return null;
        }

        if (message instanceof IntegerRedisMessage) {
            return ((IntegerRedisMessage) message).getValue();
        } else if (message instanceof BulkStringRedisMessage) {
            BulkStringRedisMessage bulkMsg = (BulkStringRedisMessage) message;
            if (bulkMsg.isNull()) {
                return null;
            } else {
                throw new RedisException("Incompatible type, null/nil BULK_STRINGS is not the expected type");
            }
        } else if (message instanceof ErrorRedisMessage) {
            throw new RedisException(((ErrorRedisMessage) message).getValue());
        }

        throw new RedisException("Unsupported message type: " + message.getType());
    }
}

