public func fLogSumExp(s: Array<Float64>): Float64 {
    let fMaxVal = fMax(s)
    if (fMaxVal.isInf()) {
        return fMaxVal
    }
    var lse: Float64 = 0.0
    for (val in s) {
        lse += exp(val - fMaxVal)
    }
    return log(lse) + fMaxVal
}

