public IMqttToken connect(MqttConnectOptions options, Object userContext, IMqttActionListener callback) {
    String methodName = "connect";
    if (comms.isConnected()) {
        throw ExceptionHelper.createMqttException(MqttException.REASON_CODE_CLIENT_CONNECTED);
    }
    if (comms.isConnecting()) {
        throw new MqttException(MqttException.REASON_CODE_CONNECT_IN_PROGRESS);
    }
    if (comms.isDisconnecting()) {
        throw new MqttException(MqttException.REASON_CODE_CLIENT_DISCONNECTING);
    }
    if (comms.isClosed()) {
        throw new MqttException(MqttException.REASON_CODE_CLIENT_CLOSED);
    }
    this.connOpts = options;
    this.userContext = userContext;
    boolean automaticReconnect = options.isAutomaticReconnect();

    // @TRACE 103=cleanSession={0} connectionTimeout={1} TimekeepAlive={2}
    // userName={3} password={4} will={5} userContext={6} callback={7}
    log.trace(
        CLASS_NAME,
        methodName,
        "103",
        new Object[]{
            options.isCleanSession(),
            options.getConnectionTimeout(),
            options.getKeepAliveInterval(),
            options.getUserName(),
            toString(options.getPassword(), true),
            options.getWillMessage(),
            toString(userContext, userContext == null),
            toString(callback, callback == null, "IMqttActionListener")
        }
    );

    comms.setNetworkModules(createNetworkModules(serverURI, options));
    comms.setReconnectCallback(new MqttReconnectCallback(this, automaticReconnect));

    // Insert our own callback to iterate through the URIs till the connect succeeds
    MqttToken userToken = new MqttToken(getClientId());
    ConnectActionListener connectActionListener = new ConnectActionListener(
        this,
        persistence,
        comms,
        options,
        userToken,
        userContext,
        callback,
        reconnecting
    );
    userToken.setActionCallback(connectActionListener);
    userToken.setUserContext(this);

    // If we are using the MqttCallbackExtended, set it on the connectActionListener
    if (this.mqttCallback instanceof MqttCallbackExtended) {
        connectActionListener.setMqttCallbackExtended((MqttCallbackExtended) this.mqttCallback);
    }

    comms.setNetworkModuleIndex(0);
    connectActionListener.connect();

    return userToken;
}

