/**
 * JoyContext interface representing the context of an HTTP request/response in the Joy framework.
 */
public interface JoyContext extends Context {
    /**
     * 获取底层的 HTTP 上下文
     *
     * @return HTTP 上下文
     */
    HttpContext getHttpContext();

    /**
     * 获取引擎配置
     *
     * @return 引擎配置
     */
    JoyConfig getConfig();

    /**
     * 获取从请求 URL 中提取的路径参数
     *
     * @return 路径参数
     */
    Map<String, String> getParams();

    /**
     * 获取请求中的 cookies
     *
     * @return cookies
     */
    Map<String, String> getCookies();

    /**
     * 获取 HTTP 请求方法 (GET, POST 等)
     *
     * @return HTTP 请求方法
     */
    String getMethod();

    /**
     * 获取 HTTP 响应状态码
     *
     * @return HTTP 响应状态码
     */
    short getRespStatus();

    /**
     * 获取 HTTP 响应体
     *
     * @return HTTP 响应体
     */
    String getRespBody();

    /**
     * 获取 HTTP 请求路径
     *
     * @return HTTP 请求路径
     */
    String getPath();

    /**
     * 获取完整的 HTTP 请求 URL
     *
     * @return 完整的 HTTP 请求 URL
     */
    URL getUrl();

    /**
     * 在上下文中设置参数
     *
     * @param key 参数键名
     * @param value 参数值
     */
    void setCtxParam(String key, Object value);

    /**
     * 从上下文中获取参数
     *
     * @param key 参数键名
     * @param <T> 参数类型
     * @return 参数值
     */
    <T> T getCtxParam(String key);

    /**
     * 从上下文中获取 URL 路径参数
     *
     * @param name 参数名
     * @return 参数值
     */
    String getParam(String name);

    /**
     * 向上下文中添加 URL 路径参数
     *
     * @param name 参数名
     * @param value 参数值
     */
    void addParam(String name, String value);

    /**
     * 从上下文中获取 URL 查询参数
     *
     * @param name 参数名
     * @return 参数值
     */
    String getQuery(String name);

    /**
     * 从上下文中获取 URL 查询参数（带默认值）
     *
     * @param name 参数名
     * @param defaultValue 如果参数不存在时的默认值
     * @return 参数值
     */
    String getQuery(String name, String defaultValue);

    /**
     * 从上下文中获取 URL 查询参数的所有值
     *
     * @param name 参数名
     * @return 参数值列表
     */
    List<String> getQueryList(String name);

    /**
     * 从上下文中获取 POST form 参数
     *
     * @param name 参数名
     * @return 参数值
     */
    String getPostForm(String name);

    /**
     * 从上下文中获取 POST form 参数（带默认值）
     *
     * @param name 参数名
     * @param defaultValue 如果参数不存在时的默认值
     * @return 参数值
     */
    String getPostForm(String name, String defaultValue);

    /**
     * 从上下文中获取 POST form 参数的所有值
     *
     * @param name 参数名
     * @return 参数值列表
     */
    List<String> getPostFormList(String name);

    /**
     * 从 POST form 或 URL 查询参数中获取参数
     *
     * @param name 参数名
     * @return 参数值
     */
    default String getForm(String name) {
        String result = getPostForm(name);
        return result != null ? result : getQuery(name);
    }

    /**
     * 从 POST 表单或 URL 查询参数中获取参数（带默认值）
     *
     * @param name 参数名
     * @param defaultValue 参数不存在时的默认值
     * @return 参数值
     */
    default String getForm(String name, String defaultValue) {
        String result = getForm(name);
        return result != null ? result : defaultValue;
    }

    /**
     * 从 POST 表单或 URL 查询参数中获取参数的所有值
     *
     * @param name 参数名
     * @return 参数值列表
     */
    default List<String> getFormList(String name) {
        List<String> res = getPostFormList(name);
        if (res.isEmpty()) {
            return getQueryList(name);
        }
        return res;
    }

    /**
     * 读取请求 JSON 体内容并反序列化为类型 T
     *
     * @param <T> 类型参数，必须实现 JsonDeserializable
     * @return 反序列化后的类型 T 对象，或 null（如果反序列化失败）
     */
    <T extends JsonDeserializable<T>> T readJson();

    /**
     * 读取请求体内容到字节数组
     *
     * @return 请求体作为字节数组
     */
    byte[] readRawData();

    /**
     * 读取请求体内容到字符串
     *
     * @return 请求体作为字符串
     */
    String readString();

    /**
     * 读取并绑定请求体内容到字符串
     *
     * @return 请求体作为字符串，或 null（如果无请求体）
     */
    String bindStringBody();

    /**
     * 读取并绑定查询参数到类型 T 的对象
     *
     * @param <T> 类型参数，必须实现 JoyBindable
     * @return 绑定后的类型 T 对象，或 null（如果无查询参数）
     */
    <T extends JoyBindable<T>> T bindQuery();

    /**
     * 读取并绑定 POST 表单参数到类型 T 的对象
     *
     * @param <T> 类型参数，必须实现 JoyBindable
     * @return 绑定后的类型 T 对象，或 null（如果无表单参数）
     */
    <T extends JoyBindable<T>> T bindPostForm();

    /**
     * 读取并绑定请求头参数到类型 T 的对象
     *
     * @param <T> 类型参数，必须实现 JoyBindable
     * @return 绑定后的类型 T 对象，或 null（如果无请求头参数）
     */
    <T extends JoyBindable<T>> T bindHeader();

    /**
     * 绑定请求 JSON 体内容到类型 T 的对象
     *
     * @param <T> 类型参数，必须实现 JsonDeserializable
     * @return 绑定后的类型 T 对象，或 null（如果绑定失败）
     */
    <T extends JsonDeserializable<T>> T bindJsonBody();

    /**
     * 使用序列化的 JSON 正文和状态码进行回复
     *
     * @param body T 类型对象
     * @param <T> 类型参数，必须实现 JsonSerializable
     * @return 当前 JoyContext 实例，便于链式调用
     */
    <T extends JsonSerializable> JoyContext json(T body);

    /**
     * 使用 JSON 正文和状态码进行回复
     *
     * @param body 字符串正文
     * @return 当前 JoyContext 实例，便于链式调用
     */
    JoyContext json(String body);

    /**
     * 使用指定内容类型和正文进行回复
     *
     * @param contentType 内容类型
     * @param body 字符串正文
     * @return 当前 JoyContext 实例，便于链式调用
     */
    JoyContext string(String contentType, String body);

    /**
     * 使用文本/纯文本正文和 OK(200) 状态码进行回复
     *
     * @param body 字符串正文
     * @return 当前 JoyContext 实例，便于链式调用
     */
    JoyContext string(String body);

    /**
     * 使用文本/纯文本正文和 OK(200) 状态码进行回复
     *
     * @param body 字符串正文
     * @return 当前 JoyContext 实例，便于链式调用
     */
    JoyContext text(String body);

    /**
     * 使用 HTML 正文和 OK(200) 状态码进行回复
     *
     * @param body HTML 正文字符串
     * @return 当前 JoyContext 实例，便于链式调用
     */
    JoyContext html(String body);

    /**
