     *
     * @return 真实客户端IP地址
     */
    String getClientIP();

    /**
     * 从连接中获取远程IP地址
     *
     * @return 远程IP地址
     */
    String getRemoteIP();

    /**
     * 获取请求体的内容类型
     *
     * @return 内容类型
     */
    String getContentType();

    /**
     * 获取指定请求头的第一个值
     *
     * @param name 请求头名称
     * @return 请求头值
     */
    String getHeader(String name);

    /**
     * 获取指定请求头的所有值
     *
     * @param name 请求头名称
     * @return 请求头值的集合
     */
    Collection<String> getHeaderList(String name);

    /**
