     *
     * @param status HTTP 状态码
     * @return 当前 JoyContext 实例，便于链式调用
     */
    JoyContext status(short status);

    /**
     * 返回 OK(200) 响应
     *
     * @return 当前 JoyContext 实例，便于链式调用
     */
    JoyContext ok();

    /**
     * 向响应添加头信息
     *
     * @param name 头名称
     * @param value 头值
     * @return 当前 JoyContext 实例，便于链式调用
     */
    JoyContext header(String name, String value);

    /**
     * 从请求读取 Cookie 值
     *
     * @param name Cookie 名称
     * @return Cookie 值
     */
    String getCookie(String name);

    /**
     * 将 Cookie 写入响应
     *
     * @param cookie Cookie 对象
     * @return 当前 JoyContext 实例，便于链式调用
     */
    JoyContext cookie(Cookie cookie);

    /**
     * 重定向到带有指定状态码的新 URL
     *
     * @param status HTTP 状态码
     * @param location 重定向位置 URL
     */
    void redirect(short status, String location);

    /**
     * 返回 404 Not Found 响应
     */
    void notFound();

    /**
     * 为流式响应创建分块写入器
     *
     * @return 分块写入器实例
     */
    JoyChunkedWriter chunkedWriter();

    /**
     * 创建一个服务器发送事件（SSE）发射器
     *
     * @return SSE 发射器实例
     */
    JoySseEmitter eventEmitter();

    /**
     * 从请求获取基础认证信息
     *
     * @return 包含用户名和密码的数组，若未提供或无效则返回 null
     */
    String[] basicAuth();

    /**
     * 按类型和名称获取请求参数
     *
     * @param typ 参数类型
     * @param name 参数名
     * @return 参数值
     */
    default String getRequestParam(String typ, String name) {
        switch (typ) {
            case "param":
            case "path":
                return getParam(name);
            case "query":
                return getQuery(name);
            case "form":
                return getForm(name);
            case "cookie":
                return getCookie(name);
            case "header":
                return getHeader(name);
            default:
                return null;
        }
    }

    /**
     * 按类型和名称获取请求参数
     *
     * @param typ 参数类型
     * @param name 参数名
     * @param defaultValue 如果参数不存在时的默认值
     * @return 参数值
     */
    default String getRequestParam(String typ, String name, String defaultValue) {
        switch (typ) {
            case "param":
            case "path":
                String paramVal = getParam(name);
                return paramVal != null ? paramVal : defaultValue;
            case "query":
                return getQuery(name, defaultValue);
            case "form":
                return getForm(name, defaultValue);
            case "cookie":
                String cookieVal = getCookie(name);
                return cookieVal != null ? cookieVal : defaultValue;
            case "header":
                String headerVal = getHeader(name);
                return headerVal != null ? headerVal : defaultValue;
            default:
                return defaultValue;
        }
    }
}

/**
 * Reverses the bits of a 32-bit unsigned integer for the specified bit length.
 *
 * @param code the input 32-bit unsigned integer (treated as int in Java)
 * @param len the number of least-significant bits to reverse
 * @return the bit-reversed value, with higher bits zeroed out
 */
private static int bitsReverse(int code, int len) {
    int result = 0;
    int val = code;
    int length = len;
    do {
        result |= val & 1;
        val >>= 1;
        result <<= 1;
        length -= 1;
    } while (length > 0);
    return result >> 1;
}

