import java.util.*;
import java.util.concurrent.atomic.AtomicBoolean;

public class MysqlQueryResult extends QueryResult {
    private final MysqlColumnInfo[] resultCount;
    private final long stmt; // CPointer<Unit> represented as long for JNI/native handle
    private final AtomicBoolean closed = new AtomicBoolean(false);
    private final Object[] resultSet;

    /**
     * 初始化 执行Select语句产生的结果
     *
     * @param stmt 初始化的stmt
     * @param resultCount 初始化的mysql列信息
     */
    public MysqlQueryResult(long stmt, MysqlColumnInfo[] resultCount) {
        this.stmt = stmt;
        this.resultCount = Objects.requireNonNull(resultCount);
        this.resultSet = new Object[resultCount.length];
        Arrays.fill(this.resultSet, Optional.empty());
    }

    /**
     * 返回结果集的列信息，比如列名，列类型，列长度，是否允许数据库Null值等（不支持）
     */
    @Override
    public ColumnInfo[] getColumnInfos() {
        ColumnInfo[] infos = new ColumnInfo[resultCount.length];
        for (int i = 0; i < resultCount.length; i++) {
            infos[i] = resultCount[i].getOrThrow();
        }
        return infos;
    }

    /**
     * 返回结果集的列信息，比如列名，列类型，列长度，是否允许数据库Null值等
     */
    public MysqlColumnInfo[] getMysqlColumnInfos() {
        return resultCount;
    }

    /**
     * 向后移动一行，必须先调用一次 next() 才能移动到第一行，第二次调用移动到第二行，依此类推。
     * 当返回 true 时，驱动会在结果集的当前行填入数据，当返回 false 时结束，且不会修改结果集当前行的内容。
     *
     * @return 存在下一行则返回true，否则返回false
     * @throws SqlException 传入参数错误或底层 MySQL 错误
     */
    @Override
    public boolean next() throws SqlException {
        // Simulate unsafe native memory allocation and binding
        long bindsCP = 0;
        try {
            bindsCP = malloc(8); // sizeof(void*) * 8? or just placeholder for malloc call
            if (bindsCP == 0) {
                throw new SqlException("Native malloc Failed.");
            }

            if (resultCount.length > 0) {
                bindsCP = init_bind(resultCount.length);
            }
            if (bindsCP == 0) {
                throw new SqlException("Init Bind Failed!");
            }

            for (int i = 0; i < resultCount.length; i++) {
                boolean isBool = cjTypeToMysqlTypeQuery(
                        resultCount[i].getTypeName(),
                        bindsCP,
                        i,
                        resultCount[i].getLength()
                );
