                                .add(header)
                                .add(
                                        Scroll.create()
                                                .add(
                                                        Column.create()
                                                                .add(mainContent)
                                                )
                                                .onScrollEdge(edge -> {
                                                    if (edge == Edge.TOP) {
                                                        isMoveTopEnd = true;
                                                    } else {
                                                        Hilog.info(0x0000, "SmartRefreshForGame", "edge is not top");
                                                    }
                                                })
                                                .onTouch(event -> {
                                                    double moveY = event.touches[0].y;
                                                    switch (event.eventType) {
                                                        case DOWN:
                                                            touchDownY = moveY;
                                                            break;
                                                        case MOVE:
                                                            double moveDistance = moveY - touchDownY;
                                                            modelGame.setDownY(moveDistance);
                                                            modelGame.setTouchMove(true);
                                                            if (marginTop != 0.0) {
                                                                if (moveDistance >= 0.0 && isMoveTopEnd) {
                                                                    marginTop = -(modelGame.getInitHeaderHeight() - moveDistance);
                                                                    modelGame.setRefreshState(1);
                                                                } else {
                                                                    isMoveTopEnd = false;
                                                                }
                                                            }
                                                            break;
                                                        case UP:
                                                            if (marginTop < 0.0) {
                                                                Timer upTimer = new Timer(true);
                                                                intervalId3 = Optional.of(upTimer);
                                                                upTimer.scheduleAtFixedRate(new TimerTask() {
                                                                    @Override
                                                                    public void run() {
                                                                        if (marginTop > -modelGame.getInitHeaderHeight()) {
                                                                            marginTop -= 20.0;
                                                                        } else {
                                                                            marginTop = -modelGame.getInitHeaderHeight();
                                                                            modelGame.setRefreshState(0);
                                                                            upTimer.cancel();
                                                                            intervalId3 = Optional.empty();
                                                                        }
                                                                    }
                                                                }, 0, 1);
                                                            } else {
                                                                modelGame.setTouchMove(false);
                                                                // 结束后是true，游戏页面没有收回去
                                                                if (modelGame.getNotifyFinish() == 1) {
                                                                    finishRefreshFunction();
                                                                }
                                                                if (marginTop >= 0.0) {
                                                                    Timer downTimer = new Timer(true);
                                                                    intervalId2 = Optional.of(downTimer);
                                                                    downTimer.scheduleAtFixedRate(new TimerTask() {
                                                                        @Override
                                                                        public void run() {
                                                                            if (marginTop > 0.0) {
                                                                                marginTop -= 20.0;
                                                                            } else {
                                                                                marginTop = 0.0;
                                                                                modelGame.setRefreshState(2);
                                                                                if (modelGame.getNotifyFinish() == 0) {
                                                                                    modelGame.getRefreshCallback().run();
                                                                                }
                                                                                downTimer.cancel();
                                                                                intervalId2 = Optional.empty();
                                                                            }
                                                                        }
                                                                    }, 0, 1);
                                                                }
                                                            }
                                                            break;
                                                        default:
                                                            if (intervalId.isPresent()) {
                                                                // "TouchType is Unknown" — log or ignore
                                                            }
                                                            break;
                                                    }
                                                })
                                )
                )
                .margin(0, marginTop, 0, 0) // top margin only
                .widthPercent(100)
                .heightPercent(100);
    }
}

