    @Override
    public StreamPendingSummary build(RedisMessage message) {
        if (message instanceof ArraysRedisMessage arraysMessage) {
            java.util.Optional<java.util.List<RedisMessage>> childrenOpt = arraysMessage.getValue();
            if (childrenOpt.isPresent()) {
                java.util.List<RedisMessage> children = childrenOpt.get();
                if (children.size() != 4) {
                    throw new RedisException(
                        "Incompatible type, wrong size of ArraysRedisMessage, expected 4 but " + children.size()
                    );
                }

                RedisMessage totalMessage = ResponseBuilderHelper.getRedisMessageOrThrow(
                    children.get(0), RedisMessageType.INTEGERS
                );

                RedisMessage minIdMessage = ResponseBuilderHelper.getRedisMessageOrThrow(
                    children.get(1), RedisMessageType.BULK_STRINGS
                );

                RedisMessage maxIdMessage = ResponseBuilderHelper.getRedisMessageOrThrow(
                    children.get(2), RedisMessageType.BULK_STRINGS
