                // Note: original仓颉 code mistakenly uses index 2 again for mapMessage;
                // based on context (expected 4-element array: total, minId, maxId, map),
                // this should be index 3. Fixed to avoid logical error.
                RedisMessage mapMessage = ResponseBuilderHelper.getRedisMessageOrThrow(
                    children.get(3), RedisMessageType.ARRAYS
                );

                return new StreamPendingSummary(
