import android.util.DisplayMetrics;
import android.view.View;
import android.view.ViewGroup;
import android.view.WindowManager;
import android.widget.FrameLayout;
import androidx.annotation.NonNull;
import androidx.core.view.ViewCompat;
import androidx.core.view.animation.PathInterpolatorCompat;
import java.util.Arrays;
import java.util.function.BiConsumer;
import java.util.function.Consumer;

public class SwipeLayoutLayDownFullGrid extends FrameLayout {

    // Linked properties (typically bound from parent UI framework)
    private String itemContent = "";
    private long itemId = 0L;

    // Internal state
    private int mDuration = 200;
    private double mWidth = 100.0; // percent
    private double mHeight = 90.0; // dp
    private double sX = 0.0;
    private double sY = 0.0;
    private double bottomViewTopH = 100.0;
    private double bottomViewBottomH = 100.0;
    private double bottomViewRightW = 320.0;
    private double bottomViewLeftW = 120.0;

    // Builder parameters (callbacks)
    private final BiConsumer<String, Long> surfaceView;
    private final Consumer<Long> bottomViewRight;

    // Stateful UI variables
    private double offsetY = 0.0;
    private double offsetX = 0.0;

    // Slide controls
    private boolean leftSlideEnable = true;
    private boolean rightSlideEnable = true;
    private double previousX = 0.0;
    private final boolean[] enableSlide = {false, true, true, false}; // index 0: left, 2: right

    // UI components (to be lazily initialized or injected)
    private View surfaceContainer;
    private View bottomRightContainer;

    public SwipeLayoutLayDownFullGrid(@NonNull android.content.Context context,
                                       BiConsumer<String, Long> surfaceView,
                                       Consumer<Long> bottomViewRight) {
        super(context);
        this.surfaceView = surfaceView;
        this.bottomViewRight = bottomViewRight;
        init();
    }

    private void init() {
        setLayoutParams(new LayoutParams(LayoutParams.MATCH_PARENT, LayoutParams.WRAP_CONTENT));
    }

    @Override
    protected void onAttachedToWindow() {
        super.onAttachedToWindow();
        aboutToAppear();
    }

    protected void aboutToAppear() {
        DisplayMetrics displayMetrics = new DisplayMetrics();
        ((WindowManager) getContext().getSystemService(android.content.Context.WINDOW_SERVICE))
                .getDefaultDisplay().getMetrics(displayMetrics);
        double screenW = displayMetrics.widthPixels; // px

        // Convert px to vp (assuming 1:1 mapping for simplicity — real px2vp would use density)
        // In real app: screenW = px2vp(screenW); but here we treat as raw pixels for layout logic.
        // Clamp mWidth
        if (mWidth > 100.0) {
            mWidth = 100.0;
        }

        // Clamp bottomViewRightW to screen width and non-negative
        if (bottomViewRightW >= screenW) {
            bottomViewRightW = screenW;
        } else if (bottomViewRightW < 0.0) {
            bottomViewRightW = 0.0;
        }
    }

    @Override
    protected void onMeasure(int widthMeasureSpec, int heightMeasureSpec) {
        // Measure children with dynamic width/height based on mWidth (percent), mHeight (dp)
        int widthMode = MeasureSpec.getMode(widthMeasureSpec);
        int widthSize = MeasureSpec.getSize(widthMeasureSpec);
        int heightMode = MeasureSpec.getMode(heightMeasureSpec);
        int heightSize = MeasureSpec.getSize(heightMeasureSpec);

        int measuredWidth;
        int measuredHeight;

        if (widthMode == MeasureSpec.EXACTLY) {
            measuredWidth = widthSize;
        } else {
            measuredWidth = (int) (widthSize * (mWidth / 100.0));
        }

        if (heightMode == MeasureSpec.EXACTLY) {
            measuredHeight = heightSize;
        } else {
            measuredHeight = (int) mHeight; // assume mHeight is in dp
        }

        setMeasuredDimension(measuredWidth, measuredHeight);
    }

    @Override
    protected void onLayout(boolean changed, int left, int top, int right, int bottom) {
        int width = right - left;
        int height = bottom - top;

        // Surface container (main content) — positioned with offsetX/offsetY offset
        if (surfaceContainer != null) {
            int surfaceLeft = (int) offsetX;
            int surfaceTop = (int) offsetY;
            int surfaceRight = surfaceLeft + width;
            int surfaceBottom = surfaceTop + height;
            surfaceContainer.layout(surfaceLeft, surfaceTop, surfaceRight, surfaceBottom);
        }

        // Bottom right view — fixed size, anchored right
        if (bottomRightContainer != null) {
            int brw = (int) bottomViewRightW;
            int brh = (int) mHeight;
            int brLeft = width - brw;
            int brTop = 0;
            int brRight = width;
            int brBottom = brh;
            bottomRightContainer.layout(brLeft, brTop, brRight, brBottom);
        }
    }

    // Simulated touch handling logic (for demonstration — real impl uses View#setOnTouchListener)
    public void setupTouchHandling() {
        // This is a conceptual translation — actual Android touch handling requires View listeners.

        // Surface container touch handler (simulated)
        if (surfaceContainer != null) {
            surfaceContainer.setOnTouchListener((v, event) -> {
                float x = event.getRawX();
                float y = event.getRawY();

                switch (event.getAction()) {
                    case android.view.MotionEvent.ACTION_DOWN:
                        sX = x;
                        sY = y;
                        break;

                    case android.view.MotionEvent.ACTION_MOVE:
                        double moveX = x - sX;
                        double moveY = y - sY;

                        // Horizontal swipe detection
                        if (Math.abs(moveX) > Math.abs(moveY)) {
                            if (offsetY == 0.0) {
                                if (moveX < 0.0 && moveY < 30.0 && moveY > -30.0) {
                                    // Left swipe
                                    if (offsetX > 0.0) {
                                        rightSlideEnable = false;
                                        if (-moveX < bottomViewLeftW) {
                                            offsetX = moveX + bottomViewLeftW;
                                        } else {
                                            offsetX = 0.0;
                                        }
                                        invalidate();
                                        return true;
                                    }

                                    if (!enableSlide[2]) {
                                        return true;
                                    }

                                    if (rightSlideEnable) {
                                        if (offsetX <= 0.0 && offsetX > -bottomViewRightW && -moveX <= bottomViewRightW) {
                                            offsetX = moveX;
                                        } else if (-moveX > bottomViewRightW) {
                                            offsetX = -bottomViewRightW;
                                            sX = x;
                                            leftSlideEnable = false;
                                        }
                                    }
                                } else if (moveX > 0.0 && moveY < 30.0 && moveY > -30.0) {
                                    // Right swipe
                                    if (offsetX < 0.0) {
                                        leftSlideEnable = false;
                                        if (moveX <= bottomViewRightW) {
                                            offsetX = moveX - bottomViewRightW;
                                            invalidate();
                                            return true;
                                        } else {
                                            offsetX = 0.0;
                                        }
                                    }

                                    if (!enableSlide[0]) {
                                        return true;
                                    }

                                    if (leftSlideEnable) {
                                        if (offsetX >= 0.0 && offsetX < bottomViewLeftW && moveX <= bottomViewLeftW) {
                                            offsetX = moveX;
                                        } else if (moveX > bottomViewRightW) {
                                            offsetX = bottomViewLeftW;
                                            sX = x;
                                            rightSlideEnable = false;
                                        }
                                    }
                                }
                            }
                        }
                        previousX = x;
                        invalidate();
                        break;

                    case android.view.MotionEvent.ACTION_UP:
                        moveX = x - sX;
                        moveY = y - sY;
                        animateTo(moveX, moveY);
                        break;
                }
                return true;
            });
        }

        // Bottom right container touch handler
        if (bottomRightContainer != null) {
            bottomRightContainer.setOnTouchListener((v, event) -> {
                float x = event.getRawX();
                float y = event.getRawY();

                switch (event.getAction()) {
                    case android.view.MotionEvent.ACTION_DOWN:
                        sX = x;
                        sY = y;
                        break;

                    case android.view.MotionEvent.ACTION_MOVE:
                        double moveX = x - sX;
                        double moveY = y - sY;

                        if (Math.abs(moveX) > Math.abs(moveY)) {
                            if (offsetY == 0.0) {
                                if (moveX > 0.0 && moveY < 30.0 && moveY > -30.0) {
                                    if (offsetX < 0.0) {
                                        leftSlideEnable = false;
                                        if (moveX <= bottomViewRightW) {
                                            offsetX = moveX - bottomViewRightW;
                                            invalidate();
                                            return true;
                                        } else {
                                            offsetX = 0.0;
                                        }
                                    }
                                }
                            }
                        }
                        previousX = x;
                        invalidate();
                        break;

                    case android.view.MotionEvent.ACTION_UP:
                        moveX = x - sX;
                        animateToForBottomRight(moveX);
                        break;
                }
                return true;
            });
        }
    }

    private void animateTo(double moveX, double moveY) {
        // Simulate animation using ViewCompat.animate()
        final long duration = mDuration;
        final Runnable onFinish = () -> {
            rightSlideEnable = true;
            leftSlideEnable = true;
        };

        if (offsetX > 0.0 && leftSlideEnable) {
            if (moveX >= 15.0) {
                offsetX = bottomViewLeftW;
            } else if (moveX > 0.0) {
                offsetX = 0.0;
            } else if (moveX < -15.0) {
                offsetX = 0.0;
            } else if (moveX < 0.0) {
                offsetX = bottomViewLeftW;
            }
        } else if (offsetX < 0.0 && rightSlideEnable) {
            if (moveX >= 15.0) {
                offsetX = 0.0;
            } else if (moveX > 0.0) {
                offsetX = -bottomViewRightW;
            } else if (moveX <= -15.0) {
                offsetX = -bottomViewRightW;
            } else if (moveX < 0.0) {
                offsetX = 0.0;
            }
        }

        // Trigger layout update
        post(() -> {
            invalidate();
            onFinish.run();
        });
    }

    private void animateToForBottomRight(double moveX) {
        final long duration = mDuration;
        final Runnable onFinish = () -> {
            rightSlideEnable = true;
            leftSlideEnable = true;
        };

        if (offsetX < 0.0 && rightSlideEnable) {
            if (moveX >= 40.0) {
                offsetX = 0.0;
            } else if (moveX > 0.0) {
                offsetX = -bottomViewRightW;
            } else if (moveX <= -40.0) {
                offsetX = -bottomViewRightW;
            } else if (moveX < 0.0) {
                offsetX = 0.0;
            }
        }

        post(() -> {
            invalidate();
            onFinish.run();
        });
    }

    // Public setters for linked properties (used by framework binding)
    public void setItemContent(String itemContent) {
        this.itemContent = itemContent;
    }

    public void setItemId(long itemId) {
        this.itemId = itemId;
    }

    // Optional: expose state for external control
    public double getOffsetX() {
        return offsetX;
    }

    public void setOffsetX(double offsetX) {
        this.offsetX = offsetX;
        invalidate();
    }

    public double getOffsetY() {
        return offsetY;
    }

    public void setOffsetY(double offsetY) {
        this.offsetY = offsetY;
        invalidate();
    }

    // For framework integration: allow injection of child views
    public void setSurfaceContainer(View surfaceContainer) {
        this.surfaceContainer = surfaceContainer;
        if (surfaceContainer != null) {
            // Call surfaceView callback to populate it
            surfaceView.accept(itemContent, itemId);
        }
    }

    public void setBottomRightContainer(View bottomRightContainer) {
        this.bottomRightContainer = bottomRightContainer;
        if (bottomRightContainer != null) {
            // Call bottomViewRight callback
            bottomViewRight.accept(itemId);
        }
    }
}

