                                        if (this.offsetX > 0.0) {
                                            this.rightSlideEnable = false
                                            if (-moveX < this.bottomViewLeftW) {
                                                this.offsetX = moveX + this.bottomViewLeftW
                                            } else {
                                                this.offsetX = 0.0
                                            }
                                            return
                                        }

                                        if (!this.enableSlide[2]) {
                                            return
                                        }
                                        //当前移动距离小于右侧View的宽度，并且没有处于刚好拉出的状态
