     */
    <T extends JsonDeserializable<T>> T sendRequest(String method, JsonSerializable requestParams);

    /**
     * 发送 JSON-RPC 通知而不等待响应
     *
     * @param method 通知方法名称
     * @param params 通知参数
     */
    void sendNotification(String method, JsonSerializable params);

    /**
     * 发送 JSON-RPC 通知而不等待响应（无参数重载）
     *
     * @param method 通知方法名称
     */
    default void sendNotification(String method) {
        sendNotification(method, null);
    }

    /**
