public class TokenResponse {
    public static final String TOKEN_TYPE_BEARER = "Bearer";

    private static final String KEY_REQUEST = "request";
    private static final String KEY_EXPIRES_AT = "expires_at";
    private static final String KEY_TOKEN_TYPE = "token_type";
    private static final String KEY_ACCESS_TOKEN = "access_token";
    private static final String KEY_EXPIRES_IN = "expires_in";
    private static final String KEY_REFRESH_TOKEN = "refresh_token";
    private static final String KEY_ID_TOKEN = "id_token";
    private static final String KEY_SCOPE = "scope";
    private static final String KEY_ADDITIONAL_PARAMETERS = "additionalParameters";

    private static final List<String> PARAMS_ARRAY = Arrays.asList(
            KEY_TOKEN_TYPE,
            KEY_ACCESS_TOKEN,
            KEY_EXPIRES_IN,
            KEY_REFRESH_TOKEN,
            KEY_ID_TOKEN,
            KEY_SCOPE
    );
    private static final Set<String> BUILT_IN_PARAMS = new HashSet<>(PARAMS_ARRAY);

    private final TokenRequest request;
    private final String tokenType;
    private final String accessToken;
    private final long accessTokenExpirationTime; // Int64 maps to long in Java
    private final String idToken;
    private final String refreshToken;
    private final String scope;
    private final Map<String, String> additionalParameters;

    public TokenResponse(
            TokenRequest request,
            String tokenType,
            String accessToken,
            long accessTokenExpirationTime,
            String idToken,
            String refreshToken,
            String scope,
            Map<String, String> additionalParameters) {
        this.request = request;
        this.tokenType = tokenType;
        this.accessToken = accessToken;
        this.accessTokenExpirationTime = accessTokenExpirationTime;
        this.idToken = idToken;
        this.refreshToken = refreshToken;
        this.scope = scope;
        this.additionalParameters = (additionalParameters != null) ? new HashMap<>(additionalParameters) : new HashMap<>();
    }

    /**
     * 获取scope集合
     * @return scope集合
     */
    public Set<String> getScopeSet() {
        return AsciiStringListUtil.stringToSet(scope);
    }

    /**
     * 将对象序列化为JSON对象
     * @return JSON对象
     */
    public JsonObject jsonSerialize() {
        JsonObject json = new JsonObject();
        JsonUtil.put(json, KEY_REQUEST, request.jsonSerialize());
        JsonUtil.putIfNotNull(json, KEY_TOKEN_TYPE, tokenType);
        JsonUtil.putIfNotNull(json, KEY_ACCESS_TOKEN, accessToken);
        JsonUtil.putIfNotNull(json, KEY_EXPIRES_AT, accessTokenExpirationTime);
        JsonUtil.putIfNotNull(json, KEY_ID_TOKEN, idToken);
        JsonUtil.putIfNotNull(json, KEY_REFRESH_TOKEN, refreshToken);
        JsonUtil.putIfNotNull(json, KEY_SCOPE, scope);
        JsonUtil.put(json, KEY_ADDITIONAL_PARAMETERS,
                JsonUtil.mapToJsonObject(additionalParameters));
        return json;
    }

    /**
     * 将对象序列化为JSON字符串
     * @return JSON字符串
     */
    public String jsonSerializeString() {
        return jsonSerialize().toString();
    }

    /**
     * 从JSON对象反序列化为TokenResponse object
     * @param json JSON对象
     * @return TokenResponse object
     * @throws IllegalArgumentException 当JSON中未提供token请求时抛出异常
     */
    public static TokenResponse jsonDeserialize(JsonObject json) {
        if (!json.containsKey(KEY_REQUEST)) {
            throw new IllegalArgumentException("token request not provided and not found in JSON");
        }

        TokenRequest request = TokenRequest.jsonDeserialize(
                json.get(KEY_REQUEST).getOrThrow().asObject());

        String tokenType = JsonUtil.getStringIfDefined(json, KEY_TOKEN_TYPE);
        String accessToken = JsonUtil.getStringIfDefined(json, KEY_ACCESS_TOKEN);
        Long expiresAt = JsonUtil.getInt64IfDefined(json, KEY_EXPIRES_AT);
        String idToken = JsonUtil.getStringIfDefined(json, KEY_ID_TOKEN);
        String refreshToken = JsonUtil.getStringIfDefined(json, KEY_REFRESH_TOKEN);
        String scope = JsonUtil.getStringIfDefined(json, KEY_SCOPE);
        Map<String, String> additionalParameters = JsonUtil.getStringMap(json, KEY_ADDITIONAL_PARAMETERS);

        return new TokenResponse(
                request,
                tokenType,
                accessToken,
                (expiresAt != null) ? expiresAt : 0L,
                idToken,
                refreshToken,
                scope,
                additionalParameters);
    }

    /**
     * 从JSON字符串反序列化为TokenResponse object
     * @param jsonStr JSON字符串
     * @return TokenResponse object
     * @throws NoneValueException 当JSON字符串为空时抛出异常
     */
    public static TokenResponse jsonDeserialize(String jsonStr) {
        if (jsonStr == null || jsonStr.trim().isEmpty()) {
            throw new NoneValueException("jsonStr cannot be null or empty");
        }
        JsonObject jsonObject = JsonValue.fromStr(jsonStr).asObject();
        return jsonDeserialize(jsonObject);
    }
}

