    // Construct the info message
    let paths = files |> map { param: ReadFileParam =>
            let start = param.startLine ?? 1
            let end = param.endLine.map { n => n.toString() } ?? "EOF"
            "${param.filePath} (${start}-${end})"
        } |> collectArray

