                int mHeight = avif.getHeight();
                mmWidth = mWidth;
                mmHeight = mHeight;

                byte[] colors = new byte[mWidth * mHeight * 4];
                boolean decoded = avif.nextFrameFFI(colors, mWidth, mHeight);
                if (!decoded) {
                    HiLog.error(LABEL, "nextFrameFFI failed");
                    avif.release();
                    return;
                }

                long endTime = System.nanoTime();
                long elapsedNs = endTime - startTime;
                HiLog.error(LABEL, "calcTime: startTime=%d, endTime=%d, sjc=%d", startTime, endTime, elapsedNs);

                Size size2 = new Size(mWidth, mHeight);
                InitializationOptions opts2 = new InitializationOptions.Builder()
                        .setEditable(true)
                        .setPixelFormat(PixelMapFormat.RGBA_8888)
                        .setSize(size2)
                        .build();

                PixelMap newPixelMap = createPixelMap(colors, opts2);
                // Update UI thread
                getUITaskDispatcher().asyncDispatch(() -> {
                    this.pixelMap = newPixelMap;
                    // Trigger UI refresh (e.g., invalidate Image component)
                });

                avif.release();

            } catch (Exception e) {
                HiLog.error(LABEL, "Exception in onTestSingleClick: %s", e.getMessage());
            }
        }, executorService);
    }

    public void onTestMultClick() {
        CompletableFuture.runAsync(() -> {
            try {
                byte[] imageData = getImageFromRawFile("a25.avif");
                if (imageData == null || imageData.length == 0) {
                    HiLog.error(LABEL, "Failed to load a25.avif");
                    return;
                }

                AvifDecoder avif = AvifDecoder.create(imageData);
                if (avif == null) {
                    HiLog.error(LABEL, "AvifDecoder.create failed for a25.avif");
                    return;
                }

                int mWidth = avif.getWidth();
                int mHeight = avif.getHeight();
                HiLog.error(LABEL, "colorvalueWH: mWidth=%d, mHeight=%d", mWidth, mHeight);
                mmWidth = mWidth;
                mmHeight = mHeight;

                long frameCount = avif.getFrameCount();
                ArrayList<Float> durationList = avif.getFrameDurations();
                if (durationList == null || durationList.size() == 0) {
                    HiLog.error(LABEL, "aviflog: 数据有误 — frame durations missing");
                    avif.release();
                    return;
                }
                if (durationList.size() != frameCount) {
                    HiLog.error(LABEL, "aviflog: 数据有误 — frame count mismatch");
                    avif.release();
                    return;
                }

                // Pre-decode all frames into pixelMapList (if not already done)
                if (pixelMapList.size() != frameCount) {
                    for (int k = 0; k < frameCount; k++) {
                        byte[] colors = new byte[mWidth * mHeight * 4];
                        boolean ok = avif.nthFrameFFI(k, colors, mWidth, mHeight);
                        if (!ok) continue;

                        Size size2 = new Size(mWidth, mHeight);
                        InitializationOptions opts2 = new InitializationOptions.Builder()
                                .setEditable(true)
                                .setPixelFormat(PixelMapFormat.RGBA_8888)
                                .setSize(size2)
                                .build();

                        PixelMap tempPixelMap = createPixelMap(colors, opts2);
                        pixelMapList.add(tempPixelMap);
                    }
                    avif.release(); // release after pre-decoding
                }

                // Now play loop
                while (isLoop && !Thread.currentThread().isInterrupted()) {
                    for (int k = 0; k < pixelMapList.size() && isLoop; k++) {
                        PixelMap frame = pixelMapList.get(k);
                        final float durationSec = durationList.get(k);
                        if (frame != null) {
                            getUITaskDispatcher().asyncDispatch(() -> {
                                this.pixelMap = frame;
                                // Notify UI to refresh image
                            });
                        }
                        try {
                            Thread.sleep((long) (durationSec * 1000)); // sec → ms
                        } catch (InterruptedException e) {
                            Thread.currentThread().interrupt();
                            break;
                        }
                    }
                }

            } catch (Exception e) {
                HiLog.error(LABEL, "Exception in onTestMultClick: %s", e.getMessage());
            }
        }, executorService);
    }

