    private byte[] getImageFromRawFile(String rawFileName) {
        try {
            Context context = getAbility().getApplicationContext();
            ResourceManager resourceManager = context.getResourceManager();
            RawFileEntry rawFileEntry = resourceManager.getRawFileEntry("resources/rawfile/" + rawFileName);
            if (rawFileEntry == null) {
