import java.util.Optional;

public abstract class TestExpectation<T> {
    private TestExpectation() {}

    public static final class Success<T> extends TestExpectation<T> {
        private final T value;

        public Success(T value) {
            this.value = value;
        }

        public T getValue() {
            return value;
        }
    }

    public static final class Timeout<T> extends TestExpectation<T> {}

    public static final class UnexpectedMessage<T> extends TestExpectation<T> {
        private final Message message;

        public UnexpectedMessage(Message message) {
            this.message = message;
        }

        public Message getMessage() {
            return message;
        }
    }

    public static final class Error<T> extends TestExpectation<T> {
        private final Exception exception;

        public Error(Exception exception) {
            this.exception = exception;
        }

        public Exception getException() {
            return exception;
        }
    }

    // Factory methods
    public static <T> TestExpectation<T> success(T value) {
        return new Success<>(value);
    }

    public static <T> TestExpectation<T> timeout() {
        return new Timeout<>();
    }

    public static <T> TestExpectation<T> unexpectedMessage(Message message) {
        return new UnexpectedMessage<>(message);
    }

    public static <T> TestExpectation<T> error(Exception exception) {
        return new Error<>(exception);
    }

    // Instance methods
    public boolean isSuccess() {
        return this instanceof Success;
    }

    public Optional<T> getValue() {
        if (this instanceof Success<?>) {
            @SuppressWarnings("unchecked")
            Success<T> success = (Success<T>) this;
            return Optional.of(success.getValue());
        }
        return Optional.empty();
    }

    @Override
    public String toString() {
        if (this instanceof Success<?>) {
            return "Success";
        } else if (this instanceof Timeout<?>) {
            return "Timeout";
        } else if (this instanceof UnexpectedMessage<?>) {
            UnexpectedMessage<?> um = (UnexpectedMessage<?>) this;
            return "UnexpectedMessage(" + um.getMessage().messageType() + ")";
        } else if (this instanceof Error<?>) {
            Error<?> err = (Error<?>) this;
            return "Error(" + err.getException().getMessage() + ")";
        }
        return super.toString();
    }
}

