import java.util.*;
import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.atomic.AtomicLong;
import java.util.concurrent.locks.ReentrantLock;

public class ActorRegistry {
    // 主要存储：路径 -> ActorRef
    private final Map<String, ActorRegistryEntry> pathToActor;

    // 反向索引：Actor路径字符串 -> 路径（简化实现，避免ActorRef作为键）
    private final Map<String, String> actorPathToPath;

    // 名称索引：名称 -> 路径集合（支持同名Actor）
    private final Map<String, Set<String>> nameToPath;

    // 父子关系索引
    private final Map<String, Set<String>> parentToChildren;
    private final Map<String, String> childToParent;

    // 统计信息
    private final AtomicLong totalActors;
    private final AtomicLong registrationCount;

    // 互斥锁
    private final ReentrantLock registryLock;

    public ActorRegistry() {
        this.pathToActor = new ConcurrentHashMap<>();
        this.actorPathToPath = new ConcurrentHashMap<>();
        this.nameToPath = new ConcurrentHashMap<>();
        this.parentToChildren = new ConcurrentHashMap<>();
        this.childToParent = new ConcurrentHashMap<>();
        this.totalActors = new AtomicLong(0);
        this.registrationCount = new AtomicLong(0);
        this.registryLock = new ReentrantLock();
    }

    /**
     * 注册Actor
     */
    public void register(ActorRef actorRef, Optional<String> parentPath) {
        String path = actorRef.path().toString();
        String name = extractActorName(path);
        long currentTime = getCurrentTimeNanos();

        // 检查是否已经注册
        if (pathToActor.containsKey(path)) {
            return; // 已经注册，忽略
        }

        // 创建注册条目
        ActorRegistryEntry entry = new ActorRegistryEntry(actorRef, currentTime, parentPath);

        // 主要存储
        pathToActor.put(path, entry);
        actorPathToPath.put(actorRef.path().toString(), path);

        // 名称索引
        nameToPath.computeIfAbsent(name, k -> ConcurrentHashMap.newKeySet()).add(path);

        // 父子关系
        parentPath.ifPresent(parent -> {
            childToParent.put(path, parent);
            parentToChildren.computeIfAbsent(parent, k -> ConcurrentHashMap.newKeySet()).add(path);
        });

        // 更新统计
        totalActors.incrementAndGet();
        registrationCount.incrementAndGet();
    }

    /**
     * 注销Actor
     */
    public void unregister(ActorRef actorRef) {
        String path = actorPathToPath.get(actorRef.path().toString());
        if (path != null) {
            unregisterByPath(path);
        }
        // Actor未注册，忽略
    }

    /**
     * 通过路径注销Actor
     */
    public void unregisterByPath(String path) {
        registryLock.lock();
        try {
            ActorRegistryEntry entry = pathToActor.get(path);
            if (entry != null) {
                ActorRef actorRef = entry.actorRef();
                String name = extractActorName(path);

                // 移除主要存储
                pathToActor.remove(path);
                actorPathToPath.remove(actorRef.path().toString());

                // 移除名称索引
                Set<String> paths = nameToPath.get(name);
                if (paths != null) {
                    paths.remove(path);
                    if (paths.isEmpty()) {
                        nameToPath.remove(name);
                    }
                }

                // 移除父子关系
                String parent = childToParent.remove(path);
                if (parent != null) {
                    Set<String> children = parentToChildren.get(parent);
                    if (children != null) {
                        children.remove(path);
                        if (children.isEmpty()) {
                            parentToChildren.remove(parent);
                        }
                    }
                }

                // 递归注销所有子Actor
                Set<String> childrenOfPath = parentToChildren.remove(path);
                if (childrenOfPath != null) {
                    for (String childPath : childrenOfPath) {
                        unregisterByPath(childPath);
                    }
                }

                // 更新统计
                totalActors.decrementAndGet();
            }
        } finally {
            registryLock.unlock();
        }
    }

    /**
     * 通过路径查找Actor
     */
    public Optional<ActorRef> findByPath(String path) {
        registryLock.lock();
        try {
            ActorRegistryEntry entry = pathToActor.get(path);
            return (entry != null) ? Optional.of(entry.actorRef()) : Optional.empty();
        } finally {
            registryLock.unlock();
        }
    }

    /**
     * 通过名称查找Actor（返回第一个匹配的）
     */
    public Optional<ActorRef> findByName(String name) {
        registryLock.lock();
        try {
            Set<String> paths = nameToPath.get(name);
            if (paths != null && !paths.isEmpty()) {
                for (String path : paths) {
                    ActorRegistryEntry entry = pathToActor.get(path);
                    if (entry != null) {
                        return Optional.of(entry.actorRef());
                    }
                }
            }
            return Optional.empty();
        } finally {
            registryLock.unlock();
        }
    }

    /**
     * 通过名称查找所有Actor
     */
    public ActorRef[] findAllByName(String name) {
        List<ActorRef> result = new ArrayList<>();

        registryLock.lock();
        try {
            Set<String> paths = nameToPath.get(name);
            if (paths != null) {
                for (String path : paths) {
                    ActorRegistryEntry entry = pathToActor.get(path);
                    if (entry != null) {
                        result.add(entry.actorRef());
                    }
                }
            }
        } finally {
            registryLock.unlock();
        }

        return result.toArray(new ActorRef[0]);
    }

    /**
     * 获取Actor的子Actor
     */
    public ActorRef[] getChildren(ActorRef actorRef) {
        List<ActorRef> result = new ArrayList<>();

        String path = actorPathToPath.get(actorRef.path().toString());
        if (path != null) {
            registryLock.lock();
            try {
                Set<String> children = parentToChildren.get(path);
                if (children != null) {
                    for (String childPath : children) {
                        ActorRegistryEntry entry = pathToActor.get(childPath);
                        if (entry != null) {
                            result.add(entry.actorRef());
                        }
                    }
                }
            } finally {
                registryLock.unlock();
            }
        }

        return result.toArray(new ActorRef[0]);
    }

    /**
     * 获取Actor的父Actor
     */
    public Optional<ActorRef> getParent(ActorRef actorRef) {
        String path = actorPathToPath.get(actorRef.path().toString());
        if (path == null) {
            return Optional.empty();
        }

        registryLock.lock();
        try {
            String parentPath = childToParent.get(path);
            if (parentPath != null) {
                ActorRegistryEntry entry = pathToActor.get(parentPath);
                return (entry != null) ? Optional.of(entry.actorRef()) : Optional.empty();
            }
            return Optional.empty();
        } finally {
            registryLock.unlock();
        }
    }

    /**
     * 检查Actor是否已注册
     */
    public boolean isRegistered(ActorRef actorRef) {
        return actorPathToPath.containsKey(actorRef.path().toString());
    }

    /**
     * 检查名称是否已被占用 - Plan10.md要求
     */
    public boolean isNameTaken(String name) {
        return nameToPath.containsKey(name);
    }

    /**
     * 获取注册的Actor总数
     */
    public long getTotalActorCount() {
        return totalActors.get();
    }

    /**
     * 获取注册次数
     */
    public long getRegistrationCount() {
        return registrationCount.get();
    }

    /**
     * 获取所有注册的Actor
     */
    public ActorRef[] getAllActors() {
        List<ActorRef> result = new ArrayList<>();

        registryLock.lock();
        try {
            for (ActorRegistryEntry entry : pathToActor.values()) {
                result.add(entry.actorRef());
            }
        } finally {
            registryLock.unlock();
        }

        return result.toArray(new ActorRef[0]);
    }

    /**
     * 清空注册表
     */
    public void clear() {
        registryLock.lock();
        try {
            pathToActor.clear();
            actorPathToPath.clear();
            nameToPath.clear();
            parentToChildren.clear();
            childToParent.clear();
            totalActors.set(0);
        } finally {
            registryLock.unlock();
        }
    }

    /**
     * 打印注册表统计信息
     */
    public void printStats() {
        System.out.println("=== ActorRegistry统计信息 ===");
        System.out.println("总Actor数量: " + getTotalActorCount());
        System.out.println("注册次数: " + getRegistrationCount());
        System.out.println("路径索引大小: " + countPathToActor());
        System.out.println("名称索引大小: " + countNameToPath());
        System.out.println("父子关系索引大小: " + countParentToChildren());
    }

    private int countPathToActor() {
        return pathToActor.size();
    }

    private int countNameToPath() {
        return nameToPath.size();
    }

    private int countParentToChildren() {
        return parentToChildren.size();
    }

    private long getCurrentTimeNanos() {
        return System.nanoTime();
    }

    /**
     * 从路径中提取Actor名称
     */
    private String extractActorName(String path) {
        // 简化实现：直接返回路径作为名称
        // 在实际实现中，应该解析路径并提取最后一部分
        return path;
    }

    // Supporting inner class for registry entries
    public static class ActorRegistryEntry {
        private final ActorRef actorRef;
        private final long registeredAt;
        private final Optional<String> parentPath;

        public ActorRegistryEntry(ActorRef actorRef, long registeredAt, Optional<String> parentPath) {
            this.actorRef = actorRef;
            this.registeredAt = registeredAt;
            this.parentPath = parentPath;
        }

        public ActorRef actorRef() {
            return actorRef;
        }

        public long registeredAt() {
            return registeredAt;
        }

        public Optional<String> parentPath() {
            return parentPath;
        }
    }
}

