public static String getFieldVarInitSrc(FieldDescriptorProto field) {
    String name = field.getPropName();
    int type = field.getType();
    int label = field.getLabel();
    String typeName = field.getTypeName();
    String shortTypeName = field.getShortTypeName();

    if (type == FieldDescriptorProto.TYPE_MESSAGE && typeName.endsWith(">")) {
        return String.format("%s = %s(src.%s)", name, typeName, name);
    } else if (label == FieldDescriptorProto.LABEL_REPEATED && type == FieldDescriptorProto.TYPE_MESSAGE) {
        return String.format("%s = RepeatedMessage<%s>(src.%s)", name, shortTypeName, name);
    } else if (label == FieldDescriptorProto.LABEL_REPEATED && type == FieldDescriptorProto.TYPE_BYTES) {
        return String.format("%s = RepeatedField<BytesSlice>(src.%s.size) { _i -> BytesSlice(src.%s[_i]) }", name, name, name);
    } else if (label == FieldDescriptorProto.LABEL_REPEATED) {
        String convertedType = typeConvert(field);
        return String.format("%s = RepeatedField<%s>(src.%s)", name, convertedType, name);
    } else if (type == FieldDescriptorProto.TYPE_MESSAGE) {
        return String.format("p_%s = PbMessage(src.%s)", field.getName(), name);
    } else {
        return String.format("p_%s = src.%s", field.getName(), name);
    }
}

