func getFieldVarInitSrc(field: FieldDescriptorProto) {
    let name = field.propName
    match {
        else field.type == TYPE_MESSAGE && field.typeName.endsWith(">") => "${name} = ${field.typeName}(src.${name})"
        else field.label == LABEL_REPEATED && field.type == TYPE_MESSAGE => "${name} = RepeatedMessage<${field.shortTypeName}>(src.${name})"
        else field.label == LABEL_REPEATED && field.type == TYPE_BYTES => "${name} = RepeatedField<BytesSlice>(src.${name}.size) { _i => BytesSlice(src.${name}[_i]) }"
        else field.label == LABEL_REPEATED => "${name} = RepeatedField<${typeConvert(field)}>(src.${name})"
        else field.type == TYPE_MESSAGE => "p_${field.name} = PbMessage(src.${name})"
        else _ => "p_${field.name} = src.${name}"
    }
