import org.quartz.TriggerBuilder;
import org.quartz.TriggerUtils;
import org.quartz.impl.triggers.DailyTimeIntervalTriggerImpl;
import org.quartz.impl.triggers.DailyTimeIntervalScheduleBuilder;
import org.quartz.time.TimeOfDay;

public class DailyTimeIntervalScheduleBuilderTest {

    private static java.time.LocalDateTime makeTime(long year, long month, long day,
            long hour, long minute, long second) {
        return java.time.LocalDateTime.of((int) year, (int) month, (int) day,
                (int) hour, (int) minute, (int) second, 0);
    }

    private static Date toJavaUtilDate(java.time.LocalDateTime ldt) {
        return java.util.Date.from(ldt.atZone(java.time.ZoneId.systemDefault()).toInstant());
    }

    @Test
    public void testScheduleActualTrigger() {
        JobDetail job = JobBuilder.newJob(TestJob.class).withIdentity("testJob").build();
        DailyTimeIntervalTrigger trigger = TriggerBuilder.newTrigger()
                .withIdentity("test")
                .withSchedule(DailyTimeIntervalScheduleBuilder.dailyTimeIntervalSchedule()
                        .withIntervalInSeconds(3)
                        .startingDailyAt(new TimeOfDay(0, 0, 0))
                        .endingDailyAt(new TimeOfDay(23, 59, 59)))
                .build();
    }

    @Test
    public void testHourlyTrigger() {
        DailyTimeIntervalTrigger trigger = TriggerBuilder.newTrigger()
                .withIdentity("test")
                .withSchedule(DailyTimeIntervalScheduleBuilder.dailyTimeIntervalSchedule()
                        .withIntervalInHours(1))
                .build();

        assertEquals("test", trigger.getKey().getName());
        assertEquals("DEFAULT", trigger.getKey().getGroup());
        assertTrue(IntervalUnit.HOUR == trigger.getRepeatIntervalUnit());
        assertEquals(1, trigger.getRepeatInterval());

        List<Date> fireTimes = computeFireTimes((OperableTrigger) trigger, null, 48);
        assertEquals(48, fireTimes.size());
    }

    @Test
    public void testMinutelyTriggerWithTimeOfDay() {
        DailyTimeIntervalTrigger trigger = TriggerBuilder.newTrigger()
                .withIdentity("test", "group")
                .withSchedule(DailyTimeIntervalScheduleBuilder.dailyTimeIntervalSchedule()
                        .withIntervalInMinutes(72)
                        .startingDailyAt(new TimeOfDay(8, 0, 0))
                        .endingDailyAt(new TimeOfDay(17, 0, 0))
                        .onMondayThroughFriday())
                .build();

        assertEquals("test", trigger.getKey().getName());
        assertEquals("group", trigger.getKey().getGroup());
        assertTrue(System.currentTimeMillis() >= trigger.getStartTime().getTime());
        assertTrue(IntervalUnit.MINUTE == trigger.getRepeatIntervalUnit());
        assertEquals(72, trigger.getRepeatInterval());
        assertTrue(new TimeOfDay(8, 0, 0).equals(trigger.getStartTimeOfDay()));
        assertTrue(new TimeOfDay(17, 0, 0).equals(trigger.getEndTimeOfDay()));

        List<Date> fireTimes = computeFireTimes((OperableTrigger) trigger, null, 48);
        assertEquals(48, fireTimes.size());
    }

    @Test
    public void testSecondlyTriggerWithStartAndEndTime() {
        DailyTimeIntervalTrigger trigger = TriggerBuilder.newTrigger()
                .withIdentity("test", "group")
                .withSchedule(DailyTimeIntervalScheduleBuilder.dailyTimeIntervalSchedule()
                        .withIntervalInSeconds(10)
                        .startingDailyAt(new TimeOfDay(8, 0, 0))
                        .endingDailyAt(new TimeOfDay(17, 0, 0))
                        .onMondayThroughFriday())
                .build();

        assertEquals("test", trigger.getKey().getName());
        assertEquals("group", trigger.getKey().getGroup());
        assertTrue(System.currentTimeMillis() >= trigger.getStartTime().getTime());
        assertTrue(IntervalUnit.SECOND == trigger.getRepeatIntervalUnit());
        assertEquals(10, trigger.getRepeatInterval());
        assertTrue(new TimeOfDay(8, 0, 0).equals(trigger.getStartTimeOfDay()));
        assertTrue(new TimeOfDay(17, 0, 0).equals(trigger.getEndTimeOfDay()));

        List<Date> fireTimes = computeFireTimes((OperableTrigger) trigger, null, 48);
        assertEquals(48, fireTimes.size());
    }

    @Test
    public void testRepeatCountTrigger() {
        DailyTimeIntervalTrigger trigger = TriggerBuilder.newTrigger()
                .withIdentity("test")
                .withSchedule(DailyTimeIntervalScheduleBuilder.dailyTimeIntervalSchedule()
                        .withIntervalInHours(1)
                        .withRepeatCount(9))
                .build();

        assertEquals("test", trigger.getKey().getName());
        assertEquals("DEFAULT", trigger.getKey().getGroup());
        assertTrue(IntervalUnit.HOUR == trigger.getRepeatIntervalUnit());
        assertEquals(1, trigger.getRepeatInterval());

        List<Date> fireTimes = computeFireTimes((OperableTrigger) trigger, null, 48);
        assertEquals(10, fireTimes.size());
    }

    @Test
    public void testEndingAtAfterCount() {
        Date startTime = toJavaUtilDate(makeTime(2011, 1, 1, 0, 0, 0));
        DailyTimeIntervalTrigger trigger = TriggerBuilder.newTrigger()
                .withIdentity("test")
                .withSchedule(DailyTimeIntervalScheduleBuilder.dailyTimeIntervalSchedule()
                        .withIntervalInMinutes(15)
                        .startingDailyAt(new TimeOfDay(8, 0, 0))
                        .endingDailyAfterCount(12))
                .startAt(startTime)
                .build();

        assertEquals("test", trigger.getKey().getName());
        assertEquals("DEFAULT", trigger.getKey().getGroup());
        assertTrue(IntervalUnit.MINUTE == trigger.getRepeatIntervalUnit());

        List<Date> fireTimes = computeFireTimes((OperableTrigger) trigger, null, 48);
        assertEquals(48, fireTimes.size());

        assertEquals(toJavaUtilDate(makeTime(2011, 1, 1, 8, 0, 0)), fireTimes.get(0));
        assertEquals(toJavaUtilDate(makeTime(2011, 1, 1, 8, 15, 0)), fireTimes.get(1));
        assertEquals(toJavaUtilDate(makeTime(2011, 1, 4, 10, 45, 0)), fireTimes.get(47));
        assertTrue(new TimeOfDay(10, 45, 0).equals(trigger.getEndTimeOfDay()));
    }

    @Test
    public void testEndingAtAfterCountOf1() {
        Date startTime = toJavaUtilDate(makeTime(2011, 1, 1, 0, 0, 0));
        DailyTimeIntervalTrigger trigger = TriggerBuilder.newTrigger()
                .withIdentity("test")
                .withSchedule(DailyTimeIntervalScheduleBuilder.dailyTimeIntervalSchedule()
                        .withIntervalInMinutes(15)
                        .startingDailyAt(new TimeOfDay(8, 0, 0))
                        .endingDailyAfterCount(1))
                .startAt(startTime)
                .forJob("testJob", "testJobGroup")
                .build();

        assertEquals("test", trigger.getKey().getName());
        assertEquals("DEFAULT", trigger.getKey().getGroup());
        assertTrue(IntervalUnit.MINUTE == trigger.getRepeatIntervalUnit());

        validateTrigger(trigger);

        List<Date> fireTimes = computeFireTimes((OperableTrigger) trigger, null, 48);
        assertEquals(48, fireTimes.size());

        assertEquals(toJavaUtilDate(makeTime(2011, 1, 1, 8, 0, 0)), fireTimes.get(0));
        assertEquals(toJavaUtilDate(makeTime(2011, 1, 2, 8, 0, 0)), fireTimes.get(1));
        assertEquals(toJavaUtilDate(makeTime(2011, 2, 17, 8, 0, 0)), fireTimes.get(47));
        assertTrue(new TimeOfDay(8, 0, 0).equals(trigger.getEndTimeOfDay()));
    }

    private void validateTrigger(DailyTimeIntervalTrigger trigger) {
        try {
            ((OperableTrigger) trigger).validate();
        } catch (SchedulerException e) {
            throw new RuntimeException(e);
        }
    }

    @Test
    public void testEndingAtAfterCountOf0() {
        try {
            Date startTime = toJavaUtilDate(makeTime(2011, 1, 1, 0, 0, 0));
            DailyTimeIntervalTrigger trigger = TriggerBuilder.newTrigger()
                    .withIdentity("test")
                    .withSchedule(DailyTimeIntervalScheduleBuilder.dailyTimeIntervalSchedule()
                            .withIntervalInMinutes(15)
                            .startingDailyAt(new TimeOfDay(8, 0, 0))
                            .endingDailyAfterCount(0))
                    .startAt(startTime)
                    .build();
            fail("We should not accept endingDailyAfterCount(0)");
        } catch (IllegalArgumentException e) {
            // expected
        }

        try {
            Date startTime = toJavaUtilDate(makeTime(2011, 1, 1, 0, 0, 0));
            DailyTimeIntervalTrigger trigger = TriggerBuilder.newTrigger()
                    .withIdentity("test")
                    .withSchedule(DailyTimeIntervalScheduleBuilder.dailyTimeIntervalSchedule()
                            .withIntervalInMinutes(15)
                            .endingDailyAfterCount(1))
                    .startAt(startTime)
                    .build();
            fail("We should not accept endingDailyAfterCount(x) without startTime");
        } catch (IllegalArgumentException e) {
            // expected
        }
    }
}

