private void deleteRollingFile() {
    try {
        java.nio.file.Path fileDir = this.file.info.getParent().toPath();
        java.io.File dir = fileDir.toFile();
        if (!dir.exists() || !dir.isDirectory()) {
            System.out.println("logfile Directory is none");
            return;
        }
        for (java.io.File file : dir.listFiles()) {
            if (file != null && file.isFile() && file.getName().contains(".log")) {
                long lastModified = file.lastModified();
                // Convert to LocalDateTime for day arithmetic (simplified: using Calendar for portability)
                java.util.Calendar cal = java.util.Calendar.getInstance();
                cal.setTimeInMillis(lastModified);
                cal.add(java.util.Calendar.DAY_OF_MONTH, this.retentionDays);
                java.util.Date expiryDate = cal.getTime();
                java.util.Date now = new java.util.Date();
                if (expiryDate.before(now)) {
                    if (!file.delete()) {
                        System.err.println("Failed to delete log file: " + file.getAbsolutePath());
                    }
                }
            }
        }
    } catch (java.lang.NullPointerException e) {
        System.out.println("logfile Directory is none");
        return;
    } catch (java.io.IOException e) {
        System.out.println("delete log file has occur an exception");
    }
}

