import java.util.Arrays;

public class Delims {
    public char start1 = '{';
    public char end1 = '}';
    public char start2 = '{';
    public char end2 = '}';

    public boolean isStaches() {
        return start1 == '{' && start2 == '{' && end1 == '}' && end2 == '}';
    }

    public Delims updateDelims(String dtext) {
        String[] delims = dtext.split(" ");
        if (delims.length != 2) {
            throw new MustacheException(errmsg(dtext));
        }

        String delimsStr1 = delims[0];
        String delimsStr2 = delims[1];
        char[] tempDelims1 = delimsStr1.toCharArray();
        char[] tempDelims2 = delimsStr2.toCharArray();

        switch (delimsStr1.length()) {
            case 1:
                start1 = tempDelims1[0];
                start2 = Mustache.NO_CHAR;
                break;
            case 2:
                start1 = tempDelims1[0];
                start2 = tempDelims1[1];
                break;
            default:
                throw new MustacheException(errmsg(dtext));
        }

        switch (delimsStr2.length()) {
            case 1:
                end1 = tempDelims2[0];
                end2 = Mustache.NO_CHAR;
                break;
            case 2:
                end1 = tempDelims2[0];
                end2 = tempDelims2[1];
                break;
            default:
                throw new MustacheException(errmsg(dtext));
        }

        return this;
    }

    public void addTag(char prefix, String name, StringBuilder into) {
        into.append(start1);
        into.append(start2);
        if (prefix != ' ') {
            into.append(prefix);
        }
        into.append(name);
        into.append(end1);
        into.append(end2);
    }

    public Delims copy() {
        Delims d = new Delims();
        d.start1 = this.start1;
        d.start2 = this.start2;
        d.end1 = this.end1;
        d.end2 = this.end2;
        return d;
    }

    private static String errmsg(String dtext) {
        return "Invalid delimiter configuration '" + dtext + "'. Must be of the " +
               "form {{=1 2=}} or {{=12 34=}} where 1, 2, 3 and 4 are delimiter chars.";
    }
}

