import java.io.InputStream;
import java.io.IOException;
import java.nio.charset.StandardCharsets;
import java.util.List;
import java.util.ArrayList;
import java.util.Map;
import java.util.HashMap;
import java.util.Optional;
import java.util.regex.Pattern;
import java.util.stream.Collectors;

public class HttpChunkedBodyProvider extends InputStream {
    private boolean eof = false;
    private long contentLength = 0;
    private long remainChunkSize = 0;
    private boolean isLastChunk = false;
    private final HttpHeaders header;
    private final HttpHeaders trailer;
    private final boolean isReq;
    private final BufferedConn conn;
    private final BodyProviderConn providerConn;
    private final HttpTimer timer;

    public HttpChunkedBodyProvider(BodyProviderConn providerConn, Object msg, HttpTimer timer) {
        this.providerConn = providerConn;
        this.timer = timer;
        this.conn = providerConn.getBufferConn();
        this.header = new HttpHeaders();
        this.trailer = new HttpHeaders();

        if (msg instanceof HttpRequest req) {
            this.header.addAll(req.headers);
            this.trailer.addAll(req.trailers);
            this.isReq = true;
        } else if (msg instanceof HttpResponse rsp) {
            this.header.addAll(rsp.headers);
            this.trailer.addAll(rsp.trailers);
            this.isReq = false;
        } else {
            throw new HttpException("Unsupported msg type!");
        }
    }

    @Override
    public int read(byte[] dst) throws IOException {
        return (int) read(dst, 0, dst.length);
    }

    @Override
    public int read(byte[] dst, int offset, int length) throws IOException {
        if (eof) {
            return 0;
        }
        int dstReadLen = 0;
        try {
            // parse the existing content in the buffer.
            // chunk-data is from the buffer,
            // but CRLF
            // and chunk-size [ chunk-ext ] CRLF
            // and 1*("0") [ chunk-ext ] CRLF may not.
            // break when eof or buffer is empty or dst is full.
            while (conn.getBufferedReader().getRemainingData() != 0 && dstReadLen < length) {
                remainChunkSize = getRemainSize(remainChunkSize);
                if (remainChunkSize == 0) {
                    return dstReadLen;
                }
                int readLen = conn.read(dst, offset + dstReadLen, (int) Math.min(remainChunkSize, length - dstReadLen));
                dstReadLen += readLen;
                remainChunkSize -= readLen;
                if (remainChunkSize == 0) {
                    readNextChunkLine(isReq);
                }
            }
        } catch (Exception e) {
            timer.cancel();
            providerConn.closeConn();
            if (providerConn.isReadTimeout().get()) {
                throw new HttpTimeoutException("Read body timeout and the connection is closed.");
            }
            throw e;
        }
        return dstReadLen;
    }

    private long getRemainSize(long remainChunkSize) {
        if (remainChunkSize == 0) {
            long chunkSize = readChunkSize();
            this.contentLength += chunkSize;
            // last-chunk = 1*("0") [ chunk-ext ] CRLF
            if (chunkSize == 0) {
                eof = true;
                readTrailer();
                clearHeader();
                timer.cancel();
                providerConn.returnConn();
            }
            return chunkSize;
        }
        return remainChunkSize;
    }

    // chunk-data CRLF
    // read CRLF and next chunk-size [ chunk-ext ] CRLF
    private void readNextChunkLine(boolean isReq) throws IOException {
        String lf = readLine();
        if (!lf.isEmpty()) {
            if (isReq) {
                throw new HttpStatusException(HttpStatusCode.STATUS_BAD_REQUEST, "Bad request.");
            } else {
                throw new HttpException("Invalid chunked data.");
            }
        }
    }

    /*
     * Trailer = #field-name
     * trailer-section = *( field-line CRLF )
     * The "Trailer" header field provides a list of field names that the sender anticipates sending as
     * trailer fields within that message. This allows a recipient to prepare for receipt of the indicated
     * metadata before it starts processing the content
     * RFC 9110 6.6.2.
     */
    private void readTrailer() throws IOException {
        while (true) {
            String trailerLine = readLine();
            if (trailerLine.isEmpty()) {
                break;
            }

            HeaderNameValuePair pair = parseAndCheckHeaderLine(trailerLine, isReq);
            if (validTrailerName(pair.name())) {
                trailer.add(pair.name(), pair.value());
            }
        }
    }

    private void clearHeader() {
        // set `Content-Length`
        header.add("content-length", String.valueOf(contentLength));
        // remove `chunked` from last
        List<String> hv = header.getInternal("transfer-encoding");
        if (hv == null || hv.isEmpty()) {
            return;
        }
