import java.nio.file.*;
import java.nio.file.attribute.BasicFileAttributes;
import java.util.HashMap;
import java.util.Map;

public class FDInfoCollector {
    public static Map<String, String> collectFDInfo() {
        Map<String, String> fds = new HashMap<>();
        Path path = Paths.get("/proc/self/fd");
        if (!Files.exists(path)) {
            return fds;
        }
        try {
            Files.walkFileTree(path, new SimpleFileVisitor<Path>() {
                @Override
                public FileVisitResult visitFile(Path file, BasicFileAttributes attrs) throws IOException {
                    String fdPath = file.toString();
                    try {
                        String realPath = Files.readSymbolicLink(file).toString();
                        fds.put(fdPath, realPath);
                    } catch (IOException e) {
                        fds.put(fdPath, "unknown");
                    }
                    return FileVisitResult.CONTINUE;
                }
            });
        } catch (IOException e) {
            AppLog.warn("hm-metricx-cj error: collectFDInfo failed: " + e.toString());
        } catch (OutOfMemoryError e) {
            AppLog.warn("hm-metricx-cj error: collectFDInfo OOM failed: " + e.toString());
        }
        return fds;
    }
}

