import java.time.Duration;
import java.time.Instant;
import java.time.temporal.ChronoUnit;
import java.util.List;
import java.util.Optional;
import java.util.function.Function;

public class JwtAuth implements JoyMiddlewareHandler {

    private final Function<JoyContext, Optional<String>> _getTokenFunc;

    private final String realm;
    private final String signingAlg;
    private final JwtKey keyProvider;
    private final JoyRequestHandlerFunc authenticator;
    private final BiFunction<JoyContext, String, Boolean> authorizator;
    private final TriFunction<JoyContext, Jwt, Void> setPayload;
    private final QuadFunction<JoyContext, Short, String, Void> unauthorized;
    private final PentaFunction<JoyContext, Short, String, Instant, Void> loginResponse;
    private final QuadFunction<JoyContext, Short, Void> logoutResponse;
    private final PentaFunction<JoyContext, Short, String, Instant, Void> refreshResponse;
    private final Duration timeout;
    private final Duration maxRefresh;
    private final String identityKey;
    private final Function<JoyContext, String> identityHandler;
    private final String tokenLookup;
    private final String tokenHeadName;
    private final boolean sendCookie;
    private final Duration cookieMaxAge;
    private final boolean cookieSecure;
    private final boolean cookieHttpOnly;
    private final String cookieDomain;
    private final String cookieName;
    private final boolean sendAuthorization;
    private final ParserConfig jwtParserConfig;

    /**
     * 构造 JwtAuth 实例。
     *
     * @param realm 向用户显示的领域名称
     * @param signingAlg 签名算法 -可能的值为 HS256、HS384、HS512、RS256、RS384 或 RS512
     * @param keyProvider 用于获取签名或验证密钥的回调函数
     * @param authenticator 执行用户身份验证的回调函数。必须在上下文中设置用户数据作为用户标识符，它将存储在 Claim 数组中
     * @param authorizator 执行已认证用户授权的回调函数。仅在身份验证成功后调用。成功时返回 true，失败时返回 false
     * @param setPayload 登录时调用的回调函数。使用此函数可以向 webtoken 添加额外的负载数据。请注意，负载未加密。jwt.io 上提到的属性不能用作映射的键
     * @param unauthorized 用户可以定义自己的 Unauthorized 函数
     * @param loginResponse 用户可以定义自己的 LoginResponse 函数
     * @param logoutResponse 用户可以定义自己的 LogoutResponse 函数
     * @param refreshResponse 用户可以定义自己的 RefreshResponse 函数
     * @param timeout JWT 令牌的有效时长
     * @param maxRefresh 刷新令牌的时长。客户端可以在 maxRefresh 结束前的最后时刻刷新令牌。这意味着令牌的最大有效时间跨度为 tokenTime + maxRefresh。默认为 0 表示不可刷新
     * @param identityKey 设置身份密钥
     * @param identityHandler 设置身份处理函数
     * @param tokenLookup TokenLookup 是一个 "<source>:<name>" 形式的字符串，用于从请求中提取令牌。可能的值：header、query、cookie、param、form
     * @param tokenHeadName 头部中的字符串
     * @param sendCookie 作为 cookie 的令牌
     * @param cookieMaxAge Cookie 的有效时长。可选，默认为 Timeout 值
     * @param cookieSecure 是否使用安全 Cookie
     * @param cookieHttpOnly 是否只允许 HTTP 访问 Cookie
     * @param cookieDomain Cookie 域名
     * @param cookieName Cookie 名称
     * @param sendAuthorization 允许为每个请求返回授权头部
     * @param jwtParserConfig 修改 jwt 解析配置
     */
    public JwtAuth(String realm, String signingAlg, JwtKey keyProvider,
                    JoyRequestHandlerFunc authenticator,
                    BiFunction<JoyContext, String, Boolean> authorizator,
                    TriFunction<JoyContext, Jwt, Void> setPayload,
                    QuadFunction<JoyContext, Short, String, Void> unauthorized,
                    PentaFunction<JoyContext, Short, String, Instant, Void> loginResponse,
                    QuadFunction<JoyContext, Short, Void> logoutResponse,
                    PentaFunction<JoyContext, Short, String, Instant, Void> refreshResponse,
                    Duration timeout, Duration maxRefresh,
                    String identityKey, Function<JoyContext, String> identityHandler,
                    String tokenLookup, String tokenHeadName,
                    boolean sendCookie, Duration cookieMaxAge,
                    boolean cookieSecure, boolean cookieHttpOnly, String cookieDomain,
                    String cookieName, boolean sendAuthorization,
                    ParserConfig jwtParserConfig) {
        this.realm = realm;
        this.signingAlg = signingAlg;
        this.keyProvider = keyProvider;
        this.authenticator = authenticator;
        this.authorizator = (authorizator != null) ? authorizator : JwtAuth::defaultAuthorizator;
        this.setPayload = (setPayload != null) ? setPayload : JwtAuth::defaultPayloadFunc;
        this.unauthorized = (unauthorized != null) ? unauthorized : JwtAuth::defaultUnauthorized;
        this.loginResponse = (loginResponse != null) ? loginResponse : JwtAuth::defaultLoginResponse;
        this.logoutResponse = (logoutResponse != null) ? logoutResponse : JwtAuth::defaultLogoutResponse;
        this.refreshResponse = (refreshResponse != null) ? refreshResponse : JwtAuth::defaultLoginResponse;
        this.timeout = (timeout != null) ? timeout : Duration.ofMinutes(30);
        this.maxRefresh = (maxRefresh != null) ? maxRefresh : Duration.ZERO;
        this.identityKey = (identityKey != null) ? identityKey : "identity";
        this.tokenLookup = (tokenLookup != null) ? tokenLookup : "header:Authorization";
        this.tokenHeadName = (tokenHeadName != null) ? tokenHeadName : "Bearer";
        this.sendCookie = sendCookie;
        this.cookieMaxAge = (cookieMaxAge != null) ? cookieMaxAge : Duration.ofMinutes(30);
        this.cookieSecure = cookieSecure;
        this.cookieHttpOnly = cookieHttpOnly;
        this.cookieDomain = (cookieDomain != null) ? cookieDomain : "";
        this.cookieName = (cookieName != null) ? cookieName : "jwt";
        this.sendAuthorization = sendAuthorization;
        this.jwtParserConfig = jwtParserConfig;

        this._getTokenFunc = createGetTokenFunc(this.tokenLookup, this.tokenHeadName);

        if (this.identityHandler == null) {
            this.identityHandler = ctx -> {
                Claims claims = ctx.getCtxParam(JWT_PAYLOAD_CTX_KEY);
                if (claims == null) {
                    return "";
                }
                return Optional.ofNullable(claims.getClaimString(this.identityKey)).orElse("");
            };
        } else {
            this.identityHandler = identityHandler;
        }
    }

    /**
     * @throws IllegalArgumentException
     */
    private static Function<JoyContext, Optional<String>> createGetTokenFunc(String tokenLookup, String tokenHeadName) {
        String[] sn = tokenLookup.split(":");
        if (sn.length != 2) {
            throw new IllegalArgumentException("tokenLookup format must be <source>:<name>");
        }
        String source = sn[0];
        String name = sn[1];

        return switch (source) {
            case "header" -> ctx -> {
                Optional<String> value = ctx.getHeader(name);
                if (value.isPresent()) {
                    String v = value.get();
                    if (!tokenHeadName.isEmpty() && v.startsWith(tokenHeadName + " ")) {
                        return Optional.of(v.substring(tokenHeadName.length() + 1));
                    }
                }
                return value;
            };
            case "query" -> ctx -> ctx.getQuery(name);
            case "form" -> ctx -> ctx.getPostForm(name);
            case "param" -> ctx -> ctx.getParam(name);
            case "cookie" -> ctx -> ctx.getCookie(name);
            default -> throw new IllegalArgumentException(
                    "lookupKey format must be <source>:<name>, source must be one of [header, query, form, param, cookie]");
        };
    }

    @Override
    public void handle(JoyContext ctx, JoyRequestHandlerChain chain) {
        try {
            // authentication: Explain Token
            setClaims(ctx);
            String identifier = Optional.ofNullable(identityHandler.apply(ctx)).orElse("");
            if (!identifier.isEmpty()) {
                ctx.setCtxParam(identityKey, identifier);
            }

            // authorization callback
            if (!authorizator.apply(ctx, identifier)) {
                doUnauthorized(ctx, (short) 403, "authorizate failed");
                return;
            }

            chain.next(ctx);
        } catch (JwtException ex) {
            doUnauthorized(ctx, (short) 401, ex.getMessage());
        }
    }

    public void loginHandler(JoyContext ctx) {
        authenticator.handle(ctx);
        if (ctx.getRespStatus() != 200) {
            return;
        }

        try {
            // create the token
            Jwt jwt = Jwt.create().alg(signingAlg);
            setPayload.apply(ctx, jwt);

            Instant now = Instant.now();
            Instant expire = now.plus(timeout.toNanos(), ChronoUnit.NANOS);
            jwt.getClaims().expirationTime(expire);
            jwt.getClaims().issuedAt(now);

            List<Key> keys = keyProvider.getKeys(jwt);
            if (keys.isEmpty()) {
                throw new JwtException("no signing key available");
            }
            String token = jwt.signWith(keys.get(0));

            if (sendCookie) {
                Cookie c = new Cookie(cookieName, token)
                        .maxAge((int) cookieMaxAge.getSeconds())
                        .domain(cookieDomain)
                        .path("/")
                        .secure(cookieSecure)
                        .httpOnly(cookieHttpOnly);
                ctx.cookie(c);
            }

            // callback loginResponse
            loginResponse.apply(ctx, (short) 200, token, expire);
        } catch (JwtException ex) {
            doUnauthorized(ctx, (short) 401, ex.getMessage());
        }
    }

    public void logoutHandler(JoyContext ctx) {
        if (sendCookie) {
            // delete auth cookie
            Cookie c = new Cookie(cookieName, "")
                    .expires(Instant.EPOCH)
                    .domain(cookieDomain)
                    .path("/")
                    .secure(cookieSecure)
                    .httpOnly(cookieHttpOnly);
            ctx.cookie(c);
        }

        // callback logoutResponse
        logoutResponse.apply(ctx, (short) 200);
    }

    public void refreshTokenHandler(JoyContext ctx) {
        try {
            Jwt origJwt = checkIfTokenExpire(ctx);

            // create new token
            Jwt jwt = Jwt.create().alg(signingAlg);
            jwt.copyClaims(origJwt);

            Instant now = Instant.now();
            Instant expire = now.plus(timeout.toNanos(), ChronoUnit.NANOS);
            jwt.getClaims().expirationTime(expire);
            jwt.getClaims().issuedAt(now);

            List<Key> keys = keyProvider.getKeys(jwt);
            if (keys.isEmpty()) {
                throw new JwtException("no signing key available");
            }
            String token = jwt.signWith(keys.get(0));

            if (sendCookie) {
                Cookie c = new Cookie(cookieName, token)
                        .maxAge((int) cookieMaxAge.getSeconds())
                        .domain(cookieDomain)
                        .path("/")
                        .secure(cookieSecure)
                        .httpOnly(cookieHttpOnly);
                ctx.cookie(c);
            }

            // callback refreshResponse
            refreshResponse.apply(ctx, (short) 200, token, expire);
        } catch (JwtException ex) {
            doUnauthorized(ctx, (short) 401, ex.getMessage());
        }
    }

    private Jwt parseToken(JoyContext ctx) throws JwtException {
        Optional<String> tokenOpt = _getTokenFunc.apply(ctx);
        String token = tokenOpt.orElseThrow(() -> new JwtException("not found token in reqired field"));
        ParserConfig config = (jwtParserConfig != null) ? jwtParserConfig
                : new ParserConfig(true, true);
        Jwt jwt = Jwt.parse(token, config);
        if (!signingAlg.equals(jwt.getHeaders().getAlg())) {
            throw new JwtException("invalid signing algorithm");
        }
        jwt.verifyWith(keyProvider.getKeys(jwt).get(1));
        // save token string if valid
        ctx.setCtxParam(JWT_CTX_KEY, token);
        return jwt;
    }

    private void setClaims(JoyContext ctx) throws JwtException {
        Jwt jwt = parseToken(ctx);
        if (sendAuthorization) {
            Optional<String> t = getJwt(ctx);
            if (t.isPresent()) {
                ctx.header(JoyHttpConsts.HEADER_AUTHORIZATION, tokenHeadName + " " + t.get());
            }
        }
        ctx.setCtxParam(JWT_PAYLOAD_CTX_KEY, jwt.getClaims());
    }

    private Jwt checkIfTokenExpire(JoyContext ctx) throws JwtException {
        Jwt jwt = parseToken(ctx);
        Instant iat = jwt.getClaims().getIssuedAt();
        if (iat == null) {
            throw new JwtException("token is expired");
        }
        Instant now = Instant.now();
        Instant cutoff = now.minus(maxRefresh.toNanos(), ChronoUnit.NANOS);
        if (iat.isBefore(cutoff)) {
            throw new JwtException("token is expired");
        }
        return jwt;
    }

    private void doUnauthorized(JoyContext ctx, short code, String message) {
        ctx.header(JoyHttpConsts.HEADER_WWW_AUTHENTICATE, "JWT realm=" + realm);
        JoyLog.error("[JwtAuth] auth failed, {}, {} {}, {}", ctx.getClientIP(), ctx.getMethod(), ctx.getUrl(), message);
        unauthorized.apply(ctx, code, message);
    }

    // Helper functional interfaces (to match仓颉语义)
    @FunctionalInterface
    interface BiFunction<T, U, R> {
        R apply(T t, U u);
    }

    @FunctionalInterface
    interface TriFunction<T, U, V, R> {
        R apply(T t, U u, V v);
    }

    @FunctionalInterface
    interface QuadFunction<T, U, V, W, R> {
        R apply(T t, U u, V v, W w);
    }

    @FunctionalInterface
    interface PentaFunction<T, U, V, W, X, R> {
        R apply(T t, U u, V v, W w, X x);
    }

    // Default implementations (stubbed as per仓颉 defaults)
    private static boolean defaultAuthorizator(JoyContext ctx, String identity) {
        return true;
    }

    private static Void defaultPayloadFunc(JoyContext ctx, Jwt jwt) {
        return null;
    }

    private static Void defaultUnauthorized(JoyContext ctx, short code, String message) {
        ctx.status(code);
        ctx.text(message);
        return null;
    }

    private static Void defaultLoginResponse(JoyContext ctx, short code, String token, Instant expire) {
        ctx.status(code);
        ctx.json(Map.of("token", token, "expire", expire.toString()));
        return null;
    }

    private static Void defaultLogoutResponse(JoyContext ctx, short code) {
        ctx.status(code);
        ctx.text("logged out");
        return null;
    }

    private static Optional<String> getJwt(JoyContext ctx) {
        return Optional.ofNullable((String) ctx.getCtxParam(JWT_CTX_KEY));
    }

    // Constants (assumed from context)
    private static final String JWT_CTX_KEY = "jwt_token";
    private static final String JWT_PAYLOAD_CTX_KEY = "jwt_claims";
}

