    private static final int IDENTITY = 0;
    private static final int OMIT_LAST_BASE = IDENTITY + 1 - 1; // 0
    private static final int UPPERCASE_FIRST = OMIT_LAST_BASE + OMIT_FIRST_LAST_LIMIT + 1; // 10
    private static final int UPPERCASE_ALL = UPPERCASE_FIRST + 1; // 11
    private static final int OMIT_FIRST_BASE = UPPERCASE_ALL + 1 - 1; // 11
    private static final int SHIFT_FIRST = OMIT_FIRST_BASE + OMIT_FIRST_LAST_LIMIT + 1; // 21
    private static final int SHIFT_ALL = SHIFT_FIRST + 1; // 22

