public boolean tryEnterSubIfd(int tagId) {
    if (tagId == ExifDirectoryConstant.TAG_SUB_IFD_OFFSET) {
        pushDirectory(new ExifSubIFDDirectory());
        return true;
    }

    if (_currentDirectory != null) {
        String className = _currentDirectory.getClassName();
        if (!"ExifIFD0Directory".equals(className) && !"PanasonicRawIFD0Directory".equals(className)) {
            if ("ExifSubIFDDirectory".equals(className)) {
                if (tagId == ExifSubIFDDirectory.TAG_INTEROP_OFFSET) {
                    pushDirectory(new ExifInteropDirectory());
                    return true;
                }
            } else if ("OlympusMakernoteDirectory".equals(className)) {
                switch (tagId) {
                    case 0x2010:
                        pushDirectory(new OlympusEquipmentMakernoteDirectory());
                        return true;
                    case 0x2020:
                        pushDirectory(new OlympusCameraSettingsMakernoteDirectory());
                        return true;
                    case 0x2030:
                        pushDirectory(new OlympusRawDevelopmentMakernoteDirectory());
                        return true;
                    case 0x2031:
                        pushDirectory(new OlympusRawDevelopment2MakernoteDirectory());
                        return true;
                    case 0x2040:
                        pushDirectory(new OlympusImageProcessingMakernoteDirectory());
                        return true;
                    case 0x2050:
                        pushDirectory(new OlympusFocusInfoMakernoteDirectory());
                        return true;
                    case 0x3000:
                        pushDirectory(new OlympusRawInfoMakernoteDirectory());
                        return true;
                    case 0x4000:
                        pushDirectory(new OlympusMakernoteDirectory());
                        return true;
                    default:
                        break;
                }
            }
        } else {
            if (tagId == ExifIFD0Directory.TAG_EXIF_SUB_IFD_OFFSET) {
                pushDirectory(new ExifSubIFDDirectory());
                return true;
            }
            if (tagId == ExifIFD0Directory.TAG_GPS_INFO_OFFSET) {
                pushDirectory(new GpsDirectory());
                return true;
            }
        }
    }

    return false;
}

