                  .append(">).getOrThrow()\n");
            buffer.append("this.").append(entity.getClassName().toLowerCase()).append("DaoConfig.initIdentityScope(t)\n");
            buffer.append("this.").append(entity.getClassName().toLowerCase()).append("Dao = ")
                  .append(entity.getClassName()).append("Dao(")
