public class LinearAlgebra {

    public enum MatrixNorm {
        MaxAbs,
        MaxRowSum,
        MaxColumnSum,
        Frobenius
    }

    public enum Uplo {
        Upper,
        Lower
    }

    public static double dlansy(MatrixNorm norm, Uplo uplo, long n, double[] a, long lda) {
        if (n == 0) {
            return 0.0;
        }
        double[] work = new double[(int) n];
        for (int i = 0; i < work.length; i++) {
            work[i] = 0.0;
        }

        switch (norm) {
            case MaxAbs:
                if (uplo == Uplo.Upper) {
                    double max = 0.0;
                    for (long i = 0; i < n; i++) {
                        for (long j = i; j < n; j++) {
                            double v = Math.abs(a[(int) (i * lda + j)]);
                            if (Double.isNaN(v)) {
                                return Double.NaN;
                            }
                            if (v > max) {
                                max = v;
                            }
                        }
                    }
                    return max;
                } else { // Lower
                    double max = 0.0;
                    for (long i = 0; i < n; i++) {
                        for (long j = 0; j <= i; j++) {
                            double v = Math.abs(a[(int) (i * lda + j)]);
                            if (Double.isNaN(v)) {
                                return Double.NaN;
                            }
                            if (v > max) {
                                max = v;
                            }
                        }
                    }
                    return max;
                }

            case MaxRowSum:
            case MaxColumnSum:
                // Initialize work array to zero
                for (int i = 0; i < work.length; i++) {
                    work[i] = 0.0;
                }
                if (uplo == Uplo.Upper) {
                    for (long i = 0; i < n; i++) {
                        work[(int) i] += Math.abs(a[(int) (i * lda + i)]);
                        for (long j = i + 1; j < n; j++) {
                            double v = Math.abs(a[(int) (i * lda + j)]);
                            work[(int) i] += v;
                            work[(int) j] += v;
                        }
                    }
                } else { // Lower
                    for (long i = 0; i < n; i++) {
                        for (long j = 0; j < i; j++) {
                            double v = Math.abs(a[(int) (i * lda + j)]);
                            work[(int) i] += v;
                            work[(int) j] += v;
                        }
                        work[(int) i] += Math.abs(a[(int) (i * lda + i)]);
                    }
                }
                double max = 0.0;
                for (int i = 0; i < work.length; i++) {
                    double v = work[i];
                    if (Double.isNaN(v)) {
                        return Double.NaN;
                    }
                    if (v > max) {
                        max = v;
                    }
                }
                return max;

            case Frobenius:
                throw new UnsupportedOperationException("not implemented"); // TODO

            default:
                throw new IllegalArgumentException("invalid norm");
        }
    }
}

