func dlansy(norm: MatrixNorm, uplo: Uplo, n: Int64, a: Array<Float64>, lda: Int64): Float64 {
    if (n == 0) {
        return 0.0
    }
    let work = Array<Float64>(n, repeat: 0.0)
    match {
        case norm == MaxAbs =>
            if (uplo == Upper) {
                var max = 0.0
                for (i in 0..n) {
                    for (j in i..n) {
                        let v = abs(a[i * lda + j])
                        if (v.isNaN()) {
                            return Float64.NaN
                        }
                        if (v > max) {
                            max = v
                        }
                    }
                }
                return max
            }
            var max = 0.0
            for (i in 0..n) {
                for (j in 0..=i) {
                    let v = abs(a[i * lda + j])
                    if (v.isNaN()) {
                        return Float64.NaN
                    }
                    if (v > max) {
                        max = v
                    }
                }
            }
            return max
        case norm == MaxRowSum || norm == MaxColumnSum =>
            for (i in 0..n) {
                work[i] = 0.0
            }
            if (uplo == Upper) {
                for (i in 0..n) {
                    work[i] += abs(a[i * lda + i])
                    for (j in i + 1..n) {
                        let v = abs(a[i * lda + j])
                        work[i] += v
                        work[j] += v
                    }
                }
            } else {
                for (i in 0..n) {
                    for (j in 0..i) {
                        let v = abs(a[i * lda + j])
                        work[i] += v
                        work[j] += v
                    }
                    work[i] += abs(a[i * lda + i])
                }
            }
            var max = 0.0
            for (i in 0..n) {
                let v = work[i]
                if (v.isNaN()) {
                    return Float64.NaN
                }
                if (v > max) {
                    max = v
                }
            }
            return max
        case norm == Frobenius => throw Exception("not implemented") // TODO
        case _ => throw Exception("invalid norm")
    }
}

