        if (length != longNameData.size) {
            let l: Array<Byte> = Array<Byte>(length, repeat: 0)
            ArrayCopy(longNameData, 0, l, 0, length)
            longNameData = l
        }
        return longNameData
    }

    private func getRecord(): ?Array<Byte> {
        var headerBuf: ?Array<Byte> = this.readRecord()
        this.setAtEOF(this.isEOFRecord(headerBuf))
        if (this.isAtEOF()) {
            match (headerBuf) {
                case None => ()
                case _ =>
                    this.tryToConsumeSecondEOFRecord()
                    this.consumeRemainderOfLastBlock()
                    headerBuf = None
            }
        }
        return headerBuf
    }

    protected func isEOFRecord(record: ?Array<Byte>): Bool {
        return match(record) {
            case Some(v) => ArchiveUtils.isArrayZero(v, this.recordSize)
            case None => true
        }
    }

    protected func readRecord(): ?Array<Byte> {
        let readNow: Int64 = this.inputStream.read(this.recordBuffer)
        this.count(readNow)
        if (readNow != this.recordSize) {
            return None
        }
        return this.recordBuffer
    }

    private func readGlobalPaxHeaders(): Unit {
        this.globalPaxHeaders = TarUtils.parsePaxHeaders(this, this.globalSparseHeaders, this.globalPaxHeaders, this.entrySize)
        this.getNextEntry()

        match(this.currEntry) {
            case None => throw Exception("Error detected parsing the pax header")
            case _ => ()
        }
    }

    private func paxHeaders(): Unit {
        var sparseHeaders: ArrayList<TarArchiveStructSparse> = ArrayList<TarArchiveStructSparse>()
        let headers: Map<String, String> = TarUtils.parsePaxHeaders(this, sparseHeaders, this.globalPaxHeaders, this.entrySize)
        if (headers.contains("GNU.sparse.map")) {
            sparseHeaders = TarUtils.parseFromPAX01SparseHeaders(headers["GNU.sparse.map"])
        }
        this.getNextEntry()
        this.currEntry.getOrThrow({=>
            throw Exception("premature end of tar archive. Didn't find any entry after PAX header.")
        })
        this.applyPaxHeadersToCurrentEntry(headers, sparseHeaders)

        if (this.currEntry.getOrThrow().isPaxGNU1XSparse()) {
            sparseHeaders = TarUtils.parsePAX1XSparseHeaders(this.inputStream, this.recordSize)
            this.currEntry.getOrThrow().setSparseHeaders(sparseHeaders)
        }

        this.buildSparseInputStreams()
    }

    private func applyPaxHeadersToCurrentEntry(headers: Map<String, String>, sparseHeaders: ArrayList<TarArchiveStructSparse>): Unit {
        this.currEntry.getOrThrow().updateEntryFromPaxHeaders(headers)
        this.currEntry.getOrThrow().setSparseHeaders(sparseHeaders)
    }

    private func readOldGNUSparse(): Unit {
        if (this.currEntry.getOrThrow().isExtendedFollows()) {
            var entry: ?TarArchiveSparseEntry = None
            do {
                let headerBuf: ?Array<Byte> = this.getRecord()
                if (headerBuf.isNone()) {
                    throw Exception("premature end of tar archive. Didn't find extended_header after header with extended flag.")
                }
                entry = TarArchiveSparseEntry(headerBuf.getOrThrow())
                this.currEntry.getOrThrow().getSparseHeaders().add(all: entry.getOrThrow().getSparseHeaders())
            } while (entry.getOrThrow().isExtendedFollows())
        }

        this.buildSparseInputStreams()
    }

    private func isDirectory(): Bool {
        return match(this.currEntry) {
            case Some(v) => v.isDirectory()
            case None => false
        }
    }

    public override func getNextEntry(): ?ArchiveEntry {
        return match(this.getNextTarEntry()) {
            case None => None
            case Some(v) => Option<ArchiveEntry>.Some(v)
        }
    }

    private func tryToConsumeSecondEOFRecord(): Unit {
    }

    public func readBytesOffset(buf: Array<Byte>, offset: Int64, numToRead: Int64): Int64 {
        if (numToRead == 0) {
            return 0
        }
        var totalRead: Int64 = 0

        if (this.isAtEOF() || this.isDirectory()) {
            return 0
        }

        match (this.currEntry) {
            case None => throw IllegalArgumentException("No current tar entry")
            case _ => ()
        }
        if (this.entryOffset >= this.currEntry.getOrThrow().getRealSize()) {
            return 0
        }

        let numToReads = min(numToRead, this.available())

        if (this.currEntry.getOrThrow().isSparse()) {
            totalRead = this.readSparse(buf, offset, numToReads)
        } else {
            totalRead = this.inputStream.read(buf[offset..numToReads])
        }

        if (totalRead == 0) {
            if (numToReads > 0) {
                throw Exception("Truncated TAR archive")
            }
            this.setAtEOF(true)
        } else {
            this.count(totalRead)
            this.entryOffset += totalRead
        }

        return totalRead
    }

    private func readSparse(buf: Array<Byte>, offset: Int64, numToRead: Int64): Int64 {
        if (this.sparseInputStreams.size == 0) {
            return this.inputStream.read(buf[offset..offset+numToRead])
        }
        if (this.currentSparseInputStreamIndex >= this.sparseInputStreams.size) {
            return -1
        }
        let currentInputStream: InputStream = this.sparseInputStreams[this.currentSparseInputStreamIndex]
        let readLen: Int64 = currentInputStream.read(buf[offset..offset+numToRead])
        if (this.currentSparseInputStreamIndex == this.sparseInputStreams.size - 1) {
            return readLen
        }
        if (readLen == -1) {
            this.currentSparseInputStreamIndex++
            return this.readSparse(buf, offset, numToRead)
        }
        if (readLen < numToRead) {
            this.currentSparseInputStreamIndex++
            let readLenOfNext: Int64 = this.readSparse(buf, offset + readLen, numToRead - readLen)
            if (readLenOfNext == -1) {
                return readLen
            }
            return readLen + readLenOfNext
        }
        return readLen
    }

    public func canReadEntryData(ae: ArchiveEntry): Bool {
        return ae is TarArchiveEntry
    }

    public override func close(): Unit {
        for (i in this.sparseInputStreams) {
            if (let Some(v) <- (i as Resource)) {
                v.close()
            }
        }
        (this.inputStream as Resource)?.close()
        this.isclosed = true
    }

    public func getCurrentEntry(): TarArchiveEntry {
        return this.currEntry.getOrThrow()
    }

    protected func setCurrentEntry(e: TarArchiveEntry): Unit {
        this.currEntry = e
    }

    protected func isAtEOF(): Bool {
        return this.hasHitEOF
    }

    protected func setAtEOF(b: Bool): Unit {
        this.hasHitEOF = b
    }

    private func consumeRemainderOfLastBlock(): Unit {
        let bytesReadOfLastBlock: Int64 = getBytesRead() % blockSize
        if (bytesReadOfLastBlock > 0) {
            let skipped: Int64 = skip(inputStream, blockSize - bytesReadOfLastBlock)
            this.count(skipped)
        }
    }

    private func buildSparseInputStreams(): Unit {
        this.currentSparseInputStreamIndex = -1
        this.sparseInputStreams = ArrayList<InputStream>()

        let sparseHeaders: Array<TarArchiveStructSparse> = this.currEntry.getOrThrow().getOrderedSparseHeaders()

        let zeroInputStream: InputStream = TarArchiveSparseZeroInputStream()
        var offset: Int64 = 0
        for (sparseHeader in sparseHeaders) {
            let zeroBlockSize: Int64 = sparseHeader.getOffset() - offset
            if (zeroBlockSize < 0) {
                throw Exception("Corrupted struct sparse detected")
            }

            if (zeroBlockSize > 0) {
                this.sparseInputStreams.add(BoundedInputStream(zeroInputStream, sparseHeader.getOffset() - offset))
            }

            if (sparseHeader.getNumbytes() > 0) {
                this.sparseInputStreams.add(BoundedInputStream(this.inputStream, sparseHeader.getNumbytes()))
            }

            offset = sparseHeader.getOffset() + sparseHeader.getNumbytes()
        }

        if (this.sparseInputStreams.size != 0) {
            this.currentSparseInputStreamIndex = 0
        }
    }
}

