public void rawWrite(long[] array, long byteOffset, long byteLength) {
    if (closed) {
        throw new java.io.IOException("Stream is closed");
    }
    // Check bounds: convert byte offsets to element indices (each int64 = 8 bytes)
    long startIndex = byteOffset / 8;
    long numElementsNeeded = (byteLength + 7) / 8; // ceiling division to get number of int64 elements
    if (startIndex < 0 || startIndex + numElementsNeeded > array.length) {
        throw new IllegalArgumentException("write length bigger than source array length");
    }

    long cursor = 0;
    while (cursor < byteLength) {
        long readLen = Math.min(byteLength - cursor, (long)(blockSize - inputCursor));
        if (readLen > 0) {
            long arrayIndex = byteOffset + cursor;
            if (arrayIndex < 0) {
                throw new ArrayIndexOutOfBoundsException("Array negative index access");
            }
            // Assuming SnappyNative.arrayCopyI64 maps to a native method copying int64s:
            // src: array, srcPos (in *elements*, so divide by 8), length (in *elements*), dst, dstPos (in *bytes*)
            SnappyNative.arrayCopyI64(array, (int)(arrayIndex / 8), (int)(readLen / 8), inputBuffer, (int)inputCursor);
            inputCursor += readLen;
        }
        if (inputCursor < blockSize) {
            return;
        }
        compressInput();
        cursor += readLen;
    }
}

