func rawWrite(array: Array<Int64>, byteOffset: Int64, byteLength: Int64): Unit {
        if (closed) {
            throw IOException("Stream is closed")
        }
        if ((byteOffset / 8 + byteLength / 8) > array.size) {
            throw IllegalArgumentException("write length bigger than source array length")
        }
        var cursor: Int64 = 0
        while (cursor < byteLength) {
            let readLen = min(byteLength - cursor, Int64(blockSize - inputCursor))
            if (readLen > 0) {
                if (byteOffset + cursor < 0) {
                    throw IndexOutOfBoundsException("Array negative index access")
                }
                SnappyNative.arrayCopyI64(array, UIntNative(byteOffset + cursor), UIntNative(readLen), inputBuffer,
                    UIntNative(inputCursor))
                inputCursor += Int64(readLen)
            }
            if (inputCursor < blockSize) {
                return
            }
            compressInput()
            cursor += readLen
        }
    }

