public class SmartRefreshForFlyRefresh {
    @Link
    var modelFly: SmartRefreshForFlyRefreshModel
    @BuilderParam
    var header: () -> Unit
    @BuilderParam
    var mainContent: () -> Unit
    @BuilderParam
    var footer: () -> Unit
    @State
    var needScroller: Bool = false
    @State
    var headerIsVisibleLoadMore: Bool = true
    @State
    var footerIsVisibleLoadMore: Bool = false
    var index: Int64 = 0

    func refreshClose(location: RefreshLocationEnum) {
        needScroller = true
        modelFly.refreshState = RefreshStateEnum.NONE
    }

    func binaryOperation(condition: Bool, leftOp: Float64, rightOp: Float64): Float64 {
        if (condition) {
            return leftOp
        }
        return rightOp
    }

    func binaryOperationVisibility(condition: Bool): Visibility {
        if (condition) {
            return Visibility.Visible
        }
        return Visibility.None
    }

    func build() {
        Column() {
            if (modelFly.expand) {
                Flex(FlexParams(alignItems: ItemAlign.End)) {
                    Text(modelFly.titleName).width(100.percent).fontColor(Color.WHITE).padding(30).fontSize(55)
                }.height(modelFly.tempTitleHeight).backgroundColor(modelFly.backgroundColor)
            }
            if (modelFly.flyRefreshHeaderIsShow) { // for FlyRefreshHeader
                Flex(FlexParams(alignItems: ItemAlign.End)) {
                    header()
                }.height(
                    binaryOperation(modelFly.headerHeight > modelFly.initHeaderHeight, modelFly.headerHeight,
                    modelFly.initHeaderHeight)).zIndex(modelFly.zHeaderIndex).backgroundColor(
                    modelFly.getBackgroundShadowColor())
            }
            Column() {
                Stack(Alignment.Top) {
                    if (!modelFly.fixedContent) {
                        Flex() {
                            header()
                        }.height(modelFly.headerHeight).zIndex(modelFly.zHeaderIndex).backgroundColor(
                            modelFly.getBackgroundShadowColor()).visibility(
                            binaryOperationVisibility(headerIsVisibleLoadMore))
                    }
                    Scroll(modelFly.scroller) {
                        Column() {
                            if (needScroller) { //重置Scroller
                                Text("0").visibility(Visibility.None)
                            } else {
                                Text("1").visibility(Visibility.None)
                            }
                            if (modelFly.fixedContent && !modelFly.flyRefreshHeaderIsShow) {
                                Flex() {
                                    header()
                                }.height(modelFly.headerHeight).zIndex(modelFly.zHeaderIndex).backgroundColor(
                                    modelFly.getBackgroundShadowColor()).visibility(
                                    binaryOperationVisibility(headerIsVisibleLoadMore))
                            }
                            Flex() {
                                mainContent()
                            }.zIndex(modelFly.zMainIndex)
                            Flex() {
                                footer()
                            }.height(modelFly.footerHeight).zIndex(modelFly.zFooterIndex).backgroundColor(
                                modelFly.getBackgroundShadowColor()).visibility(
                                binaryOperationVisibility(footerIsVisibleLoadMore))
                        }.width(100.percent)
                    }.scrollable(ScrollDirection.Vertical).scrollBar(BarState.Off).onScrollEdge(
                        {
                        edge => match (edge) {
                            case Edge.Top =>
                                modelFly.refreshHeaderCallbackState = true
                                modelFly.refreshBottomCallbackState = false
                                modelFly.scrollLocation = RefreshLocationEnum.HEAD
                            case Edge.Top =>
                                if (modelFly.dragArriveBottomEdgeState) {
                                    modelFly.dragArriveBottomEdgeState = false
                                    modelFly.refreshBottomCallbackState = true
                                    modelFly.refreshHeaderCallbackState = false
                                    modelFly.firstArriveBottomEdgeOffsetY = modelFly.scroller.currentOffset().yOffset
                                }
                                modelFly.scrollLocation = RefreshLocationEnum.FOOT
                            case _ => index++
                        }
                    }).onScroll(
                        {
                            offset =>
                            if (modelFly.fixedContent != modelFly.oldFixedContent) { //内容固定
                                needScroller = true
                                modelFly.oldFixedContent = modelFly.fixedContent
                            }
                            modelFly.latestYOffset = modelFly.scroller.currentOffset().yOffset
                            if (modelFly.initRefreshing) { //初始化刷新
                                scrollerInit()
                            }
                            scrollerEventFunction()
                        }
                    ).onScrollEnd(
                        {
                        => if (modelFly.scrollerEndState) {
                            modelFly.scrollerEndState = false
                            modelFly.scroller.scrollTo(
                                xOffset: 0.0,
                                yOffset: modelFly.scrollerEndYOffset,
                                duration: 10.0,
                                curve: Curve.Ease
                            )
                        }
                    }).onTouch({
                        event => touchEventFunction(event)
                    })
                }
            }
        }
    }

    func scrollerInit() {
        modelFly.initRefreshing = false
        headerIsVisibleLoadMore = true
        modelFly.headerHeight = modelFly.initHeaderHeight
        modelFly.refreshState = RefreshStateEnum.REFRESHING
        modelFly.scroller.scrollTo(
            xOffset: 0.px,
            yOffset: 0.px,
            duration: 10.0,
            curve: Curve.Ease
        )
        modelFly.refreshHeaderCallback()
        modelFly.refreshTimeOut = Timer.once(modelFly.refreshDuration) {
            =>
            headerIsVisibleLoadMore = false
            refreshClose(RefreshLocationEnum.HEAD)
            modelFly.refreshTimeOut = Option<Timer>.None
        }
    }

    func scrollerEventFunction() {
        if (modelFly.scrollLocation == RefreshLocationEnum.HEAD && needScroller) {
            closeHeaderRefresh()
            needScroller = false
            modelFly.scrollerEndYOffset = 0.0
            modelFly.scrollerEndState = true
            modelFly.scroller.scrollTo(
                xOffset: 0.px,
                yOffset: 0.px,
                duration: modelFly.toRefreshDuration,
                curve: Curve.Ease
            )
        }
    }

    func closeHeaderRefresh() {
        modelFly.refreshHeaderCallbackState = true
        modelFly.refreshBottomCallbackState = false
        modelFly.headerRefreshId?.cancel()
        modelFly.headerRefreshId = Option<Timer>.None
    }

    func closeFooterRefresh() {
        modelFly.refreshHeaderCallbackState = false
        modelFly.refreshBottomCallbackState = true
        modelFly.headerRefreshId?.cancel()
    }

    func binaryOperation(condition: Bool, leftOp: Bool, rightOp: Bool): Bool {
        if (condition) {
            return leftOp
        }
        return rightOp
    }

    func touchEventFunction(event: TouchEvent) {
        match (event.eventType) {
            case TouchType.Down =>
                modelFly.headerHeight = 210.0
                modelFly.initScrollerYOffset = modelFly.scroller.currentOffset().yOffset
                modelFly.scrollToEdgeStatus = true
                // 记录按下的y坐标
                modelFly.downY = event.touches[0].y
            case TouchType.Move =>
                modelFly.currentMouseX = event.touches[0].screenX
                modelFly.downYOffset = event.touches[0].y - modelFly.downY
                modelFly.dragDirection = binaryOperation(modelFly.downYOffset > 0.0, true, false)
                if (modelFly.dragDirection) {
                    if (modelFly.downYOffset > modelFly.initScrollerYOffset) {
                        headerIsVisibleLoadMore = true
                        footerIsVisibleLoadMore = false
                    }
                    if (modelFly.refreshHeaderCallbackState) {
                        modelFly.refreshHeaderCallbackState = false
                        modelFly.refreshHeaderCallback()
                    }
                    dragDownDirection_Move(event)
                } else { // 尾部刷新
                    if (modelFly.firstArriveBottomEdgeOffsetY == 0.0 || modelFly.scrollLocation != RefreshLocationEnum.
                        FOOT) { //第一次进入，高度为默认高度0
                        headerIsVisibleLoadMore = false
                        footerIsVisibleLoadMore = false
                    } else {
                        if (abs(modelFly.downYOffset) > (modelFly.firstArriveBottomEdgeOffsetY - modelFly.
                            initScrollerYOffset)) {
                            headerIsVisibleLoadMore = false
                            footerIsVisibleLoadMore = true
                        }
                    }
                    if (modelFly.refreshBottomCallbackState) {
                        modelFly.refreshBottomCallbackState = false
                        modelFly.refreshBottomCallback()
                    }
                    dragUpDirection_Move(event)
                }
            case TouchType.Up =>
                modelFly.downYOffset = event.touches[0].y - modelFly.downY
                if (modelFly.downYOffset > 0.0) {
                    dragDownDirection_UP(modelFly.downYOffset)
                } else if (modelFly.downYOffset < 0.0) {
                    dragUpDirection_UP(abs(modelFly.downYOffset))
                }
            case TouchType.Cancel => index++
            case _ => index--
        }
    }

    func dragDownDirection_Move(event: TouchEvent) {
        match (modelFly.refreshState) {
            case RefreshStateEnum.NONE => modelFly.refreshState = RefreshStateEnum.TO_REFRESH
            case RefreshStateEnum.TO_REFRESH =>
                if ((event.touches[0].y - modelFly.downY) > 0.0) { //下拉超过默认值
                    //下拉超出初始范围
                    modelFly.headerHeight = modelFly.initHeaderHeight + (pow(event.touches[0].y - modelFly.downY, 0.8))
                }
                modelFly.refreshState = RefreshStateEnum.TO_REFRESH
            case RefreshStateEnum.REFRESHING => if ((event.touches[0].y - modelFly.downY) > 0.0) { //刷新状态下拉
                modelFly.headerHeight = modelFly.initHeaderHeight + (pow(event.touches[0].y - modelFly.downY, 0.8))
            }
            case _ => index = 0
        }
    }

    func dragDownDirection_UP(downYOffsetParam: Float64) {
        if (modelFly.refreshState != RefreshStateEnum.NONE) {
            if (modelFly.refreshState == RefreshStateEnum.TO_REFRESH) {
                if (modelFly.headerHeight < modelFly.initHeaderHeight) { //未下滑到指定位置则不刷新(头部高度小于默认高度)
                    headerIsVisibleLoadMore = false //小于头部固定高度时，则隐藏头部
                    closeHeaderRefresh()
                    refreshClose(RefreshLocationEnum.HEAD)
                } else {
                    modelFly.headerHeight = modelFly.initHeaderHeight //重置头部高度
                    modelFly.scroller.scrollEdge(Edge.Start) //刷新，滑动至头部
                    modelFly.scrollerEndYOffset = 0.0
                    modelFly.scrollerEndState = true
                    modelFly.refreshState = RefreshStateEnum.REFRESHING //更改为刷新态
                    if (modelFly.refreshTimeOut == Option<Timer>.None) {
                        modelFly.refreshTimeOut = Timer.once(modelFly.refreshDuration) {
                            headerIsVisibleLoadMore = false
                            closeHeaderRefresh()
                            refreshClose(RefreshLocationEnum.HEAD)
                            modelFly.refreshTimeOut = Option<Timer>.None
                            modelFly.lastRefreshTime = DateTime.now()
                        }
                    }
                }
            } else if (modelFly.refreshState == RefreshStateEnum.REFRESHING) {
                modelFly.headerHeight = modelFly.initHeaderHeight //重置头部高度
            }
        }
    }

    func dragUpDirection_Move(event: TouchEvent) {
        var dragOffsetY = abs(event.touches[0].y - modelFly.downY)
        if (modelFly.footerHeight < modelFly.initFooterHeight && modelFly.refreshState != RefreshStateEnum.REFRESHING) {
            modelFly.footerHeight = dragOffsetY
        } else {
            if (modelFly.refreshState != RefreshStateEnum.REFRESHING
                && (modelFly.downY - event.touches[0].y) > 0.0 && dragOffsetY > modelFly.initFooterHeight) { //非刷新状态上拉
                modelFly.footerHeight = modelFly.initFooterHeight + pow(dragOffsetY - modelFly.initFooterHeight, 0.8)
                modelFly.refreshState = RefreshStateEnum.TO_REFRESH
            }
            if (modelFly.refreshState == RefreshStateEnum.REFRESHING && dragOffsetY > 0.0) { //刷新状态下拉
                modelFly.footerHeight = modelFly.initFooterHeight + pow(dragOffsetY, 0.8)
            }
        }
    }

    func dragUpDirection_UP(downYOffsetParam: Float64) {
        if (modelFly.refreshState != RefreshStateEnum.NONE) {
            if (modelFly.refreshState == RefreshStateEnum.TO_REFRESH) {
                if (downYOffsetParam <= modelFly.initFooterHeight / 2.0) { //未下滑到指定位置则不刷新
                    footerIsVisibleLoadMore = false //小于尾部固定高度时，则隐藏尾部
                    refreshClose(RefreshLocationEnum.HEAD)
                } else {
                    modelFly.footerHeight = modelFly.initFooterHeight //重置尾部高度
                    modelFly.scroller.scrollEdge(Edge.Bottom)
                    modelFly.refreshState = RefreshStateEnum.REFRESHING //更改为刷新态
                    if (modelFly.refreshTimeOut == Option<Timer>.None) {
                        modelFly.refreshTimeOut = Timer.once(modelFly.refreshDuration) {
                            footerIsVisibleLoadMore = false
                            refreshClose(RefreshLocationEnum.HEAD)
                            modelFly.refreshTimeOut = Option<Timer>.None
                            modelFly.lastRefreshTime = DateTime.now()
                        }
                    }
                }
            } else if (modelFly.refreshState == RefreshStateEnum.REFRESHING) {
                modelFly.footerHeight = modelFly.initFooterHeight //重置尾部高度
            }
        }
    }
}

