public static class HttpResponseHeaderCheckResult {
    public final Long contentLength;
    public final boolean chunked;

    public HttpResponseHeaderCheckResult(Long contentLength, boolean chunked) {
        this.contentLength = contentLength;
        this.chunked = chunked;
