/**
 * Creates a diagonal matrix from a vector.
 * The vector elements become the diagonal entries of the resulting square matrix.
 *
 * @param <T> the numeric type, must be a subclass of Number (handled via generic constraints in Java using bounded wildcards or runtime checks)
 * @param a the input vector
 * @return a square matrix with the vector elements on the main diagonal
 */
public static <T extends Number> Matrix<T> diag(Vector<T> a) {
    int n = a.size();
    Matrix<T> res = Matrix.zeros(n, n);
    for (int i = 0; i < n; i++) {
        res.set(i, i, a.get(i));
    }
    return res;
}

