    void test13() {
        BigMoney m1 = new BigMoney("-22452352345432532223444444444444444444444444423452314.024555555555551243253253252325", "PHP");
        BigMoney m2 = new BigMoney("-11431455312451342144245325256476543252356.324353242452345432453253288", "TJS");

        assertThrows(CurrencyNotSameException.class, () -> {
            calculate(m1, m2, "modulus");
        });
    }

    @Test
    void test14() {
        BigMoney m1 = new BigMoney("-22452352345432532223444444444444444444444444423452314.024555555555551243253253252325", "TJS");
        BigMoney m2 = new BigMoney("0", "TJS");

        assertThrows(IllegalArgumentException.class, () -> {
            calculate(m1, m2, "modulus");
        });
