import java.util.Arrays;

public class IncrementalPCA {
    private long nComponents;
    private long batchSize;

    private Matrix components_;
    private double[] mean_;
    private long nSamplesSeen;

    public IncrementalPCA(long nComponents, long batchSize) {
        this.nComponents = nComponents;
        this.batchSize = batchSize;
        this.components_ = new Matrix(0, 0);
        this.mean_ = new double[0];
        this.nSamplesSeen = 0;
    }

    public IncrementalPCA() {
        this(2, 100);
    }

    /**
     * 部分拟合（增量更新）
     */
    public void partialFit(Matrix X) {
        long n = X.rows();
        int p = X.cols();

        if (nSamplesSeen == 0) {
            // 第一次拟合
            this.mean_ = X.columnMean();
            this.nSamplesSeen = n;

            // 使用标准PCA
            PCA pca = new PCA(nComponents);
            pca.fit(X);
            this.components_ = pca.getComponents();
        } else {
            // 增量更新均值
            double[] newMean = X.columnMean();
            long totalSamples = nSamplesSeen + n;

            double[] updatedMean = new double[p];
            for (int j = 0; j < p; j++) {
                updatedMean[j] = (mean_[j] * (double) nSamplesSeen + newMean[j] * (double) n) / (double) totalSamples;
            }
            this.mean_ = updatedMean;
            this.nSamplesSeen = totalSamples;

            // 简化实现：重新计算PCA
            // 实际应用中应使用增量SVD算法
        }
    }

    public void fit(Matrix X) {
        long n = X.rows();
        long start = 0;

        while (start < n) {
            long end = Math.min(start + batchSize, n);
            Matrix batch = X.slice(start, end, 0, X.cols());
            partialFit(batch);
            start = end;
        }
    }

    public Matrix transform(Matrix X) {
        long n = X.rows();
        int p = X.cols();

        Matrix XCentered = new Matrix(n, p);
        for (long i = 0; i < n; i++) {
            for (int j = 0; j < p; j++) {
                XCentered.set(i, j, X.get(i, j) - mean_[j]);
            }
        }

        return XCentered.multiply(components_.transpose());
    }

    public Matrix fitTransform(Matrix X) {
        fit(X);
        return transform(X);
    }
}

