public class IncrementalPCA {
    private var nComponents: Int64
    private var batchSize: Int64

    private var components_: Matrix = Matrix(0, 0)
    private var mean_: Array<Float64> = Array<Float64>()
    private var nSamplesSeen: Int64 = 0

    public init(nComponents!: Int64 = 2, batchSize!: Int64 = 100) {
        this.nComponents = nComponents
        this.batchSize = batchSize
    }

    /**
     * 部分拟合（增量更新）
     */
    public func partialFit(X: Matrix): Unit {
        let n = X.rows
        let p = X.cols

        if (nSamplesSeen == 0) {
            // 第一次拟合
            mean_ = X.columnMean()
            nSamplesSeen = n

            // 使用标准PCA
            let pca = PCA(nComponents: nComponents)
            pca.fit(X)
            components_ = pca.getComponents()
        } else {
            // 增量更新均值
            let newMean = X.columnMean()
            let totalSamples = nSamplesSeen + n

            var updatedMean = Array<Float64>(p, repeat: 0.0)
            for (j in 0..p) {
                updatedMean[j] = (mean_[j] * Float64(nSamplesSeen) + newMean[j] * Float64(n)) / Float64(totalSamples)
            }
            mean_ = updatedMean
            nSamplesSeen = totalSamples

            // 简化实现：重新计算PCA
            // 实际应用中应使用增量SVD算法
        }
    }

    public func fit(X: Matrix): Unit {
        let n = X.rows
        var start: Int64 = 0

        while (start < n) {
            let end = min(start + batchSize, n)
            let batch = X.slice(start, end, 0, X.cols)
            partialFit(batch)
            start = end
        }
    }

    public func transform(X: Matrix): Matrix {
        let n = X.rows

        var XCentered = Matrix(n, X.cols)
        for (i in 0..n) {
            for (j in 0..X.cols) {
                XCentered.set(i, j, X.get(i, j) - mean_[j])
            }
        }

        return XCentered.multiply(components_.transpose())
    }

    public func fitTransform(X: Matrix): Matrix {
        fit(X)
        return transform(X)
    }
}

