import java.time.Instant;
import java.util.*;

public class Meter {
    private final String name;
    private final String version;
    private final Map<String, Counter> counters;
    private final Map<String, Histogram> histograms;
    private final Map<String, UpDownCounter> upDownCounters;
    private final Map<String, ObservableCounter> observableCounters;
    private final Map<String, ObservableGauge> observableGauges;

    public Meter(String name) {
        this(name, "1.0.0");
    }

    public Meter(String name, String version) {
        this.name = Objects.requireNonNull(name);
        this.version = Objects.requireNonNullElse(version, "1.0.0");
        this.counters = new HashMap<>();
        this.histograms = new HashMap<>();
        this.upDownCounters = new HashMap<>();
        this.observableCounters = new HashMap<>();
        this.observableGauges = new HashMap<>();
    }

    public Counter createCounter(String name, String description, String unit) {
        Counter counter = counters.get(name);
        if (counter != null) {
            return counter;
        }
        counter = new Counter(name, description, unit);
        counters.put(name, counter);
        return counter;
    }

    public Histogram createHistogram(String name, String description, String unit) {
        Histogram histogram = histograms.get(name);
        if (histogram != null) {
            return histogram;
        }
        histogram = new Histogram(name, description, unit);
        histograms.put(name, histogram);
        return histogram;
    }

    public UpDownCounter createUpDownCounter(String name, String description, String unit) {
        UpDownCounter counter = upDownCounters.get(name);
        if (counter != null) {
            return counter;
        }
        counter = new UpDownCounter(name, description, unit);
        upDownCounters.put(name, counter);
        return counter;
    }

    public ObservableCounter createObservableCounter(String name, String description, String unit) {
        ObservableCounter counter = observableCounters.get(name);
        if (counter != null) {
            return counter;
        }
        counter = new ObservableCounter(name, description, unit);
        observableCounters.put(name, counter);
        return counter;
    }

    public ObservableGauge createObservableGauge(String name, String description, String unit) {
        ObservableGauge gauge = observableGauges.get(name);
        if (gauge != null) {
            return gauge;
        }
        gauge = new ObservableGauge(name, description, unit);
        observableGauges.put(name, gauge);
        return gauge;
    }

    public List<MetricData> collectMetrics() {
        // Capture a point-in-time snapshot of all instruments for this meter.
        List<MetricData> metrics = new ArrayList<>();
        long collectionTime = Instant.now().getEpochSecond() * 1_000_000_000L; // nanoseconds

        for (Counter counter : counters.values()) {
            metrics.addAll(buildCounterMetrics(counter, collectionTime));
        }

        for (UpDownCounter counter : upDownCounters.values()) {
            metrics.addAll(buildUpDownCounterMetrics(counter, collectionTime));
        }

        for (Histogram histogram : histograms.values()) {
            metrics.addAll(buildHistogramMetrics(histogram, collectionTime));
        }

        for (ObservableCounter observableCounter : observableCounters.values()) {
            metrics.addAll(buildObservableCounterMetrics(observableCounter, collectionTime));
        }

        for (ObservableGauge observableGauge : observableGauges.values()) {
            metrics.addAll(buildObservableGaugeMetrics(observableGauge, collectionTime));
        }

        return metrics;
    }

    public Optional<OtlpScopeMetrics> collectScopeMetrics() {
        // Capture a point-in-time snapshot of all instruments for this meter.
        List<OtlpMetric> metrics = new ArrayList<>();
        long collectionTime = Instant.now().getEpochSecond() * 1_000_000_000L; // nanoseconds

        for (Counter counter : counters.values()) {
            Optional<OtlpMetric> metric = buildCounterMetric(counter, collectionTime);
            metric.ifPresent(metrics::add);
        }

        for (UpDownCounter counter : upDownCounters.values()) {
            Optional<OtlpMetric> metric = buildUpDownCounterMetric(counter, collectionTime);
            metric.ifPresent(metrics::add);
        }

        for (Histogram histogram : histograms.values()) {
            Optional<OtlpMetric> metric = buildHistogramMetric(histogram, collectionTime);
            metric.ifPresent(metrics::add);
        }

        for (ObservableCounter observableCounter : observableCounters.values()) {
            Optional<OtlpMetric> metric = buildObservableCounterMetric(observableCounter, collectionTime);
            metric.ifPresent(metrics::add);
        }

        for (ObservableGauge observableGauge : observableGauges.values()) {
            Optional<OtlpMetric> metric = buildObservableGaugeMetric(observableGauge, collectionTime);
            metric.ifPresent(metrics::add);
        }

        if (metrics.isEmpty()) {
            return Optional.empty();
        }

        OtlpInstrumentationScope scope = new OtlpInstrumentationScope();
        scope.setName(name);
        scope.setVersion(version);

        OtlpScopeMetrics scopeMetrics = new OtlpScopeMetrics();
        scopeMetrics.setScope(scope);
        scopeMetrics.setMetrics(metrics);
        return Optional.of(scopeMetrics);
    }

    private Optional<OtlpMetric> buildCounterMetric(Counter counter, long collectionTime) {
        Map<String, Double> totals = counter.getAttributeTotals();
        if (totals.isEmpty()) {
            return Optional.empty();
        }

        // Convert each attribute combination into an OTLP number data point.
        List<OtlpNumberDataPoint> dataPoints = new ArrayList<>();
        for (Map.Entry<String, Double> entry : totals.entrySet()) {
            Map<String, String> attributes = OtlpJsonUtils.decodeAttributeKey(entry.getKey());
            List<OtlpKeyValue> otlpAttributes = OtlpJsonUtils.mapStringAttributes(attributes);
            dataPoints.add(createNumberDataPoint(counter.getStartTimeUnixNano(), collectionTime, entry.getValue(), otlpAttributes));
        }

        OtlpSum sum = new OtlpSum();
        sum.setDataPoints(dataPoints);
        sum.setAggregationTemporality("AGGREGATION_TEMPORALITY_CUMULATIVE");
        sum.setIsMonotonic(true);

        OtlpMetric metric = new OtlpMetric();
        metric.setName(counter.getName());
        metric.setDescription(counter.getDescription());
        metric.setUnit(counter.getUnit());
        metric.setSum(sum);
        return Optional.of(metric);
    }

    private Optional<OtlpMetric> buildUpDownCounterMetric(UpDownCounter counter, long collectionTime) {
        List<OtlpNumberDataPoint> dataPoints = new ArrayList<>();
        dataPoints.add(createNumberDataPoint(counter.getStartTimeUnixNano(), collectionTime, counter.getValue(), new ArrayList<>()));

        OtlpSum sum = new OtlpSum();
        sum.setDataPoints(dataPoints);
        sum.setAggregationTemporality("AGGREGATION_TEMPORALITY_CUMULATIVE");
        sum.setIsMonotonic(false);

        OtlpMetric metric = new OtlpMetric();
        metric.setName(counter.getName());
        metric.setDescription(counter.getDescription());
        metric.setUnit(counter.getUnit());
        metric.setSum(sum);
        return Optional.of(metric);
    }

    private Optional<OtlpMetric> buildObservableCounterMetric(ObservableCounter counter, long collectionTime) {
        double value = safeObserve(counter::read);
        List<OtlpNumberDataPoint> dataPoints = new ArrayList<>();
        dataPoints.add(createNumberDataPoint(counter.getStartTimeUnixNano(), collectionTime, value, new ArrayList<>()));

        OtlpSum sum = new OtlpSum();
        sum.setDataPoints(dataPoints);
        sum.setAggregationTemporality("AGGREGATION_TEMPORALITY_CUMULATIVE");
        sum.setIsMonotonic(true);

        OtlpMetric metric = new OtlpMetric();
        metric.setName(counter.getName());
        metric.setDescription(counter.getDescription());
        metric.setUnit(counter.getUnit());
        metric.setSum(sum);
        return Optional.of(metric);
    }

    private Optional<OtlpMetric> buildObservableGaugeMetric(ObservableGauge gauge, long collectionTime) {
        double value = safeObserve(gauge::read);
        List<OtlpNumberDataPoint> dataPoints = new ArrayList<>();
        dataPoints.add(createNumberDataPoint(gauge.getStartTimeUnixNano(), collectionTime, value, new ArrayList<>()));

        OtlpGauge otlpGauge = new OtlpGauge();
        otlpGauge.setDataPoints(dataPoints);

        OtlpMetric metric = new OtlpMetric();
        metric.setName(gauge.getName());
        metric.setDescription(gauge.getDescription());
        metric.setUnit(gauge.getUnit());
        metric.setGauge(otlpGauge);
        return Optional.of(metric);
    }

    private Optional<OtlpMetric> buildHistogramMetric(Histogram histogram, long collectionTime) {
        if (histogram.getCount() == 0) {
            return Optional.empty();
        }

        // Translate internal bucket map into ordered bucket counts for OTLP.
        Map<String, Long> bucketCountsMap = histogram.getBuckets();
        List<String> bucketCounts = new ArrayList<>();
        List<Double> explicitBounds = new ArrayList<>();
        for (double bound : histogram.getBucketBoundaries()) {
            explicitBounds.add(bound);
            String countStr = Optional.ofNullable(bucketCountsMap.get(Double.toString(bound)))
                    .map(Long::toString)
                    .orElse("0");
            bucketCounts.add(countStr);
        }
        String infCountStr = Optional.ofNullable(bucketCountsMap.get("+Inf"))
                .map(Long::toString)
                .orElse("0");
        bucketCounts.add(infCountStr);

        OtlpHistogramDataPoint dataPoint = new OtlpHistogramDataPoint();
        dataPoint.setStartTimeUnixNano(String.valueOf(histogram.getStartTimeUnixNano()));
        dataPoint.setTimeUnixNano(String.valueOf(collectionTime));
        dataPoint.setCount(String.valueOf(histogram.getCount()));
        dataPoint.setSum(histogram.getSum());
        dataPoint.setBucketCounts(bucketCounts);
        dataPoint.setExplicitBounds(explicitBounds);
        dataPoint.setFlags("0");
        dataPoint.setAttributes(new ArrayList<>());
        dataPoint.setMin(histogram.getMinValue());
        dataPoint.setMax(histogram.getMaxValue());

        List<OtlpHistogramDataPoint> dataPoints = new ArrayList<>();
        dataPoints.add(dataPoint);

        OtlpHistogram otlpHistogram = new OtlpHistogram();
        otlpHistogram.setDataPoints(dataPoints);
        otlpHistogram.setAggregationTemporality("AGGREGATION_TEMPORALITY_CUMULATIVE");

        OtlpMetric metric = new OtlpMetric();
        metric.setName(histogram.getName());
        metric.setDescription(histogram.getDescription());
        metric.setUnit(histogram.getUnit());
        metric.setHistogram(otlpHistogram);
        return Optional.of(metric);
    }

    private OtlpNumberDataPoint createNumberDataPoint(long startTime, long collectionTime, double value, List<OtlpKeyValue> attributes) {
        OtlpNumberDataPoint point = new OtlpNumberDataPoint();
        point.setStartTimeUnixNano(String.valueOf(startTime));
        point.setTimeUnixNano(String.valueOf(collectionTime));
        point.setAttributes(attributes);
        point.setFlags("0");
        point.setAsDouble(value);
        return point;
    }

    private double safeObserve(Supplier<Double> callback) {
        try {
            return callback.get();
        } catch (Exception ex) {
            return 0.0;
        }
    }

    // Helper methods to build MetricData objects
    private List<MetricData> buildCounterMetrics(Counter counter, long collectionTime) {
        List<MetricData> metrics = new ArrayList<>();
        Map<String, Double> totals = counter.getAttributeTotals();

        for (Map.Entry<String, Double> entry : totals.entrySet()) {
            Map<String, String> attributes = OtlpJsonUtils.decodeAttributeKey(entry.getKey());
            Map<String, AttributeValue> metricAttributes = new HashMap<>();
            for (Map.Entry<String, String> attrEntry : attributes.entrySet()) {
                metricAttributes.put(attrEntry.getKey(), new AttributeValue.StringValue(attrEntry.getValue()));
            }

            MetricData metricData = new MetricData(
                    counter.getName(),
                    counter.getDescription(),
                    counter.getUnit(),
                    entry.getValue(),
                    metricAttributes,
                    collectionTime
            );
            metrics.add(metricData);
        }

        return metrics;
    }

    private List<MetricData> buildUpDownCounterMetrics(UpDownCounter counter, long collectionTime) {
        List<MetricData> metrics = new ArrayList<>();
        Map<String, AttributeValue> attributes = new HashMap<>();

        MetricData metricData = new MetricData(
                counter.getName(),
                counter.getDescription(),
                counter.getUnit(),
                counter.getValue(),
                attributes,
                collectionTime
        );
        metrics.add(metricData);

        return metrics;
    }

    private List<MetricData> buildObservableCounterMetrics(ObservableCounter counter, long collectionTime) {
        List<MetricData> metrics = new ArrayList<>();
        double value = safeObserve(counter::read);
        Map<String, AttributeValue> attributes = new HashMap<>();

        MetricData metricData = new MetricData(
                counter.getName(),
                counter.getDescription(),
                counter.getUnit(),
                value,
                attributes,
                collectionTime
        );
        metrics.add(metricData);

        return metrics;
    }

    private List<MetricData> buildObservableGaugeMetrics(ObservableGauge gauge, long collectionTime) {
        List<MetricData> metrics = new ArrayList<>();
        double value = safeObserve(gauge::read);
        Map<String, AttributeValue> attributes = new HashMap<>();

        MetricData metricData = new MetricData(
                gauge.getName(),
                gauge.getDescription(),
                gauge.getUnit(),
                value,
                attributes,
                collectionTime
        );
        metrics.add(metricData);

        return metrics;
    }

    private List<MetricData> buildHistogramMetrics(Histogram histogram, long collectionTime) {
        List<MetricData> metrics = new ArrayList<>();

        if (histogram.getCount() > 0) {
            Map<String, AttributeValue> attributes = new HashMap<>();
            // For histogram, we export the count as the main value
            MetricData metricData = new MetricData(
                    histogram.getName() + "_count",
                    histogram.getDescription() + " (count)",
                    histogram.getUnit(),
                    (double) histogram.getCount(),
                    attributes,
                    collectionTime
            );
            metrics.add(metricData);

            // Also export the sum as a separate metric
            MetricData sumMetricData = new MetricData(
                    histogram.getName() + "_sum",
                    histogram.getDescription() + " (sum)",
                    histogram.getUnit(),
                    histogram.getSum(),
                    attributes,
                    collectionTime
            );
            metrics.add(sumMetricData);
        }

        return metrics;
    }
}

