import java.io.InputStream;
import java.nio.charset.StandardCharsets;
import java.util.*;

// Supporting types (minimal stubs for compilation; real impl would be richer)
class XmlEvent {}
class XmlDeserializable<T> {
    public static <T extends XmlDeserializable<T>> T fromXml(XmlReader reader) {
        throw new UnsupportedOperationException();
    }
}
class XmlException extends RuntimeException {
    public XmlException(String message) { super(message); }
}
class UnsupportedException extends UnsupportedOperationException {
    public UnsupportedException() { super(); }
}
class Position {}
class Namespace {}
class QName {
    final String name;
    final String prefix;
    final String namespace;
    QName(String name, String prefix, String namespace) {
        this.name = name;
        this.prefix = prefix;
        this.namespace = namespace;
    }
}
class Attribute {}
class EntityReference {
    final EntityDecl decl;
    EntityReference(EntityDecl decl) { this.decl = decl; }
}
class EntityDecl {
    final String value;
    EntityDecl(String value) { this.value = value; }
}
class DocTypeDecl {}

// Constants (reconstructed from BA_* byte arrays in仓颉)
final class XmlConstants {
    static final byte[] BA_XML_S = "xml".getBytes(StandardCharsets.US_ASCII);
    static final byte[] BA_DOCTYPE = "DOCTYPE".getBytes(StandardCharsets.US_ASCII);
    static final byte[] BA_CDATA_PRE = "[CDATA[".getBytes(StandardCharsets.US_ASCII);
    static final byte[] BA_DASH_DASH = "--".getBytes(StandardCharsets.US_ASCII);
    static final byte[] BA_EMPTY_TAG_END = "/>".getBytes(StandardCharsets.US_ASCII);
    static final byte[] BA_XMLNS = "xmlns".getBytes(StandardCharsets.US_ASCII);
    static final byte[] BA_CDATA_SUF = "]]>".getBytes(StandardCharsets.US_ASCII);
}

// Minimal BytesInputStream stub (assumes UTF-8, basic ops)
class BytesInputStream {
    private final InputStream in;
    private final List<Byte> buffer = new ArrayList<>();
    private int pos = 0;

    BytesInputStream(InputStream in) {
        this.in = in;
        // Pre-read all bytes (for simplicity; real impl may be lazy)
        try {
            int b;
            while ((b = in.read()) != -1) {
                buffer.add((byte) b);
            }
        } catch (java.io.IOException e) {
            throw new RuntimeException(e);
        }
    }

    byte get(int index) {
        return buffer.get(index);
    }

    boolean strcmp(int offset, byte[] pattern) {
        if (offset + pattern.length > buffer.size()) return false;
        for (int i = 0; i < pattern.length; i++) {
            if (buffer.get(offset + i) != pattern[i]) return false;
        }
        return true;
    }

    void skip(int n) {
        pos += n;
    }

    void skipBytes(java.util.function.Predicate<Byte> predicate) {
        while (pos < buffer.size() && predicate.test(buffer.get(pos))) {
            pos++;
        }
    }

    void skipIndex(java.util.function.Predicate<Integer> predicate) {
        while (pos < buffer.size() && predicate.test(pos)) {
            pos++;
        }
    }

    String readUntil(byte delimiter) {
        int start = pos;
        while (pos < buffer.size() && buffer.get(pos) != delimiter) {
            pos++;
        }
        String result = new String(
            buffer.subList(start, pos).stream().mapToObj(Byte::byteValue)
                .collect(ArrayList::new, (l, b) -> l.add(b), ArrayList::addAll)
                .stream().mapToByte(Byte::byteValue).toArray(),
            StandardCharsets.UTF_8
        );
        if (pos < buffer.size()) pos++; // skip delimiter
        return result;
    }

    String readUntil(java.util.function.BiPredicate<Byte, Integer> predicate) {
        int start = pos;
        while (pos < buffer.size() && !predicate.test(buffer.get(pos), pos)) {
            pos++;
        }
        String result = new String(
            buffer.subList(start, pos).stream().mapToObj(Byte::byteValue)
                .collect(ArrayList::new, (l, b) -> l.add(b), ArrayList::addAll)
                .stream().mapToByte(Byte::byteValue).toArray(),
            StandardCharsets.UTF_8
        );
        return result;
    }

    String readName() {
        int start = pos;
        while (pos < buffer.size()) {
            byte b = buffer.get(pos);
            if (!isNameChar(b)) break;
            pos++;
        }
        return new String(
            buffer.subList(start, pos).stream().mapToObj(Byte::byteValue)
                .collect(ArrayList::new, (l, b) -> l.add(b), ArrayList::addAll)
                .stream().mapToByte(Byte::byteValue).toArray(),
            StandardCharsets.UTF_8
        );
    }

    private boolean isNameChar(byte b) {
        return (b >= 'a' && b <= 'z') || (b >= 'A' && b <= 'Z') || b == '_' || b == ':' ||
               (b >= '0' && b <= '9') || b == '-' || b == '.';
    }
}

enum Status {
    Init,
    EOF,
    MarkupClose,
    Decl,
    ProcInst,
    DTD,
    CData,
    Comment,
    ElementStart,
    ElementEnd,
    ElementEmpty,
    Text,
    Attribute,
    Namespace,
    EntityRef;

    XmlEvent toEvent() {
        // Stub — real impl would construct proper event
        return new XmlEvent();
    }

    void assert(Status expected) {
        if (this != expected) {
            throw new XmlException("Expected status " + expected + ", got " + this);
        }
    }

    boolean check(Status... allowed) {
        for (Status s : allowed) {
            if (this == s) return true;
        }
        return false;
    }
}

class Stack<T> {
    private final Deque<T> stack = new ArrayDeque<>();

    void push(T item) { stack.push(item); }
    T pop() { return stack.pop(); }
    T peek() { return stack.peek(); }
    boolean isEmpty() { return stack.isEmpty(); }
}

public class XmlReader {
    private Status status = Status.Init;
    private boolean readAfterLastPeek = false;
    private final Stack<String> stack = new Stack<>();

    private final BytesInputStream buf;

    public XmlReader(InputStream input) {
        this.buf = new BytesInputStream(input);
    }

    public <T extends XmlDeserializable<T>> T readObject() {
        // stash status
        Status stashStatus = status;
        boolean stashReadAfterLastPeek = readAfterLastPeek;

        // init status before read new Xml Object
        status = Status.Init;
        readAfterLastPeek = false;
        @SuppressWarnings("unchecked")
        T v = (T) XmlDeserializable.fromXml(this);

        // pop status
        status = stashStatus;
        readAfterLastPeek = stashReadAfterLastPeek;
        return v;
    }

    public Optional<XmlEvent> peek() {
        if (status == Status.EOF) {
            return Optional.empty();
        }

        if (status != Status.Init && !readAfterLastPeek) {
            return Optional.of(status.toEvent());
        }

        readUntilEvent();
        status = switch (buf.get(0)) {
            case (byte) '<' -> switch (buf.get(1)) {
                case (byte) '?' -> buf.strcmp(2, XmlConstants.BA_XML_S) ? Status.Decl : Status.ProcInst;
                case (byte) '!' -> {
                    if (buf.strcmp(2, XmlConstants.BA_DOCTYPE)) {
                        yield Status.DTD;
                    } else if (buf.strcmp(2, XmlConstants.BA_CDATA_PRE)) {
                        yield Status.CData;
                    } else if (buf.strcmp(2, XmlConstants.BA_DASH_DASH)) {
                        yield Status.Comment;
                    } else {
                        throw new XmlException("Unkonw xml token: " + buf);
                    }
                }
                case (byte) '/' -> Status.ElementEnd;
                default -> Status.ElementStart;
            };
            case (byte) '&' -> Status.EntityRef; // TODO predefined entity: lt/gt/amp/apos/quot
            default -> {
                if (status.check(Status.ElementStart, Status.Attribute, Status.Namespace)) {
                    if (buf.strcmp(0, XmlConstants.BA_EMPTY_TAG_END)) {
                        yield Status.ElementEmpty;
                    } else if (buf.strcmp(0, XmlConstants.BA_XMLNS)) {
                        yield Status.Namespace;
                    } else {
                        yield Status.Attribute;
                    }
                } else {
                    yield Status.Text;
                }
            }
        };

        readAfterLastPeek = false;
        return Optional.of(status.toEvent());
    }

    public void skip() {
        XmlEvent event = status.toEvent();
        switch (status) {
            case ElementStart -> readElementStart();
            case ElementEnd -> readElementEnd();
            case Text -> buf.skipBytes(b -> b != (byte) '<' && b != (byte) '&');
            case Attribute, Namespace -> {
                buf.skipBytes(b -> b != (byte) '\'' && b != (byte) '"');
                byte q = buf.get(0);
                buf.skip(1);
                buf.skipBytes(b -> b != q);
                buf.skip(1);
            }
            case Comment, Decl, ProcInst -> buf.skipBytes(b -> b != (byte) '>');
            case CData -> buf.skipIndex(i -> !buf.strcmp(i, XmlConstants.BA_CDATA_SUF)); // skip '<![CDATA['
            case EntityRef -> {
                buf.skipBytes(b -> b != (byte) ';');
                buf.skip(1); // skip ';'
            }
            case DTD -> readDTD();
            default -> throw new XmlException("Unexpected status: " + status);
        }
        readAfterLastPeek = true;
    }

    public Tuple3<String, Optional<String>, Optional<Boolean>> readDecl() {
        peek();
        status.assert(Status.Decl);
        buf.skipBytes(b -> b != (byte) 'v');

        String version = readValue("version");
        if (!"1.0".equals(version)) {
            throw new XmlException("Unsupported XML version: `" + version + "`.");
        }

        skipWhitespace();
        Optional<String> encoding = switch (buf.get(0)) {
            case (byte) 'e' -> Optional.of(readValue("encoding"));
            case (byte) 's', (byte) '?' -> Optional.empty();
            default -> throw new XmlException("Unsuppored XMLDecl expected `encoding or standalone` but found `" + buf + "`.");
        };
        if (encoding.isPresent()) {
            String enc = encoding.get();
            if (!enc.equalsIgnoreCase("utf-8")) {
                throw new XmlException("Unsupported XML encoding: `" + enc + "`.");
            }
        }

        skipWhitespace();
        Optional<Boolean> standalone = Optional.empty();
        Optional<String> standaloneStr = switch (buf.get(0)) {
            case (byte) 's' -> Optional.of(readValue("standalone"));
            case (byte) '?' -> Optional.empty();
            default -> throw new XmlException("Unsuppored XMLDecl expected `standalone` but found `" + buf + "`.");
        };
        if (standaloneStr.isPresent()) {
            String v = standaloneStr.get();
            if ("yes".equals(v)) {
                standalone = Optional.of(true);
            } else if ("no".equals(v)) {
                standalone = Optional.of(false);
            } else {
                throw new XmlException("Invalid value of `standalone`: `" + v + "`.");
            }
        }

        // skip '?>'
        skipWhitespace();
        readString("?>");

        readAfterLastPeek = true;
        return new Tuple3<>(version, encoding, standalone);
    }

    public String readElementText(String name, Optional<String> namespace) {
        readElementStart(name, namespace);
        buf.skipBytes(b -> b != (byte) '>' && b != (byte) '/'); // skip attributes
        String data = readText();
        readElementEnd(name, namespace);
        return data;
    }

    public void readElementStart(String name, Optional<String> namespace) {
        peek();
        status.assert(Status.ElementStart);
        buf.skip(1); // skip '<'
        readString(name);
        readAfterLastPeek = true;
        stack.push(name);
    }

    public void readElementEnd(String name, Optional<String> namespace) {
        if (!name.equals(stack.peek())) {
            throw new XmlException("Element name should be `" + stack.peek() + "`");
        }

        peek();

        // read empty element end tag
        if (status == Status.ElementEmpty) {
            buf.skip(2); // skip '/>'
            readAfterLastPeek = true;
            stack.pop();
            return;
        }

        // read EndTag
        status.assert(Status.ElementEnd);
        buf.skip(2); // skip '</'
        readString(name);
        skipWhitespace();
        readByte((byte) '>');
        readAfterLastPeek = true;
        stack.pop();

        // EOF
        if (stack.isEmpty()) {
            status = Status.EOF;
        }
    }

    public QName readElementStart() {
        peek();
        status.assert(Status.ElementStart);
        buf.skip(1); // skip '<'

        String name = buf.readName();

        readAfterLastPeek = true;
        stack.push(name);
        return new QName(name, null, null);
    }

    public QName readElementEnd() {
        peek();

        if (status == Status.ElementEmpty) {
            buf.skip(2); // skip '/>'
            readAfterLastPeek = true;
            return new QName(stack.pop(), null, null);
        }

        status.assert(Status.ElementEnd);
        buf.skip(2); // skip '</'

        String name = buf.readName();
        if (!name.equals(stack.peek())) {
            throw new XmlException("Failed to read XML element end tag, expect name `" + stack.peek() + "` but found `" + name + "`.");
        }

        readAfterLastPeek = true;
        stack.pop();

        // EOF
        if (stack.isEmpty()) {
            status = Status.EOF;
        }

        return new QName(name, null, null);
    }

    public String readText() {
        peek();
        if (status.check(Status.ElementEnd, Status.ElementEmpty)) {
            return "";
        }
        status.assert(Status.Text, Status.CData, Status.EntityRef);
        return switch (status) {
            case Text -> {
                String txt = doReadText();
                readAfterLastPeek = true;
                yield txt;
            }
            case CData -> readCData();
            default -> readEntityRef().decl.value;
        };
    }

    public String readCData() {
        peek();
        status.assert(Status.CData);
        buf.skip(9); // <![CDATA[

        String txt = buf.readUntil((b, i) -> b == (byte) ']' && buf.strcmp(i, XmlConstants.BA_CDATA_SUF));
        buf.skip(3); // ]]>

        readAfterLastPeek = true;
        return txt;
    }

    public Position getCurrentPosition() {
        throw new UnsupportedException();
    }

    public Optional<Namespace> getCurrentNamespace() {
        throw new UnsupportedException();
    }

    public String readComment() {
        throw new UnsupportedException();
    }

    public Tuple2<String, Optional<String>> readProcInst() {
        throw new UnsupportedException();
    }

    public DocTypeDecl readDTD() {
        throw new UnsupportedException();
    }

    public Attribute readAttribute() {
        throw new UnsupportedException();
    }

    public String readAttribute(String name, Optional<String> namespace) {
        throw new UnsupportedException();
    }

    public Tuple2<Optional<String>, String> readNamespace() {
        throw new UnsupportedException();
    }

    public EntityReference readEntityRef() {
        throw new UnsupportedException();
    }

    // TODO support xml:space="preserve"
    private void readUntilEvent() {
        skipWhitespace();
        if (buf.get(0) == (byte) '>') {
            status = Status.MarkupClose;
            buf.skip(1); // skip '>'
            skipWhitespace();
        }
    }

    private void skipWhitespace() {
        buf.skipBytes(b -> Character.isWhitespace((char) (b & 0xFF)));
    }

    private void readString(String str) {
        byte[] bytes = str.getBytes(StandardCharsets.US_ASCII);
        if (!buf.strcmp(0, bytes)) {
            throw new XmlException("Failed to read from `" + buf + "`, `" + str + "` was required.");
        }
        buf.skip(bytes.length);
    }

    private void readByte(byte b) {
        if (buf.get(0) != b) {
            throw new XmlException("Failed to read from `" + buf + "`, `" + ((char) b) + "` was required.");
        }
        buf.skip(1);
    }

    private String readValue(String name) {
        readString(name);
        readByte((byte) '=');

        String value = switch (buf.get(0)) {
            case (byte) '"' -> {
                buf.skip(1);
                yield buf.readUntil((byte) '"');
            }
            case (byte) '\'' -> {
                buf.skip(1);
                yield buf.readUntil((byte) '\'');
            }
            default -> throw new XmlException("Failed to read value of `" + name + "` from `" + buf + "`, `'` or `\"` was required.");
        };
        buf.skip(1);
        return value;
    }

    private String doReadText() {
        // TODO replace \r\n to \n， \r to \n
        return buf.readUntil(b -> b == (byte) '<' || b == (byte) '&');
    }

    // Helper tuple classes for multi-return
    static class Tuple2<A, B> {
        final A _1;
        final B _2;
        Tuple2(A _1, B _2) { this._1 = _1; this._2 = _2; }
    }

    static class Tuple3<A, B, C> {
        final A _1;
        final B _2;
        final C _3;
        Tuple3(A _1, B _2, C _3) { this._1 = _1; this._2 = _2; this._3 = _3; }
    }
}

