public class SqlArgFactory {
    public static <T> SqlArg newSqlArg(long index, T value) {
        if (value instanceof Boolean) {
            return new BoolSqlArg(index, (Boolean) value);
        } else if (value instanceof Byte) {
            // Note: Java byte is signed; assuming Int8 maps to byte
            return new Int8SqlArg(index, (Byte) value);
        } else if (value instanceof Short && ((Short) value) >= 0) {
            // Assuming UInt8 is represented as Short in range [0, 255]
            return new UInt8SqlArg(index, (Short) value);
        } else if (value instanceof Short) {
            return new Int16SqlArg(index, (Short) value);
        } else if (value instanceof Integer && ((Integer) value) >= 0) {
            // Assuming UInt16 is represented as Integer in range [0, 65535]
            return new UInt16SqlArg(index, (Integer) value);
        } else if (value instanceof Integer) {
            return new Int32SqlArg(index, (Integer) value);
        } else if (value instanceof Long && ((Long) value) >= 0) {
            // Assuming UInt32 is represented as Long in range [0, 4294967295]
            return new UInt32SqlArg(index, (Long) value);
        } else if (value instanceof Long) {
            return new Int64SqlArg(index, (Long) value);
        } else if (value instanceof java.math.BigInteger) {
            // Assuming UInt64 maps to BigInteger for full range
            return new UInt64SqlArg(index, (java.math.BigInteger) value);
        } else if (value instanceof HalfFloat) { // Custom Float16 type needed
            return new Float16SqlArg(index, (HalfFloat) value);
        } else if (value instanceof Float) {
            return new Float32SqlArg(index, (Float) value);
        } else if (value instanceof Double) {
            return new Float64SqlArg(index, (Double) value);
        } else if (value instanceof java.math.BigDecimal) {
            return new DecimalSqlArg(index, (java.math.BigDecimal) value);
        } else if (value instanceof java.math.BigInteger) {
            return new BigIntSqlArg(index, (java.math.BigInteger) value);
        } else if (value instanceof Character) {
            return new RuneSqlArg(index, (Character) value);
        } else if (value instanceof String) {
            return new StringSqlArg(index, (String) value);
        } else if (value instanceof java.time.Duration) {
            return new DurationSqlArg(index, (java.time.Duration) value);
        } else if (value instanceof java.time.LocalDateTime ||
                   value instanceof java.time.Instant ||
                   value instanceof java.time.ZonedDateTime) {
            return new DateTimeSqlArg(index, value);
        } else if (value instanceof byte[]) {
            return new ByteArraySqlArg(index, (byte[]) value);
        } else if (value instanceof java.io.InputStream) {
            return new InputStreamSqlArg(index, (java.io.InputStream) value);
        } else {
            throw new SqlArgException("type of arg index " + index + " which is " + value.getClass().getName() + " does not exist");
        }
    }
}

