public long indexOf(byte[] other, long fromIndex) {
    if (other == null) {
        return -1;
    }
    long startIndex = Math.max(fromIndex, 0L);
    long maxSearchIndex = this.data.length - other.length;
    for (long i = startIndex; i <= maxSearchIndex; i++) {
        if (Util.arrayRangeEquals(this.data, (int) i, other, 0, other.length)) {
            return i;
        }
    }
    return -1L;
}

