public class TagsForIterator implements Iterator<TagsForIteratorItem> {
    /**
     * 内部标签迭代器。
     */
    private Iterator<String> tags;

    /**
     * 类别，可能为 null。
     */
    private String category;

    /**
     * 原始字符串表示。
     */
    private final String src;

    /**
     * 初始化 TagsForIterator 实例。
     * @param tf TagsFor 实例
     */
    public TagsForIterator(TagsFor tf) {
        this.tags = tf.getTags().iterator();
        this.category = tf.getCategory().orElse(null);
        this.src = tf.getSrc();
    }

    @Override
    public boolean hasNext() {
        // Simulate hasNext by peeking: we'll implement next() with stateful logic,
        // but for correctness in Java Iterator contract, we need hasNext().
        // Since original仓颉 has no explicit hasNext and relies on next() returning None,
        // we simulate by trying to find next non-null item without consuming.
        // However, due to complexity of the logic (category fallback, parsing),
        // and to preserve exact semantics, we delegate full logic to next() and use a cached result.
        // But per Java spec, we must avoid side effects in hasNext(). So we adopt common pattern:
        // cache next element; compute lazily in hasNext(), consume in next().
        // We'll refactor internally with lazy evaluation — but original仓颉 does not separate them.
        // Given constraints, we implement stateful hasNext/next using a cached next value.
        // However, the original仓颉 code is designed as a one-pass iterator with internal mutation.
        // To stay faithful and avoid complex lookahead, we follow typical "cache-on-hasNext" pattern.
        // But note: original logic mutates `this.category` and `this.tags` in next(), so true hasNext()
        // would require cloning or replay — which is not feasible here.
        // Therefore, we implement hasNext() conservatively: assume true until next() returns null.
        // This is acceptable for many use cases, though not perfectly spec-compliant.
        // Alternatively, restructure to compute next on hasNext() call and cache.
        // We choose the latter for correctness.
        if (cachedNext == null && !computedHasNext) {
            cachedNext = computeNext();
            computedHasNext = true;
        }
        return cachedNext != null;
    }

    private TagsForIteratorItem cachedNext = null;
    private boolean computedHasNext = false;

    private TagsForIteratorItem computeNext() {
        if (category != null) {
            while (tags.hasNext()) {
                String s = tags.next();
                if (s.startsWith(category) && s.length() > category.length() && s.charAt(category.length()) == '=') {
                    String rangeStr = s.substring(category.length() + 1);
                    return new LanguageRange(rangeStr);
                }
            }
            // Exhausted category-filtered tags
            category = null;
            tags = Arrays.stream(src.split(",")).map(String::trim).iterator();
        }
        while (tags.hasNext()) {
            String s = tags.next();
            // Find first '=' index manually (no built-in indexOf for runes, but Java String is UTF-16; assume ASCII '=' is fine)
            int eqIndex = -1;
            for (int i = 0; i < s.length(); i++) {
                if (s.charAt(i) == '=') {
                    eqIndex = i;
                    break;
                }
            }
            if (eqIndex == -1) {
                return new LanguageRange(s);
            }
        }
        return null;
    }

    @Override
    public TagsForIteratorItem next() {
        if (!hasNext()) {
            throw new NoSuchElementException();
        }
        TagsForIteratorItem result = cachedNext;
        cachedNext = null;
        computedHasNext = false;
        return result;
    }

    // Optional: remove if not needed, but Iterator interface requires it
    @Override
    public void remove() {
        throw new UnsupportedOperationException();
    }
}

