    } else if (field.getLabel() == FieldDescriptorProto.Label.LABEL_REPEATED) {
        return "public let " + field.getPropName() + ": RepeatedField<" + typeConvert(field) + ">";
    } else if (field.getType() == FieldDescriptorProto.Type.TYPE_MESSAGE) {
        return "private var p_" + field.getName() + ": PbMessage<" + field.getShortTypeName() + ">";
