    if (unconsumedMessages.isClosed()) {
        return;
    }
    if (messageExpired) {
        // 消息过期的处理
        acknowledge(md, MessageAck.EXPIRED_ACK_TYPE);
    } else {
        if (session.getTransacted()) {
            // do nothing
        } else if (isAutoAcknowledgeEach()) {
            if (deliveryingAcknowledgements.compareAndSet(false, true)) {
                synchronized (deliveredMessagesMutex) {
                    if (!deliveredMessages.isEmpty()) {
                        if (optimizeAcknowledge) {
                            ackCounter++;
                            long now = System.currentTimeMillis();
                            int prefetchSize = info.getPrefetchSize();
                            double threshold = prefetchSize * 0.65;
                            if ((ackCounter + deliveredCounter) >= threshold ||
                                (optimizeAcknowledgeTimeOut > 0 &&
                                 (now - optimizeAckTimestamp) > optimizeAcknowledgeTimeOut)) {
                                MessageAck ack = makeAckForAllDeliveredMessages(MessageAck.STANDARD_ACK_TYPE);
                                if (ack != null) {
                                    deliveredMessages.clear();
                                    ackCounter = 0;
                                    session.sendAck(ack);
                                    optimizeAckTimestamp = now;
                                }

                                if (deliveredCounter > 0) {
                                    if (pendingAck != null) {
                                        session.sendAck(pendingAck);
                                        this.pendingAck = null;
                                        deliveredCounter = 0;
                                    }
                                }
                            }
                        } else {
                            MessageAck ack = makeAckForAllDeliveredMessages(MessageAck.STANDARD_ACK_TYPE);
                            if (ack != null) {
                                deliveredMessages.clear();
                                session.sendAck(ack);
                            }
                        }
                    }
                }
                deliveryingAcknowledgements.set(false);
            }
        } else if (isAutoAcknowledgeBatch()) {
            ackLater(md, MessageAck.STANDARD_ACK_TYPE);
        } else if (session.isClientAcknowledge() || session.isIndividualAcknowledge()) {
            boolean messageUnackedByConsumer;
            synchronized (deliveredMessagesMutex) {
                messageUnackedByConsumer = deliveredMessages.contains(md);
            }
            if (messageUnackedByConsumer) {
                ackLater(md, MessageAck.DELIVERED_ACK_TYPE);
            }
        } else {
            throw new IllegalStateException("Invalid session state.");
        }
    }
}

