    }else{//大端序->转小端序
        UInt64(data[0]) | UInt64(data[1]) << 8 | UInt64(data[2]) << 16 | UInt64(data[3]) << 24 | UInt64(data[4]) << 32 | UInt64(data[5]) << 40 | UInt64(data[6]) << 48 | UInt64(data[7]) << 56;
    }
